def verify_budget_transition(
    previous_ledger: object,
    reservation: object,
    reserved_ledger: object,
    settlement: object,
    resulting_ledger: object,
) -> bool:
    before = verify_document_digest("elapsed-budget-ledger/v1", previous_ledger)
    held = verify_document_digest("elapsed-budget-reservation/v1", reservation)
    reserved = verify_document_digest("elapsed-budget-ledger/v1", reserved_ledger)
    settled = verify_document_digest("elapsed-budget-settlement/v1", settlement)
    after = verify_document_digest("elapsed-budget-ledger/v1", resulting_ledger)
    if held["task_id"] != before["task_id"]:
        _fail("BUDGET_TASK_MISMATCH")
    previous_fields = (
        ("previous_consumed_ms", "consumed_ms"),
        ("previous_reserved_ms", "reserved_ms"),
        ("previous_calls_consumed", "calls_consumed"),
        ("previous_calls_reserved", "calls_reserved"),
    )
    if any(held[left] != before[right] for left, right in previous_fields):
        _fail("BUDGET_PREVIOUS_STATE_MISMATCH")
    if before["consumed_ms"] + before["reserved_ms"] + held["reserved_ms"] > before["elapsed_limit_ms"]:
        _fail("BUDGET_ELAPSED_LIMIT_EXCEEDED", code="BUDGET_EXHAUSTED")
    if before["calls_consumed"] + before["calls_reserved"] + held["reserved_calls"] > before["tool_call_limit"]:
        _fail("BUDGET_CALL_LIMIT_EXCEEDED", code="BUDGET_EXHAUSTED")
    reserved_expected = {
        "task_id": before["task_id"],
        "grant_digest": before["grant_digest"],
        "elapsed_limit_ms": before["elapsed_limit_ms"],
        "tool_call_limit": before["tool_call_limit"],
        "consumed_ms": before["consumed_ms"],
        "reserved_ms": before["reserved_ms"] + held["reserved_ms"],
        "calls_consumed": before["calls_consumed"],
        "calls_reserved": before["calls_reserved"] + held["reserved_calls"],
    }
    if any(reserved[key] != item for key, item in reserved_expected.items()):
        _fail("BUDGET_RESERVED_LEDGER_MISMATCH")
    if settled["reservation_id"] != held["reservation_id"] or settled["invocation_digest"] != held["invocation_digest"]:
        _fail("BUDGET_SETTLEMENT_IDENTITY_MISMATCH")
    if settled["consumed_ms"] + settled["released_ms"] != held["reserved_ms"]:
        _fail("BUDGET_ELAPSED_CONSERVATION_INVALID")
    if settled["consumed_calls"] + settled["released_calls"] != held["reserved_calls"]:
        _fail("BUDGET_CALL_CONSERVATION_INVALID")
    if settled["outcome"] == "settled":
        if (settled["consumed_calls"], settled["released_calls"]) != (1, 0):
            _fail("BUDGET_SETTLED_CALL_INVALID")
        if settled["elapsed_ms"] > held["reserved_ms"] or settled["consumed_ms"] != settled["elapsed_ms"]:
            _fail("BUDGET_SETTLED_ELAPSED_INVALID")
        if settled["released_ms"] != held["reserved_ms"] - settled["elapsed_ms"]:
            _fail("BUDGET_SETTLED_RELEASE_INVALID")
    elif (
        settled["consumed_calls"] != 0
        or settled["released_calls"] != 1
        or settled["consumed_ms"] != 0
        or settled["released_ms"] != held["reserved_ms"]
    ):
        _fail("BUDGET_ABANDONMENT_RELEASE_INVALID")
    expected = {
        "resulting_consumed_ms": before["consumed_ms"] + settled["consumed_ms"],
        "resulting_reserved_ms": before["reserved_ms"],
        "resulting_calls_consumed": before["calls_consumed"] + settled["consumed_calls"],
        "resulting_calls_reserved": before["calls_reserved"],
    }
    if any(settled[key] != item for key, item in expected.items()):
        _fail("BUDGET_RESULTING_STATE_MISMATCH")
    after_expected = {
        "task_id": before["task_id"],
        "grant_digest": before["grant_digest"],
        "elapsed_limit_ms": before["elapsed_limit_ms"],
        "tool_call_limit": before["tool_call_limit"],
        "consumed_ms": expected["resulting_consumed_ms"],
        "reserved_ms": expected["resulting_reserved_ms"],
        "calls_consumed": expected["resulting_calls_consumed"],
        "calls_reserved": expected["resulting_calls_reserved"],
    }
    if any(after[key] != item for key, item in after_expected.items()):
        _fail("BUDGET_RESULTING_LEDGER_MISMATCH")
    return True


from datetime import datetime
import unicodedata


def _require(condition: bool, detail: str, path: str = "$", code: str | None = None) -> None:
    if not condition:
        _fail(detail, path, code)


def _ordered_unique(values: list[object], key) -> bool:
    keys = [key(item) for item in values]
    return keys == sorted(keys) and len(keys) == len(set(keys))


def _sorted_unique(values: list[object]) -> bool:
    return values == sorted(values) and len(values) == len(set(values))


def _ref_key(value: dict[str, object]) -> tuple[object, ...]:
    return (
        value["content_schema_id"],
        value["artifact_id"],
        value["sha256"],
    )


def _artifact_ref_key(value: dict[str, object]) -> str:
    ref = value.get("ref", value)
    return ref["artifact_id"]


def _verify_embedded_digest(schema_id: str, value: dict[str, object]) -> None:
    spec = schema(schema_id).get("x-pullwise-digest")
    if not isinstance(spec, dict):
        return
    field, domain = spec["field"], spec["domain"]
    presented = value[field]
    unsigned = {key: item for key, item in value.items() if key != field}
    raw = domain.encode("utf-8") + b"\0" + canonical_document_bytes(unsigned)
    _require(
        presented == hashlib.sha256(raw).hexdigest(),
        "CONTRACT_DIGEST_MISMATCH",
        f"$.{field}",
    )


def _rule_server_authority_envelope(value: dict[str, object]) -> None:
    grant = value["grant"]
    _verify_embedded_digest("agent-worker-grant/v1", grant)
    grant_bound_fields = (
        "task_id", "attempt_id", "session_id", "owner_id", "lease_id",
        "task_version", "deletion_version", "owner_epoch", "native_epoch",
        "transport_epoch", "absolute_deadline_at", "terminalization_reserve_ms",
    )
    _require(
        all(value[field] == grant[field] for field in grant_bound_fields),
        "AUTHORITY_GRANT_BINDING_MISMATCH",
        code="AUTHORITY_INPUT_UNTRUSTED",
    )


def _rule_transport_abandonment_record(value: dict[str, object]) -> None:
    _require(
        value["abandoned_task_version"] == value["previous_task_version"] + 1,
        "AUTHORITY_SUCCESSOR_VERSION_INVALID",
        "$.abandoned_task_version",
        "AUTHORITY_INPUT_UNTRUSTED",
    )


def _decode_canonical_base64(value: str, path: str) -> bytes:
    try:
        raw = base64.b64decode(value, validate=True)
    except (ValueError, TypeError):
        _fail("SOURCE_CONTENT_BASE64_INVALID", path)
    _require(
        base64.b64encode(raw).decode("ascii") == value,
        "SOURCE_CONTENT_BASE64_NONCANONICAL",
        path,
    )
    return raw


def _rule_binary_content(value: dict[str, object], data_field: str = "data_base64") -> None:
    raw = _decode_canonical_base64(value[data_field], f"$.{data_field}")
    _require(len(raw) == value["size_bytes"], "SOURCE_CONTENT_SIZE_MISMATCH", "$.size_bytes")
    _require(
        hashlib.sha256(raw).hexdigest() == value["byte_sha256"],
        "SOURCE_CONTENT_SHA256_MISMATCH",
        "$.byte_sha256",
    )


def _rule_change_set_patch(value: dict[str, object]) -> None:
    _rule_binary_content(value)
    _verify_embedded_digest("change-set-patch/v1", value)


def _valid_tree_entry(entry: dict[str, object]) -> bool:
    expected = {
        "file": {"path", "type", "size_bytes", "sha256", "executable"},
        "symlink": {"path", "type", "target"},
        "gitlink": {"path", "type", "commit_sha"},
    }.get(entry.get("type"))
    return expected is not None and set(entry) == expected


def _rule_change_set(value: dict[str, object]) -> None:
    paths: list[str] = []
    for group in ("added", "modified", "deleted", "type_changed"):
        group_paths: list[str] = []
        for index, item in enumerate(value[group]):
            expected = {"after"} if group == "added" else {"before"}
            if group in {"modified", "type_changed"}:
                expected = {"before", "after"}
            _require(set(item) == expected, "CHANGE_SET_ENTRY_SHAPE_INVALID", f"$.{group}[{index}]")
            _require(
                all(_valid_tree_entry(entry) for entry in item.values()),
                "CHANGE_SET_ENTRY_SHAPE_INVALID",
                f"$.{group}[{index}]",
            )
            before, after = item.get("before"), item.get("after")
            path = (after or before)["path"]
            if before is not None and after is not None:
                _require(before["path"] == after["path"], "CHANGE_SET_PATH_INVALID", f"$.{group}[{index}]")
                _require(before != after, "CHANGE_SET_EMPTY_MUTATION", f"$.{group}[{index}]")
                _require(
                    (before["type"] == after["type"]) == (group == "modified"),
                    "CHANGE_SET_TYPE_BRANCH_INVALID",
                    f"$.{group}[{index}]",
                )
            group_paths.append(path)
        _require(
            group_paths == sorted(group_paths, key=lambda item: item.encode("utf-8")),
            "CHANGE_SET_ORDER_INVALID",
            f"$.{group}",
        )
        paths.extend(group_paths)
    _require(bool(paths), "CHANGE_SET_EMPTY")
    _require(len(paths) == len(set(paths)), "CHANGE_SET_PATH_OVERLAP")
    _require(
        value["original_source_state_id"] != value["final_source_state_id"],
        "CHANGE_SET_STATE_UNCHANGED",
    )


def _rule_execution_profile(value: dict[str, object]) -> None:
    _require(value["operating_system"] == "linux", "EXECUTION_PROFILE_OS_INVALID")
    _require(value["cpu_architecture"] in {"aarch64", "x86_64"}, "EXECUTION_PROFILE_ARCH_INVALID")
    _require(
        value["image_identity"].startswith("sha256:")
        and re.fullmatch(r"sha256:[0-9a-f]{64}", value["image_identity"]) is not None,
        "EXECUTION_PROFILE_IMAGE_MUTABLE",
    )


def _rule_execution_state(value: dict[str, object]) -> None:
    _require(_ordered_unique(value["toolchain"], lambda item: item["tool_id"]), "EXECUTION_TOOLCHAIN_ORDER_INVALID")
    _require(_ordered_unique(value["config_and_fixtures"], _ref_key), "EXECUTION_CONFIG_ORDER_INVALID")
    _require(_ordered_unique(value["services"], lambda item: item["service_id"]), "EXECUTION_SERVICE_ORDER_INVALID")
    _require(_ordered_unique(value["environment"], lambda item: item["key"]), "EXECUTION_ENVIRONMENT_ORDER_INVALID")
    for index, item in enumerate(value["environment"]):
        expected = {"kind", "key", "value"} if item["kind"] == "value" else {
            "kind", "key", "secret_key_id", "secret_version"
        }
        _require(set(item) == expected, "EXECUTION_ENVIRONMENT_SHAPE_INVALID", f"$.environment[{index}]")
    unsigned = {
        key: item
        for key, item in value.items()
        if key not in {"execution_state_id", "manifest_digest"}
    }
    _require(
        value["execution_state_id"] == canonical_document_sha256(unsigned),
        "EXECUTION_STATE_ID_INVALID",
        "$.execution_state_id",
    )


def _rule_source_selection_policy(value: dict[str, object]) -> None:
    excluded, ephemeral = value["excluded_control_roots"], value["ephemeral_patterns"]
    _require(value["include"] == "all_repository_regular_files", "SOURCE_SELECTION_INCLUDE_INVALID")
    _require(".git/" in excluded and ".pullwise-worker/" in excluded, "SOURCE_SELECTION_CONTROL_ROOT_MISSING")
    _require(_ordered_unique(excluded, lambda item: item.encode("utf-8")), "SOURCE_SELECTION_ORDER_INVALID")
    _require(_ordered_unique(ephemeral, lambda item: item.encode("utf-8")), "SOURCE_SELECTION_ORDER_INVALID")


def _rule_source_tree(value: dict[str, object]) -> None:
    entries = value["entries"]
    _require(_ordered_unique(entries, lambda item: item["path"].encode("utf-8")), "SOURCE_TREE_ORDER_INVALID")
    _require(all(_valid_tree_entry(item) for item in entries), "SOURCE_TREE_ENTRY_INVALID")
    folded = [item["path"].lower() for item in entries]
    _require(len(folded) == len(set(folded)), "SOURCE_TREE_CASE_COLLISION")
    total = sum(item["size_bytes"] for item in entries if item["type"] == "file")
    _require(value["entry_count"] == len(entries), "SOURCE_TREE_COUNT_INVALID")
    _require(value["total_bytes"] == total, "SOURCE_TREE_SIZE_INVALID")
    identity = {
        "base_revision": value["base_revision"],
        "selection_policy_digest": value["selection_policy_digest"],
        "entries": entries,
    }
    _require(
        value["source_state_id"] == canonical_document_sha256(identity),
        "SOURCE_STATE_ID_INVALID",
        "$.source_state_id",
    )


def _timestamp_millis(value: object) -> int | None:
    if not isinstance(value, str) or re.fullmatch(
        r"[0-9]{4}-[0-9]{2}-[0-9]{2}T[0-9]{2}:[0-9]{2}:[0-9]{2}\.[0-9]{3}Z",
        value,
    ) is None:
        return None
    try:
        parsed = datetime.strptime(value, "%Y-%m-%dT%H:%M:%S.%fZ")
    except ValueError:
        return None
    elapsed = parsed - datetime(1970, 1, 1)
    return (
        elapsed.days * 86_400_000
        + elapsed.seconds * 1_000
        + elapsed.microseconds // 1_000
    )


def _rule_actor(value: dict[str, object]) -> None:
    session_kinds = {
        "task_owner", "quality_verifier", "domain_reviewer",
        "explorer", "troubleshooter", "implementer",
    }
    if value["kind"] in session_kinds:
        _require(
            isinstance(value["session_id"], str)
            and re.fullmatch(r"sess_[0-9a-f]{32}", value["session_id"]) is not None,
            "ACTOR_SESSION_INVALID",
        )
    else:
        _require(value["session_id"] is None, "ACTOR_SESSION_INVALID")


def _rule_observation(value: dict[str, object]) -> None:
    _rule_actor(value["actor"])
    status = value["status"]
    started, completed = _timestamp_millis(value["started_at"]), _timestamp_millis(value["completed_at"])
    if status == "policy_denied":
        _require(
            all(value[key] is None for key in ("started_at", "completed_at", "duration_ms", "exit_code")),
            "OBSERVATION_STATUS_MATRIX_INVALID",
        )
        _require(
            value["result_ref"]["availability"] == "available"
            and value["result_ref"]["ref"]["content_schema_id"] == "error-response/v1"
            and value["source_state_before_id"] == value["source_state_after_id"]
            and value["execution_state_id"] is None,
            "OBSERVATION_STATUS_MATRIX_INVALID",
        )
    else:
        _require(
            started is not None and completed is not None and completed >= started
            and value["duration_ms"] == completed - started,
            "OBSERVATION_TIME_INVALID",
        )
        if status == "succeeded":
            _require(value["result_ref"]["availability"] == "available", "OBSERVATION_RESULT_REQUIRED")
    _require(value["partial_side_effect"] is False, "OBSERVATION_PARTIAL_SIDE_EFFECT")


def _rule_observation_manifest(value: dict[str, object]) -> None:
    entries = value["entries"]
    _require(value["entry_count"] == len(entries), "OBSERVATION_MANIFEST_COUNT_INVALID")
    _require(
        _ordered_unique(entries, lambda item: (item["observation_seq"], item["observation_id"])),
        "OBSERVATION_MANIFEST_ORDER_INVALID",
    )
    if value["schema_id"] == "pre-verifier-observation-manifest/v1":
        allowed = {"task_owner", "legacy_domain_reviewer"}
        _require(all(item["actor"]["kind"] in allowed for item in entries), "OBSERVATION_MANIFEST_ACTOR_INVALID")
    else:
        _require(any(item["actor"]["kind"] == "quality_verifier" for item in entries), "OBSERVATION_MANIFEST_VERIFIER_MISSING")


def _rule_completion_proposal(value: dict[str, object]) -> None:
    _require(_sorted_unique(value["execution_state_ids"]), "PROPOSAL_EXECUTION_STATE_ORDER_INVALID")
    _require(_ordered_unique(value["artifact_refs"], _artifact_ref_key), "PROPOSAL_ARTIFACT_ORDER_INVALID")
    _require(_ordered_unique(value["requirement_claims"], lambda item: item["requirement_id"]), "PROPOSAL_CLAIM_ORDER_INVALID")
    for item in value["requirement_claims"]:
        _require(_sorted_unique(item["evidence_ids"]), "PROPOSAL_EVIDENCE_ORDER_INVALID")
    _require(_sorted_unique(value["known_gaps"]), "PROPOSAL_GAP_ORDER_INVALID")
    _require(_sorted_unique(value["residual_risks"]), "PROPOSAL_RISK_ORDER_INVALID")
    if value["outcome_requested"] == "NO_CHANGE_NEEDED":
        _require(value["change_set_ref"] is None, "PROPOSAL_NO_CHANGE_SET_INVALID")
        _require(
            value["original_source_state_id"] == value["final_source_state_id"],
            "PROPOSAL_NO_CHANGE_STATE_INVALID",
        )


def _rule_verifier_input(value: dict[str, object]) -> None:
    _require(value["owner_conclusion_excluded"] is True, "VERIFIER_OWNER_CONCLUSION_INCLUDED")
    _require(_ordered_unique(value["artifact_refs"], _artifact_ref_key), "VERIFIER_ARTIFACT_ORDER_INVALID")
    _require(_ordered_unique(value["engineering_rule_refs"], _ref_key), "VERIFIER_RULE_ORDER_INVALID")
    _require(_sorted_unique(value["requirement_ids"]), "VERIFIER_REQUIREMENT_ORDER_INVALID")


def _valid_assessments(values: list[dict[str, object]]) -> bool:
    if not _ordered_unique(values, lambda item: item["requirement_id"]):
        return False
    return all(
        _sorted_unique(item["evidence_ids"])
        and _sorted_unique(item["limitations"])
        and (item["verdict"] != "PASS" or not item["limitations"])
        for item in values
    )


def _rule_verifier_work(value: dict[str, object]) -> None:
    _require(value["sandbox_mode"] == "read_only_or_cow", "VERIFIER_SANDBOX_INVALID")
    for field in ("counterexamples_searched", "own_observation_ids", "limitations"):
        _require(_sorted_unique(value[field]), "VERIFIER_WORK_ORDER_INVALID", f"$.{field}")
    _require(bool(value["own_observation_ids"]), "VERIFIER_OBSERVATION_REQUIRED")
    _require(_valid_assessments(value["provisional_requirement_assessments"]), "VERIFIER_ASSESSMENT_INVALID")


def _rule_attestation(value: dict[str, object]) -> None:
    _require(_sorted_unique(value["execution_state_ids"]), "ATTESTATION_EXECUTION_ORDER_INVALID")
    _require(_sorted_unique(value["own_observation_ids"]) and bool(value["own_observation_ids"]), "ATTESTATION_OBSERVATION_INVALID")
    verdicts = value["requirement_verdicts"]
    _require(_valid_assessments(verdicts), "ATTESTATION_VERDICT_INVALID")
    present = {item["verdict"] for item in verdicts}
    expected = next((item for item in ("POLICY_VIOLATION", "NEEDS_WORK", "UNVERIFIABLE") if item in present), "PASS")
    _require(value["run_status"] == expected, "ATTESTATION_RUN_STATUS_INVALID")


def _rule_attestation_manifest(value: dict[str, object]) -> None:
    attestations = value["attestations"]
    _require(value["attestation_count"] == len(attestations), "ATTESTATION_MANIFEST_COUNT_INVALID")
    _require(_ordered_unique(attestations, lambda item: (item["slot_id"], item["attestation_id"])), "ATTESTATION_MANIFEST_ORDER_INVALID")
    slots = {item["slot_id"] for item in attestations}
    ids = {item["attestation_id"] for item in attestations}
    aggregates = value["requirement_aggregates"]
    _require(_ordered_unique(aggregates, lambda item: item["requirement_id"]), "ATTESTATION_AGGREGATE_ORDER_INVALID")
    for item in aggregates:
        _require(_sorted_unique(item["required_slot_ids"]), "ATTESTATION_REQUIRED_SLOT_ORDER_INVALID")
        _require(_sorted_unique(item["attestation_ids"]), "ATTESTATION_ID_ORDER_INVALID")
        _require(set(item["attestation_ids"]).issubset(ids), "ATTESTATION_ID_UNKNOWN")
        if set(item["required_slot_ids"]).difference(slots):
            _require(item["verdict"] == "UNVERIFIABLE", "ATTESTATION_MISSING_SLOT_INVALID")


def _rule_evidence_closure(value: dict[str, object]) -> None:
    entries = value["entries"]
    _require(value["entry_count"] == len(entries), "EVIDENCE_CLOSURE_COUNT_INVALID")
    _require(_ordered_unique(entries, _ref_key), "EVIDENCE_CLOSURE_ORDER_INVALID")
    forbidden = {
        "evidence-closure-manifest/v1", "task-result-core/v1",
        "task-result/v1", "worker-debug-fragment/v1",
    }
    _require(all(item["content_schema_id"] not in forbidden for item in entries), "EVIDENCE_CLOSURE_BACK_EDGE")
    verify_content_ref_set(entries)
    keys = {_ref_key(item) for item in entries}
    required = {
        _ref_key(value["pre_gate_evidence_closure_ref"]),
        _ref_key(value["input_snapshot_ref"]),
        _ref_key(value["gate_decision_ref"]),
    }
    _require(required.issubset(keys), "EVIDENCE_CLOSURE_REQUIRED_EDGE_MISSING")
    _require(value["evidence_closure_digest"] == canonical_document_sha256(entries), "EVIDENCE_CLOSURE_DIGEST_INVALID")


def _seo_require(
    condition: bool,
    detail: str,
    path: str = "$",
    code: str | None = None,
) -> None:
    if not condition:
        _fail(detail, path, code)


def _seo_verify_embedded_digest(
    schema_id: str, value: dict[str, object]
) -> None:
    spec = schema(schema_id)["x-pullwise-digest"]
    field, domain = spec["field"], spec["domain"]
    unsigned = {key: item for key, item in value.items() if key != field}
    digest_input = (
        domain.encode("utf-8")
        + b"\0"
        + canonical_document_bytes(unsigned)
    )
    _seo_require(
        value[field] == hashlib.sha256(digest_input).hexdigest(),
        "CONTRACT_DIGEST_MISMATCH",
        f"$.{field}",
    )


def _seo_tree_entry_valid(value: object) -> bool:
    if not isinstance(value, dict):
        return False
    expected = {
        "file": {"path", "type", "size_bytes", "sha256", "executable"},
        "symlink": {"path", "type", "target"},
        "gitlink": {"path", "type", "commit_sha"},
    }.get(value.get("type"))
    return expected is not None and set(value) == expected


def _seo_ref_matches_document(
    ref: dict[str, object],
    schema_id: str,
    document: dict[str, object],
) -> bool:
    raw = canonical_document_bytes(document)
    expected = {
        "content_schema_id": schema_id,
        "sha256": hashlib.sha256(raw).hexdigest(),
        "size_bytes": len(raw),
        "media_type": "application/json",
        "encoding": "utf-8",
    }
    return all(ref.get(key) == item for key, item in expected.items())


def _seo_change_entry_path(entry: dict[str, object]) -> str:
    branch = entry.get("after") or entry.get("before")
    return branch["path"]


def _rule_change_set_complete(value: dict[str, object]) -> None:
    all_paths: list[str] = []
    for group in ("added", "modified", "deleted", "type_changed"):
        paths: list[str] = []
        for index, item in enumerate(value[group]):
            expected = {"after"} if group == "added" else {"before"}
            if group in {"modified", "type_changed"}:
                expected = {"before", "after"}
            path = f"$.{group}[{index}]"
            _seo_require(
                set(item) == expected,
                "CHANGE_SET_ENTRY_SHAPE_INVALID",
                path,
            )
            _seo_require(
                all(_seo_tree_entry_valid(entry) for entry in item.values()),
                "CHANGE_SET_ENTRY_SHAPE_INVALID",
                path,
            )
            before, after = item.get("before"), item.get("after")
            if before is not None and after is not None:
                _seo_require(
                    before["path"] == after["path"],
                    "CHANGE_SET_PATH_INVALID",
                    path,
                )
                _seo_require(
                    canonical_document_bytes(before)
                    != canonical_document_bytes(after),
                    "CHANGE_SET_EMPTY_MUTATION",
                    path,
                )
                _seo_require(
                    (before["type"] == after["type"])
                    == (group == "modified"),
                    "CHANGE_SET_TYPE_BRANCH_INVALID",
                    path,
                )
            paths.append(_seo_change_entry_path(item))
        _seo_require(
            paths == sorted(paths, key=lambda item: item.encode("utf-8")),
            "CHANGE_SET_ORDER_INVALID",
            f"$.{group}",
        )
        all_paths.extend(paths)
    _seo_require(bool(all_paths), "CHANGE_SET_EMPTY")
    _seo_require(
        len(all_paths) == len(set(all_paths)),
        "CHANGE_SET_PATH_OVERLAP",
    )
    _seo_require(
        value["original_source_state_id"] != value["final_source_state_id"],
        "CHANGE_SET_STATE_UNCHANGED",
    )
    _seo_verify_embedded_digest("change-set/v1", value)


def _seo_expected_change_groups(
    original: dict[str, object], final: dict[str, object]
) -> dict[str, list[dict[str, object]]]:
    before = {entry["path"]: entry for entry in original["entries"]}
    after = {entry["path"]: entry for entry in final["entries"]}
    groups: dict[str, list[dict[str, object]]] = {
        "added": [],
        "modified": [],
        "deleted": [],
        "type_changed": [],
    }
    for path in sorted(set(before) | set(after), key=lambda item: item.encode("utf-8")):
        old, new = before.get(path), after.get(path)
        if old is None:
            groups["added"].append({"after": new})
        elif new is None:
            groups["deleted"].append({"before": old})
        elif canonical_document_bytes(old) != canonical_document_bytes(new):
            group = "modified" if old["type"] == new["type"] else "type_changed"
            groups[group].append({"before": old, "after": new})
    return groups


def verify_change_set_context(
    change_set: object,
    original_source_tree: object,
    final_source_tree: object,
    patch: object,
) -> dict[str, object]:
    """Bind a change set to its two source trees and exact patch content."""
    checked = verify_document_digest("change-set/v1", change_set)
    original = verify_document_digest(
        "source-tree-manifest/v1", original_source_tree
    )
    final = verify_document_digest("source-tree-manifest/v1", final_source_tree)
    patch_value = verify_document_digest("change-set-patch/v1", patch)
    _seo_require(
        checked["original_source_state_id"] == original["source_state_id"],
        "CHANGE_SET_CONTEXT_INVALID",
        "$.original_source_state_id",
    )
    _seo_require(
        checked["final_source_state_id"] == final["source_state_id"],
        "CHANGE_SET_CONTEXT_INVALID",
        "$.final_source_state_id",
    )
    expected = _seo_expected_change_groups(original, final)
    for group in ("added", "modified", "deleted", "type_changed"):
        _seo_require(
            canonical_document_bytes(checked[group])
            == canonical_document_bytes(expected[group]),
            "CHANGE_SET_CONTEXT_INVALID",
            f"$.{group}",
        )
    _seo_require(
        _seo_ref_matches_document(
            checked["patch_ref"], "change-set-patch/v1", patch_value
        ),
        "CAS_CORRUPT",
        "$.patch_ref",
    )
    return checked


def _seo_ordered_unique(values: list[object], key) -> bool:
    keys = [key(item) for item in values]
    return keys == sorted(keys) and len(keys) == len(set(keys))


def _seo_content_ref_key(value: dict[str, object]) -> tuple[str, str, str]:
    return (value["content_schema_id"], value["artifact_id"], value["sha256"])


def _rule_execution_state_manifest(value: dict[str, object]) -> None:
    _seo_require(
        _seo_ordered_unique(value["toolchain"], lambda item: item["tool_id"]),
        "EXECUTION_TOOLCHAIN_ORDER_INVALID", "$.toolchain",
    )
    _seo_require(
        _seo_ordered_unique(value["config_and_fixtures"], _seo_content_ref_key),
        "EXECUTION_CONFIG_ORDER_INVALID", "$.config_and_fixtures",
    )
    _seo_require(
        _seo_ordered_unique(value["services"], lambda item: item["service_id"]),
        "EXECUTION_SERVICE_ORDER_INVALID", "$.services",
    )
    _seo_require(
        _seo_ordered_unique(value["environment"], lambda item: item["key"]),
        "EXECUTION_ENVIRONMENT_ORDER_INVALID", "$.environment",
    )
    for index, item in enumerate(value["environment"]):
        expected = (
            {"kind", "key", "value"}
            if item["kind"] == "value"
            else {"kind", "key", "secret_key_id", "secret_version"}
        )
        _seo_require(
            set(item) == expected,
            "EXECUTION_ENVIRONMENT_SHAPE_INVALID",
            f"$.environment[{index}]",
        )
    unsigned = {
        key: item for key, item in value.items()
        if key not in {"execution_state_id", "manifest_digest"}
    }
    _seo_require(
        value["execution_state_id"]
        == hashlib.sha256(canonical_document_bytes(unsigned)).hexdigest(),
        "EXECUTION_STATE_ID_INVALID", "$.execution_state_id",
    )
    _seo_verify_embedded_digest("execution-state-manifest/v1", value)


def verify_execution_state_context(
    manifest: object,
    source_tree: object,
    execution_profile: object,
) -> dict[str, object]:
    """Bind execution state to its exact source state and runtime profile."""
    checked = verify_document_digest("execution-state-manifest/v1", manifest)
    source = verify_document_digest("source-tree-manifest/v1", source_tree)
    profile = verify_document_digest("execution-profile/v1", execution_profile)
    _seo_require(
        checked["source_state_id"] == source["source_state_id"],
        "EXECUTION_STATE_CONTEXT_INVALID", "$.source_state_id",
    )
    _seo_require(
        checked["execution_profile_digest"] == profile["profile_digest"],
        "EXECUTION_STATE_CONTEXT_INVALID", "$.execution_profile_digest",
    )
    _seo_require(
        _seo_ref_matches_document(
            checked["execution_profile_ref"], "execution-profile/v1", profile
        ),
        "CAS_CORRUPT", "$.execution_profile_ref",
    )
    return checked


def _rule_source_selection_policy_complete(value: dict[str, object]) -> None:
    excluded = value["excluded_control_roots"]
    ephemeral = value["ephemeral_patterns"]
    _seo_require(
        value["include"] == "all_repository_regular_files",
        "SOURCE_SELECTION_INCLUDE_INVALID", "$.include",
    )
    _seo_require(
        ".git/" in excluded and ".pullwise-worker/" in excluded,
        "SOURCE_SELECTION_CONTROL_ROOT_MISSING", "$.excluded_control_roots",
    )
    _seo_require(
        _seo_ordered_unique(excluded, lambda item: item.encode("utf-8")),
        "SOURCE_SELECTION_ORDER_INVALID", "$.excluded_control_roots",
    )
    _seo_require(
        _seo_ordered_unique(ephemeral, lambda item: item.encode("utf-8")),
        "SOURCE_SELECTION_ORDER_INVALID", "$.ephemeral_patterns",
    )
    _seo_verify_embedded_digest("source-selection-policy/v1", value)


def _seo_case_collision_key(value: str) -> str:
    return value.upper().lower()


def _rule_source_tree_manifest(value: dict[str, object]) -> None:
    entries = value["entries"]
    _seo_require(
        _seo_ordered_unique(entries, lambda item: item["path"].encode("utf-8")),
        "SOURCE_TREE_ORDER_INVALID", "$.entries",
    )
    for index, entry in enumerate(entries):
        _seo_require(
            _seo_tree_entry_valid(entry),
            "SOURCE_TREE_ENTRY_INVALID", f"$.entries[{index}]",
        )
    folded = [_seo_case_collision_key(entry["path"]) for entry in entries]
    _seo_require(
        len(folded) == len(set(folded)),
        "SOURCE_TREE_CASE_COLLISION", "$.entries",
    )
    total = sum(
        entry["size_bytes"] for entry in entries if entry["type"] == "file"
    )
    _seo_require(
        value["entry_count"] == len(entries),
        "SOURCE_TREE_COUNT_INVALID", "$.entry_count",
    )
    _seo_require(
        value["total_bytes"] == total,
        "SOURCE_TREE_SIZE_INVALID", "$.total_bytes",
    )
    identity = {
        "base_revision": value["base_revision"],
        "selection_policy_digest": value["selection_policy_digest"],
        "entries": entries,
    }
    _seo_require(
        value["source_state_id"]
        == hashlib.sha256(canonical_document_bytes(identity)).hexdigest(),
        "SOURCE_STATE_ID_INVALID", "$.source_state_id",
    )
    _seo_verify_embedded_digest("source-tree-manifest/v1", value)


def verify_source_tree_context(
    manifest: object,
    selection_policy: object,
) -> dict[str, object]:
    """Bind a source tree to the exact selection policy used to build it."""
    checked = verify_document_digest("source-tree-manifest/v1", manifest)
    policy = verify_document_digest(
        "source-selection-policy/v1", selection_policy
    )
    _seo_require(
        checked["selection_policy_digest"] == policy["policy_digest"],
        "SOURCE_TREE_CONTEXT_INVALID", "$.selection_policy_digest",
    )
    _seo_require(
        _seo_ref_matches_document(
            checked["selection_policy_ref"],
            "source-selection-policy/v1",
            policy,
        ),
        "CAS_CORRUPT", "$.selection_policy_ref",
    )
    return checked


def _seo_observation_manifest_common(
    value: dict[str, object], *, pre_verifier: bool
) -> None:
    entries = value["entries"]
    _seo_require(
        value["entry_count"] == len(entries),
        "OBSERVATION_MANIFEST_COUNT_INVALID", "$.entry_count",
    )
    _seo_require(
        _seo_ordered_unique(
            entries,
            lambda item: (item["observation_seq"], item["observation_id"]),
        ),
        "OBSERVATION_MANIFEST_ORDER_INVALID", "$.entries",
    )
    if pre_verifier:
        allowed = {"task_owner", "domain_reviewer"}
        for index, entry in enumerate(entries):
            _seo_require(
                entry["actor"]["kind"] in allowed,
                "OBSERVATION_MANIFEST_ACTOR_INVALID",
                f"$.entries[{index}].actor.kind",
            )
    else:
        _seo_require(
            any(
                entry["actor"]["kind"] == "quality_verifier"
                for entry in entries
            ),
            "OBSERVATION_MANIFEST_VERIFIER_MISSING", "$.entries",
        )


def _rule_observation_manifest_complete(value: dict[str, object]) -> None:
    _seo_observation_manifest_common(value, pre_verifier=False)
    _seo_verify_embedded_digest("observation-manifest/v1", value)


def _rule_pre_verifier_observation_manifest(
    value: dict[str, object]
) -> None:
    _seo_observation_manifest_common(value, pre_verifier=True)
    _seo_verify_embedded_digest(
        "pre-verifier-observation-manifest/v1", value
    )


def verify_observation_manifest_extension(
    manifest: object,
    pre_verifier_manifest: object,
) -> dict[str, object]:
    """Verify that final observations strictly and exactly extend the pre-set."""
    final = verify_document_digest("observation-manifest/v1", manifest)
    pre = verify_document_digest(
        "pre-verifier-observation-manifest/v1", pre_verifier_manifest
    )
    for field in ("task_id", "proposal_id", "attempt_id", "native_epoch"):
        _seo_require(
            final[field] == pre[field],
            "OBSERVATION_MANIFEST_IDENTITY_INVALID", f"$.{field}",
        )
    _seo_require(
        final["manifest_id"] != pre["manifest_id"],
        "OBSERVATION_MANIFEST_IDENTITY_INVALID", "$.manifest_id",
    )
    _seo_require(
        _seo_ref_matches_document(
            final["pre_verifier_observation_manifest_ref"],
            "pre-verifier-observation-manifest/v1",
            pre,
        ),
        "CAS_CORRUPT", "$.pre_verifier_observation_manifest_ref",
    )
    prefix_length = len(pre["entries"])
    _seo_require(
        len(final["entries"]) > prefix_length,
        "OBSERVATION_MANIFEST_EXTENSION_INVALID", "$.entries",
    )
    _seo_require(
        canonical_document_bytes(final["entries"][:prefix_length])
        == canonical_document_bytes(pre["entries"]),
        "OBSERVATION_MANIFEST_EXTENSION_INVALID", "$.entries",
    )
    for index, entry in enumerate(
        final["entries"][prefix_length:], prefix_length
    ):
        _seo_require(
            entry["actor"]["kind"] == "quality_verifier",
            "OBSERVATION_MANIFEST_EXTENSION_INVALID",
            f"$.entries[{index}].actor.kind",
        )
    return final


def _budget_exhausted(detail: str, path: str = "$") -> None:
    _fail(detail, path, code="BUDGET_EXHAUSTED")


def _rule_elapsed_budget_ledger(value: dict[str, object]) -> None:
    _verify_embedded_digest("elapsed-budget-ledger/v1", value)
    if value["consumed_ms"] + value["reserved_ms"] > value["elapsed_limit_ms"]:
        _budget_exhausted("BUDGET_ELAPSED_LIMIT_EXCEEDED")
    if (
        value["calls_consumed"] + value["calls_reserved"]
        > value["tool_call_limit"]
    ):
        _budget_exhausted("BUDGET_CALL_LIMIT_EXCEEDED")


def _rule_elapsed_budget_reservation(value: dict[str, object]) -> None:
    _verify_embedded_digest("elapsed-budget-reservation/v1", value)
    _require(
        _timestamp_millis(value["started_at"]) is not None,
        "BUDGET_RESERVATION_TIME_INVALID",
        "$.started_at",
    )
    totals = (
        value["previous_consumed_ms"]
        + value["previous_reserved_ms"]
        + value["reserved_ms"],
        value["previous_calls_consumed"]
        + value["previous_calls_reserved"]
        + value["reserved_calls"],
    )
    _require(
        all(item <= SAFE_INTEGER for item in totals),
        "BUDGET_RESERVATION_TOTAL_UNSAFE",
    )


def _rule_elapsed_budget_settlement(value: dict[str, object]) -> None:
    _verify_embedded_digest("elapsed-budget-settlement/v1", value)
    _require(
        value["consumed_calls"] + value["released_calls"] == 1,
        "BUDGET_CALL_CONSERVATION_INVALID",
    )
    if value["outcome"] == "settled":
        _require(
            value["consumed_calls"] == 1 and value["released_calls"] == 0,
            "BUDGET_SETTLED_CALL_INVALID",
        )
        _require(
            value["consumed_ms"] == value["elapsed_ms"],
            "BUDGET_SETTLED_ELAPSED_INVALID",
        )
    else:
        _require(
            value["elapsed_ms"] == 0
            and value["consumed_ms"] == 0
            and value["consumed_calls"] == 0
            and value["released_calls"] == 1,
            "BUDGET_ABANDONMENT_RELEASE_INVALID",
        )
    _require(
        value["consumed_ms"] + value["released_ms"] <= SAFE_INTEGER,
        "BUDGET_SETTLEMENT_TOTAL_UNSAFE",
    )


def _utf8_fields(value: dict[str, object]) -> None:
    limits = {
        "objective": 16384,
        "statement": 16384,
        "rationale": 16384,
        "objective_restated": 16384,
        "reason": 16384,
    }
    for field, limit in limits.items():
        if field in value:
            _require(
                unicodedata.normalize("NFC", value[field]) == value[field],
                "UTF8_NFC_INVALID",
                f"$.{field}",
            )
            _require(len(value[field].encode("utf-8")) <= limit, "UTF8_BYTE_LIMIT_INVALID", f"$.{field}")


def _rule_task_request_acceptance_sources(
    value: dict[str, object]
) -> None:
    for field in ("acceptance_criteria", "constraints"):
        items = value[field]
        _require(_ordered_unique(items, lambda item: item["source_id"]), "TASK_REQUEST_SOURCE_ID_ORDER_INVALID", f"$.{field}")


def _rule_task_request_sets(value: dict[str, object]) -> None:
    _require(_sorted_unique(value["requested_capabilities"]), "TASK_REQUEST_CAPABILITY_ORDER_INVALID")
    _require(_sorted_unique(value["delivery"]["required_outputs"]), "TASK_REQUEST_DELIVERY_ORDER_INVALID")


def _rule_task_request(value: dict[str, object]) -> None:
    _utf8_fields(value)
    _rule_task_request_acceptance_sources(value)
    _rule_task_request_sets(value)


def _rule_policy_capability_sets(value: dict[str, object]) -> None:
    granted = value["granted_capabilities"]
    denied = value["denied_capabilities"]
    denied_ids = [item["id"] for item in denied]
    _require(_sorted_unique(granted), "POLICY_CAPABILITY_ORDER_INVALID")
    _require(_ordered_unique(denied, lambda item: item["id"]), "POLICY_CAPABILITY_ORDER_INVALID")
    _require(not set(granted).intersection(denied_ids), "POLICY_CAPABILITY_OVERLAP")


def _rule_policy_roots_and_origins(value: dict[str, object]) -> None:
    _require(_sorted_unique(value["allowed_read_roots"]), "POLICY_ROOT_ORDER_INVALID")
    _require(_sorted_unique(value["allowed_write_roots"]), "POLICY_ROOT_ORDER_INVALID")
    origins = value["agent_tool_network"]["origins"]
    _require(_sorted_unique(origins), "POLICY_ORIGIN_ORDER_INVALID")


def _rule_policy_risk_ceiling(value: dict[str, object]) -> None:
    _require(value["capability_risk_ceiling"] in {"R0", "R1"}, "POLICY_RISK_CEILING_INVALID")
    _require(value["quality_risk_floor"] == "Q1", "POLICY_QUALITY_RISK_FLOOR_INVALID")
    _require(value["source_write_mode"] == "read_only", "POLICY_SOURCE_WRITE_INVALID")
    _require(value["agent_tool_network"] == {"mode": "deny", "origins": []}, "POLICY_NETWORK_INVALID")
    _require(value["dependency_install"] == "deny", "POLICY_DEPENDENCY_INSTALL_INVALID")
    _require(value["interaction_mode"] == "unavailable", "POLICY_INTERACTION_INVALID")
    _require(value["authorized_waiver_issuers"] == [], "POLICY_WAIVER_ISSUER_INVALID")


def _rule_policy_budget_ceilings(value: dict[str, object]) -> None:
    budgets = value["budgets"]
    _require(value["terminalization_reserve_ms"] <= budgets["wall_ms"], "POLICY_RESERVE_INVALID")
    _require(value["max_agent_sessions_total"] <= budgets["agent_sessions"], "POLICY_SESSION_CEILING_INVALID")
    _require(value["max_attempts"] <= budgets["attempts"], "POLICY_ATTEMPT_CEILING_INVALID")
    _require(value["max_agents"] <= value["max_agent_sessions_total"], "POLICY_AGENT_CEILING_INVALID")


def _rule_policy_digest(value: dict[str, object]) -> None:
    unsigned = {key: item for key, item in value.items() if key != "digest"}
    raw = (
        b"pullwise:effective-execution-policy/v1\0"
        + canonical_document_bytes(unsigned)
    )
    _require(
        value["digest"] == hashlib.sha256(raw).hexdigest(),
        "CONTRACT_DIGEST_MISMATCH",
        "$.digest",
    )


def _rule_effective_policy(value: dict[str, object]) -> None:
    _rule_policy_capability_sets(value)
    _rule_policy_roots_and_origins(value)
    _rule_policy_risk_ceiling(value)
    _rule_policy_budget_ceilings(value)
    _rule_policy_digest(value)


_REQUIREMENT_KIND_RANK = {
    "user_objective": 0,
    "user_acceptance": 1,
    "user_constraint": 2,
    "delivery": 3,
    "policy": 4,
    "interaction": 5,
    "derived": 5,
}


def _requirement_ingest_key(value: dict[str, object]) -> tuple[object, ...]:
    rank = _REQUIREMENT_KIND_RANK[value["source_kind"]]
    return (
        rank,
        value["ledger_version"] if rank >= 5 else 0,
        value["source_id"],
        value["requirement_id"],
    )


def _rule_requirement_entry(value: dict[str, object]) -> None:
    _utf8_fields(value)
    expected = "req_" + value["source_kind"] + "_"
    _require(value["requirement_id"].startswith(expected), "REQUIREMENT_ID_KIND_INVALID")
    _require(_sorted_unique(value["parent_requirement_ids"]), "REQUIREMENT_PARENT_ORDER_INVALID")
    _require(_sorted_unique(value["supersedes"]), "REQUIREMENT_SUPERSEDES_ORDER_INVALID")
    if value["source_kind"] == "derived" and value["mandatory"]:
        _require(bool(value["rationale"]), "DERIVED_REQUIREMENT_RATIONALE_REQUIRED")


def _requirement_graph_acyclic(entries: list[dict[str, object]]) -> None:
    graph = {item["requirement_id"]: item["parent_requirement_ids"] for item in entries}
    visiting: set[str] = set()
    visited: set[str] = set()

    def visit(requirement_id: str) -> None:
        if requirement_id in visiting:
            _fail("REQUIREMENT_CYCLE_INVALID")
        if requirement_id in visited:
            return
        visiting.add(requirement_id)
        for parent in graph[requirement_id]:
            if parent in graph:
                visit(parent)
        visiting.remove(requirement_id)
        visited.add(requirement_id)

    for requirement_id in graph:
        visit(requirement_id)


def _rule_requirement_ledger(value: dict[str, object]) -> None:
    entries = value["entries"]
    for item in entries:
        _rule_requirement_entry(item)
        _require(item["ledger_version"] <= value["ledger_version"], "REQUIREMENT_LEDGER_VERSION_INVALID")
    _require(entries == sorted(entries, key=_requirement_ingest_key), "REQUIREMENT_INGEST_ORDER_INVALID")
    _requirement_graph_acyclic(entries)
    superseded = {identity for item in entries for identity in item["supersedes"]}
    expected = sorted(
        item["requirement_id"]
        for item in entries
        if item["requirement_id"] not in superseded
    )
    _require(value["active_requirement_ids"] == expected, "REQUIREMENT_ACTIVE_SET_INVALID")


def _rule_task_charter(value: dict[str, object]) -> None:
    _utf8_fields(value)
    for field in (
        "scope_in", "scope_out", "assumptions", "requirement_ids",
        "unresolved_questions",
    ):
        _require(_sorted_unique(value[field]), "CHARTER_SET_ORDER_INVALID", f"$.{field}")
    _require(_sorted_unique(value["delivery_plan"]["required_outputs"]), "CHARTER_DELIVERY_ORDER_INVALID")
    _require(
        (value["charter_version"] == 1 and value["previous_charter_ref"] is None)
        or (value["charter_version"] > 1 and value["previous_charter_ref"] is not None),
        "CHARTER_PREDECESSOR_INVALID",
    )


def _rule_waiver(value: dict[str, object]) -> None:
    _utf8_fields(value)
    _require(value["issued_at"] < value["expires_at"], "WAIVER_TIME_RANGE_INVALID", code="WAIVER_INVALID")


def _transport_binding_complete(value: dict[str, object]) -> bool:
    fields = ("outer_job_id", "run_id", "lease_id", "transport_epoch")
    values = [value[key] for key in fields]
    return all(item is None for item in values) or all(item is not None for item in values)


def _rule_attempt_record(value: dict[str, object]) -> None:
    binding = value["transport_binding"]
    _require(_transport_binding_complete(binding), "ATTEMPT_TRANSPORT_BINDING_INVALID")
    terminal = value["state"] in {"SUCCEEDED", "SUSPENDED", "FAILED", "CANCELLED", "FENCED"}
    _require(
        (value["ended_at"] is not None and value["termination_reason"] is not None) == terminal,
        "ATTEMPT_STATE_NULLABILITY_INVALID",
    )
    if value["state"] == "FENCED":
        _require(value["termination_reason"] == "OWNERSHIP_LOST", "ATTEMPT_FENCE_REASON_INVALID")


def _rule_task_owner(value: dict[str, object]) -> None:
    terminal = value["state"] in {"CLOSED", "FENCED"}
    _require(
        (value["ended_at"] is not None and value["termination_reason"] is not None) == terminal,
        "OWNER_STATE_NULLABILITY_INVALID",
    )
    if value["state"] == "FENCED":
        _require(value["termination_reason"] == "OWNERSHIP_LOST", "OWNER_FENCE_REASON_INVALID")


def _rule_task_record(value: dict[str, object]) -> None:
    values = [value[key] for key in ("outer_job_id", "run_id", "lease_id", "transport_epoch")]
    _require(
        all(item is None for item in values) or all(item is not None for item in values),
        "TASK_RECORD_TRANSPORT_BINDING_INVALID",
    )
    terminal = value["lifecycle"] == "TERMINAL"
    terminal_fields = ("terminal_kind", "result_ref", "result_digest", "outcome", "terminal_at")
    _require(
        all(value[key] is not None for key in terminal_fields) == terminal,
        "TASK_RECORD_TERMINAL_RESULT_INVALID",
    )
    _require((value["charter_ref"] is None) == (value["charter_version"] == 0), "TASK_RECORD_CHARTER_HEAD_INVALID")
    checkpoint_null = value["current_checkpoint_generation"] is None
    _require(checkpoint_null == (value["current_checkpoint_hash"] is None), "TASK_RECORD_CHECKPOINT_HEAD_INVALID")


def _rule_tool_catalog(value: dict[str, object]) -> None:
    tools = value["tools"]
    _require(_ordered_unique(tools, lambda item: item["tool_key"]), "TOOL_CATALOG_ORDER_INVALID")
    for item in tools:
        _require(item["risk"] == "R0", "TOOL_CATALOG_RISK_INVALID")
        _require(not any(item[key] for key in ("uses_command", "uses_network", "uses_secret", "requests_approval")), "TOOL_CATALOG_EFFECT_INVALID")
        _require(item["request_schema_id"] == "agent-tool-request/v1", "TOOL_CATALOG_REQUEST_SCHEMA_INVALID")


def _rule_agent_tool_request(value: dict[str, object]) -> None:
    _require(set(value["tool_input"]) == {"relative_path"}, "TOOL_INPUT_SHAPE_INVALID")


def _rule_tool_invocation(value: dict[str, object]) -> None:
    _rule_agent_tool_request({
        "tool_input": value["tool_input"],
    })


def _rule_tool_intent(value: dict[str, object]) -> None:
    _require(value["state"] == "INTENT", "TOOL_INTENT_STATE_INVALID")
    _require(set(value["tool_input"]) == {"relative_path"}, "TOOL_INPUT_SHAPE_INVALID")


def _rule_tool_capability(value: dict[str, object]) -> None:
    _require(value["capability_kind"] == "opaque_dispatch", "TOOL_CAPABILITY_KIND_INVALID")
    _require(value["max_uses"] == 1, "TOOL_CAPABILITY_USE_LIMIT_INVALID")


def _rule_local_receipt(value: dict[str, object]) -> None:
    _require(value["receipt_kind"] == "local_tool", "TOOL_RECEIPT_KIND_INVALID")
    _require(value["status"] == "succeeded", "TOOL_RECEIPT_STATUS_INVALID")
    started, completed = _timestamp_millis(value["started_at"]), _timestamp_millis(value["completed_at"])
    _require(
        started is not None and completed is not None and completed >= started
        and value["elapsed_ms"] == completed - started,
        "TOOL_RECEIPT_TIMING_INVALID",
    )


def _normalized_relative_path(value: str) -> bool:
    return (
        value != ""
        and "\\" not in value
        and not value.startswith("/")
        and all(item not in {"", ".", ".."} for item in value.split("/"))
    )


def _rule_r0_payload(value: dict[str, object]) -> None:
    _require(_normalized_relative_path(value["relative_path"]), "R0_PATH_INVALID")


def _rule_r0_result(value: dict[str, object]) -> None:
    _require(
        value["source_state_before_id"] == value["source_state_after_id"],
        "R0_SOURCE_STATE_CHANGED",
        code="SOURCE_STATE_CHANGED",
    )


def _rule_source_state(value: dict[str, object]) -> None:
    identity = {
        "task_id": value["task_id"],
        "attempt_id": value["attempt_id"],
        "native_epoch": value["native_epoch"],
        "repository_root_id": value["repository_root_id"],
        "entry_count": value["entry_count"],
        "manifest_sha256": value["manifest_sha256"],
    }
    _require(value["source_state_id"] == canonical_document_sha256(identity), "SOURCE_STATE_ID_INVALID")


_TASK_CONTROL_REQUIREMENT_KIND_RANK = {
    "user_objective": 0,
    "user_acceptance": 1,
    "user_constraint": 2,
    "delivery": 3,
    "policy": 4,
    "interaction": 5,
    "derived": 5,
}


def _task_control_utf8_walk(
    rule: dict[str, object], value: object, path: str
) -> None:
    if "$ref" in rule:
        _task_control_utf8_walk(schema(rule["$ref"]), value, path)
        return
    if "oneOf" in rule:
        for option in rule["oneOf"]:
            try:
                _validate_node(option, value, path)
            except ContractValidationError:
                continue
            _task_control_utf8_walk(option, value, path)
            break
    if isinstance(value, str):
        _require(
            unicodedata.normalize("NFC", value) == value,
            "UTF8_NFC_INVALID",
            path,
        )
        limit = rule.get("maxLength")
        if isinstance(limit, int):
            _require(
                len(value.encode("utf-8")) <= limit,
                "UTF8_BYTE_LIMIT_INVALID",
                path,
            )
    elif isinstance(value, dict):
        properties = rule.get("properties", {})
        for key, item in value.items():
            if key in properties:
                _task_control_utf8_walk(
                    properties[key], item, f"{path}.{key}"
                )
    elif isinstance(value, list) and "items" in rule:
        for index, item in enumerate(value):
            _task_control_utf8_walk(
                rule["items"], item, f"{path}[{index}]"
            )


def _task_control_rule_utf8(value: dict[str, object]) -> None:
    _task_control_utf8_walk(schema(value["schema_id"]), value, "$")


def _task_control_rule_request_acceptance_sources(
    value: dict[str, object]
) -> None:
    items = value["acceptance_criteria"] + value["constraints"]
    source_ids = [item["source_id"] for item in items]
    _require(
        len(source_ids) == len(set(source_ids)),
        "TASK_REQUEST_SOURCE_ID_INVALID",
    )


def _task_control_rule_request_sets(value: dict[str, object]) -> None:
    _require(
        _sorted_unique(value["requested_capabilities"]),
        "TASK_REQUEST_CAPABILITY_ORDER_INVALID",
    )
    _require(
        _sorted_unique(value["delivery"]["required_outputs"]),
        "TASK_REQUEST_DELIVERY_ORDER_INVALID",
    )


def _task_control_rule_policy_capabilities(value: dict[str, object]) -> None:
    granted = value["granted_capabilities"]
    denied_ids = [item["id"] for item in value["denied_capabilities"]]
    _require(
        _sorted_unique(granted) and _sorted_unique(denied_ids),
        "POLICY_CAPABILITY_ORDER_INVALID",
    )
    _require(
        not set(granted).intersection(denied_ids),
        "POLICY_CAPABILITY_OVERLAP",
    )


def _task_control_rule_policy_roots(value: dict[str, object]) -> None:
    for field in ("allowed_read_roots", "allowed_write_roots"):
        _require(
            _sorted_unique(value[field]),
            "POLICY_ROOT_ORDER_INVALID",
        )
    _require(
        _sorted_unique(value["agent_tool_network"]["origins"]),
        "POLICY_ORIGIN_ORDER_INVALID",
    )


def _task_control_rule_policy_mvp(value: dict[str, object]) -> None:
    _require(
        value["capability_risk_ceiling"] in {"R0", "R1"},
        "POLICY_RISK_CEILING_INVALID",
    )
    _require(
        value["quality_risk_floor"] == "Q1",
        "POLICY_QUALITY_RISK_FLOOR_INVALID",
    )
    _require(
        value["source_write_mode"] == "read_only",
        "POLICY_SOURCE_WRITE_INVALID",
    )
    _require(
        value["agent_tool_network"] == {"mode": "deny", "origins": []},
        "POLICY_NETWORK_INVALID",
    )
    _require(
        value["dependency_install"] == "deny",
        "POLICY_DEPENDENCY_INSTALL_INVALID",
    )
    _require(
        value["interaction_mode"] == "unavailable",
        "POLICY_INTERACTION_INVALID",
    )
    _require(
        value["authorized_waiver_issuers"] == [],
        "POLICY_WAIVER_ISSUER_INVALID",
    )


def _task_control_rule_policy_budgets(value: dict[str, object]) -> None:
    budgets = value["budgets"]
    _require(
        value["terminalization_reserve_ms"] <= budgets["wall_ms"],
        "POLICY_RESERVE_INVALID",
    )
    _require(
        value["max_agent_sessions_total"] <= budgets["agent_sessions"],
        "POLICY_SESSION_CEILING_INVALID",
    )
    _require(
        value["max_attempts"] <= budgets["attempts"],
        "POLICY_ATTEMPT_CEILING_INVALID",
    )
    _require(
        value["max_agents"] <= value["max_agent_sessions_total"],
        "POLICY_AGENT_CEILING_INVALID",
    )


def _task_control_embedded_digest(
    value: dict[str, object], field: str, domain: str
) -> None:
    unsigned = {key: item for key, item in value.items() if key != field}
    expected = hashlib.sha256(
        domain.encode("utf-8")
        + b"\0"
        + canonical_document_bytes(unsigned)
    ).hexdigest()
    _require(value[field] == expected, "CONTRACT_DIGEST_MISMATCH", f"$.{field}")


def _task_control_rule_policy_digest(value: dict[str, object]) -> None:
    _task_control_embedded_digest(
        value, "digest", "pullwise:effective-execution-policy/v1"
    )


def _task_control_rule_requirement_shape(value: dict[str, object]) -> None:
    if value["source_kind"] == "derived" and value["mandatory"]:
        _require(
            bool(value["rationale"]),
            "DERIVED_REQUIREMENT_RATIONALE_REQUIRED",
            "$.rationale",
        )


def _task_control_rule_requirement_id(value: dict[str, object]) -> None:
    _require(
        value["requirement_id"].startswith(
            "req_" + value["source_kind"] + "_"
        ),
        "REQUIREMENT_ID_KIND_INVALID",
        "$.requirement_id",
    )


def _task_control_rule_requirement_links(value: dict[str, object]) -> None:
    for field in ("parent_requirement_ids", "supersedes"):
        _require(
            _sorted_unique(value[field]),
            "REQUIREMENT_LINK_ORDER_INVALID",
            f"$.{field}",
        )
    _require(
        value["requirement_id"] not in value["parent_requirement_ids"],
        "REQUIREMENT_SELF_LINK_INVALID",
        "$.parent_requirement_ids",
    )
    _require(
        value["requirement_id"] not in value["supersedes"],
        "REQUIREMENT_SELF_LINK_INVALID",
        "$.supersedes",
    )


def _task_control_requirement_key(
    value: dict[str, object]
) -> tuple[object, ...]:
    rank = _TASK_CONTROL_REQUIREMENT_KIND_RANK[value["source_kind"]]
    return (
        rank,
        value["ledger_version"] if rank >= 5 else 0,
        value["source_id"],
        value["requirement_id"],
    )


def _task_control_requirement_graph(
    entries: list[dict[str, object]]
) -> None:
    by_id = {item["requirement_id"]: item for item in entries}
    _require(
        len(by_id) == len(entries),
        "REQUIREMENT_ID_COLLISION",
        code="REQUIREMENT_ID_COLLISION",
    )
    visiting: set[str] = set()
    visited: set[str] = set()

    def visit(requirement_id: str) -> None:
        if requirement_id in visiting:
            _fail("REQUIREMENT_CYCLE_INVALID")
        if requirement_id in visited:
            return
        visiting.add(requirement_id)
        for parent in by_id[requirement_id]["parent_requirement_ids"]:
            _require(parent in by_id, "REQUIREMENT_PARENT_UNKNOWN")
            visit(parent)
        visiting.remove(requirement_id)
        visited.add(requirement_id)

    for requirement_id in by_id:
        visit(requirement_id)
    for item in entries:
        for superseded in item["supersedes"]:
            target = by_id.get(superseded)
            _require(
                target is not None and target["source_kind"] == "derived",
                "REQUIREMENT_SUPERSEDES_INVALID",
            )


def _task_control_rule_ledger_entries(value: dict[str, object]) -> None:
    entries = value["entries"]
    for item in entries:
        validate_document("requirement-entry/v1", item)
        _require(
            item["ledger_version"] <= value["ledger_version"],
            "REQUIREMENT_LEDGER_VERSION_INVALID",
        )
    _require(
        entries == sorted(entries, key=_task_control_requirement_key),
        "REQUIREMENT_INGEST_ORDER_INVALID",
    )
    if value["ledger_version"] == 1:
        _require(
            all(item["ledger_version"] == 1 for item in entries),
            "REQUIREMENT_LEDGER_VERSION_INVALID",
        )
    _task_control_requirement_graph(entries)


def _task_control_rule_ledger_digest(value: dict[str, object]) -> None:
    _task_control_embedded_digest(
        value, "ledger_digest", "pullwise:requirement-ledger:v1"
    )


def _task_control_rule_ledger_active(value: dict[str, object]) -> None:
    superseded = {
        requirement_id
        for item in value["entries"]
        for requirement_id in item["supersedes"]
    }
    expected = sorted(
        item["requirement_id"]
        for item in value["entries"]
        if item["requirement_id"] not in superseded
    )
    _require(
        value["active_requirement_ids"] == expected,
        "REQUIREMENT_ACTIVE_SET_INVALID",
        "$.active_requirement_ids",
    )


def _task_control_rule_charter_digest(value: dict[str, object]) -> None:
    _task_control_embedded_digest(
        value, "digest", "pullwise:task-charter:v1"
    )


def _task_control_rule_charter_sets(value: dict[str, object]) -> None:
    for field in ("scope_in", "scope_out", "requirement_ids"):
        _require(
            _sorted_unique(value[field]),
            "CHARTER_SET_ORDER_INVALID",
            f"$.{field}",
        )
    _require(
        _sorted_unique(value["delivery_plan"]["required_outputs"]),
        "CHARTER_DELIVERY_ORDER_INVALID",
        "$.delivery_plan.required_outputs",
    )
    predecessor = value["previous_charter_ref"]
    _require(
        (value["charter_version"] == 1 and predecessor is None)
        or (value["charter_version"] > 1 and predecessor is not None),
        "CHARTER_PREDECESSOR_INVALID",
        "$.previous_charter_ref",
    )


def _task_control_rule_waiver_time(value: dict[str, object]) -> None:
    _require(
        value["issued_at"] < value["expires_at"],
        "WAIVER_TIME_RANGE_INVALID",
        code="WAIVER_INVALID",
    )


_TASK_CONTROL_ATTEMPT_TERMINAL = {
    "SUCCEEDED", "SUSPENDED", "FAILED", "CANCELLED", "FENCED"
}


def _task_control_rule_attempt_nullability(value: dict[str, object]) -> None:
    terminal = value["state"] in _TASK_CONTROL_ATTEMPT_TERMINAL
    _require(
        (value["ended_at"] is not None)
        == (value["termination_reason"] is not None)
        == terminal,
        "ATTEMPT_STATE_NULLABILITY_INVALID",
    )


def _task_control_rule_attempt_transport(value: dict[str, object]) -> None:
    binding = value["transport_binding"]
    fields = ("outer_job_id", "run_id", "lease_id", "transport_epoch")
    present = [binding[field] is not None for field in fields]
    _require(
        all(present) or not any(present),
        "ATTEMPT_TRANSPORT_BINDING_INVALID",
        "$.transport_binding",
    )


def _task_control_rule_fenced_reason(value: dict[str, object]) -> None:
    if value["state"] == "FENCED":
        _require(
            value["termination_reason"] == "OWNERSHIP_LOST",
            "FENCED_REASON_INVALID",
            "$.termination_reason",
        )


def _task_control_rule_owner_nullability(value: dict[str, object]) -> None:
    terminal = value["state"] in {"CLOSED", "FENCED"}
    _require(
        (value["ended_at"] is not None)
        == (value["termination_reason"] is not None)
        == terminal,
        "OWNER_STATE_NULLABILITY_INVALID",
    )


def _task_control_rule_record_heads(value: dict[str, object]) -> None:
    _require(
        (value["charter_version"] == 0) == (value["charter_ref"] is None),
        "TASK_RECORD_CHARTER_HEAD_INVALID",
        "$.charter_ref",
    )
    _require(
        (value["current_checkpoint_generation"] == 0)
        == (value["current_checkpoint_hash"] is None),
        "TASK_RECORD_CHECKPOINT_HEAD_INVALID",
        "$.current_checkpoint_hash",
    )


def _task_control_rule_record_transport(value: dict[str, object]) -> None:
    fields = ("outer_job_id", "run_id", "lease_id", "transport_epoch")
    present = [value[field] is not None for field in fields]
    _require(
        all(present) or not any(present),
        "TASK_RECORD_TRANSPORT_BINDING_INVALID",
    )


def _task_control_rule_record_terminal(value: dict[str, object]) -> None:
    terminal = value["lifecycle"] == "TERMINAL"
    fields = (
        "terminal_kind", "result_ref", "result_digest", "outcome",
        "terminal_at",
    )
    _require(
        all(value[field] is not None for field in fields) == terminal,
        "TASK_RECORD_TERMINAL_RESULT_INVALID",
    )
    if not terminal:
        _require(
            all(value[field] is None for field in fields),
            "TASK_RECORD_TERMINAL_RESULT_INVALID",
        )


def validate_task_request_acceptance(
    request: object,
    expected_task_id: str | None = None,
    expected_task_type: str | None = None,
) -> dict[str, object]:
    checked = validate_document("task-request/v1", request)
    _require(
        checked["submitted_by"]["kind"] in {"user_control", "server_control"},
        "TASK_REQUEST_SUBMITTER_INVALID",
    )
    if expected_task_id is not None:
        _require(
            checked["task_id"] == expected_task_id,
            "TASK_REQUEST_TASK_ID_INVALID",
            "$.task_id",
        )
    if expected_task_type is not None:
        _require(
            checked["task_type"] == expected_task_type,
            "TASK_REQUEST_TASK_TYPE_INVALID",
            "$.task_type",
        )
    interaction = checked["interaction_policy"]
    if interaction["mode"] == "unavailable":
        _require(
            interaction["input_deadline_ms"] == 0
            and interaction["approval_deadline_ms"] == 0,
            "TASK_REQUEST_INTERACTION_DEADLINE_INVALID",
            "$.interaction_policy",
        )
    return checked


def validate_effective_policy_derivation(
    request: object, policy: object
) -> dict[str, object]:
    accepted = validate_task_request_acceptance(request)
    effective = verify_document_digest(
        "effective-execution-policy/v1", policy
    )
    _require(
        effective["issuer"]["kind"] == "server_control",
        "POLICY_ISSUER_INVALID",
        "$.issuer",
        code="POLICY_INVARIANT_BROKEN",
    )
    _require(
        effective["task_type"] == accepted["task_type"],
        "POLICY_TASK_TYPE_DERIVATION_INVALID",
        "$.task_type",
    )
    _require(
        effective["issued_at"] >= accepted["submitted_at"],
        "POLICY_ISSUED_BEFORE_REQUEST",
        "$.issued_at",
    )
    requested = set(accepted["requested_capabilities"])
    granted = set(effective["granted_capabilities"])
    denied = {item["id"] for item in effective["denied_capabilities"]}
    _require(
        granted.issubset(requested),
        "POLICY_UNREQUESTED_CAPABILITY_GRANTED",
        "$.granted_capabilities",
        code="POLICY_INVARIANT_BROKEN",
    )
    _require(
        requested == granted.union(requested.intersection(denied)),
        "POLICY_REQUESTED_CAPABILITY_UNDECIDED",
        code="POLICY_INVARIANT_BROKEN",
    )
    for field, ceiling in accepted["requested_budgets"].items():
        if ceiling != 0:
            _require(
                effective["budgets"][field] <= ceiling,
                "POLICY_REQUEST_BUDGET_EXCEEDED",
                f"$.budgets.{field}",
                code="POLICY_INVARIANT_BROKEN",
            )
    _require(
        effective["interaction_mode"]
        == accepted["interaction_policy"]["mode"],
        "POLICY_INTERACTION_DERIVATION_INVALID",
        "$.interaction_mode",
        code="POLICY_INVARIANT_BROKEN",
    )
    return effective


def validate_requirement_entry_ingest(
    entry: object, previous_ledger: object | None = None
) -> dict[str, object]:
    checked = validate_document("requirement-entry/v1", entry)
    if previous_ledger is None:
        _require(
            checked["ledger_version"] == 1,
            "REQUIREMENT_INGEST_VERSION_INVALID",
            "$.ledger_version",
        )
        return checked
    previous = verify_document_digest(
        "requirement-ledger/v1", previous_ledger
    )
    _require(
        checked["ledger_version"] == previous["ledger_version"] + 1,
        "REQUIREMENT_INGEST_VERSION_INVALID",
        "$.ledger_version",
    )
    by_id = {item["requirement_id"]: item for item in previous["entries"]}
    _require(
        checked["requirement_id"] not in by_id,
        "REQUIREMENT_ID_COLLISION",
        "$.requirement_id",
        code="REQUIREMENT_ID_COLLISION",
    )
    _require(
        set(checked["parent_requirement_ids"]).issubset(by_id),
        "REQUIREMENT_PARENT_UNKNOWN",
        "$.parent_requirement_ids",
    )
    active = set(previous["active_requirement_ids"])
    for requirement_id in checked["supersedes"]:
        target = by_id.get(requirement_id)
        _require(
            requirement_id in active
            and target is not None
            and target["source_kind"] == "derived",
            "REQUIREMENT_SUPERSEDES_INVALID",
            "$.supersedes",
        )
    return checked


def validate_requirement_ledger_transition(
    previous_ledger: object, candidate_ledger: object
) -> dict[str, object]:
    previous = verify_document_digest(
        "requirement-ledger/v1", previous_ledger
    )
    candidate = verify_document_digest(
        "requirement-ledger/v1", candidate_ledger
    )
    _require(
        candidate["task_id"] == previous["task_id"],
        "REQUIREMENT_LEDGER_TASK_INVALID",
        "$.task_id",
    )
    _require(
        candidate["ledger_version"] == previous["ledger_version"] + 1,
        "REQUIREMENT_LEDGER_SUCCESSOR_INVALID",
        "$.ledger_version",
    )
    prefix_length = len(previous["entries"])
    _require(
        candidate["entries"][:prefix_length] == previous["entries"],
        "REQUIREMENT_LEDGER_HISTORY_MUTATED",
        "$.entries",
    )
    appended = candidate["entries"][prefix_length:]
    _require(bool(appended), "REQUIREMENT_LEDGER_APPEND_REQUIRED", "$.entries")
    _require(
        all(
            item["ledger_version"] == candidate["ledger_version"]
            for item in appended
        ),
        "REQUIREMENT_INGEST_VERSION_INVALID",
        "$.entries",
    )
    previous_ids = {item["requirement_id"] for item in previous["entries"]}
    appended_ids = [item["requirement_id"] for item in appended]
    _require(
        not previous_ids.intersection(appended_ids)
        and len(appended_ids) == len(set(appended_ids)),
        "REQUIREMENT_ID_COLLISION",
        "$.entries",
        code="REQUIREMENT_ID_COLLISION",
    )
    return candidate


def validate_task_charter_transition(
    previous_charter: object | None,
    candidate_charter: object,
    requirement_ledger: object | None = None,
) -> dict[str, object]:
    candidate = verify_document_digest("task-charter/v1", candidate_charter)
    if previous_charter is None:
        _require(
            candidate["charter_version"] == 1
            and candidate["previous_charter_ref"] is None,
            "CHARTER_PREDECESSOR_INVALID",
            "$.previous_charter_ref",
        )
    else:
        previous = verify_document_digest("task-charter/v1", previous_charter)
        predecessor = candidate["previous_charter_ref"]
        previous_bytes = canonical_document_bytes(previous)
        _require(
            candidate["task_id"] == previous["task_id"],
            "CHARTER_TASK_INVALID",
            "$.task_id",
        )
        _require(
            candidate["charter_version"] == previous["charter_version"] + 1,
            "CHARTER_VERSION_INVALID",
            "$.charter_version",
        )
        _require(
            predecessor is not None
            and predecessor["sha256"]
            == hashlib.sha256(previous_bytes).hexdigest()
            and predecessor["size_bytes"] == len(previous_bytes),
            "CHARTER_PREDECESSOR_INVALID",
            "$.previous_charter_ref",
        )
        _require(
            candidate["created_at"] >= previous["created_at"],
            "CHARTER_TIME_ORDER_INVALID",
            "$.created_at",
        )
    if requirement_ledger is not None:
        ledger = verify_document_digest(
            "requirement-ledger/v1", requirement_ledger
        )
        _require(
            ledger["task_id"] == candidate["task_id"],
            "CHARTER_LEDGER_TASK_INVALID",
            "$.task_id",
        )
        _require(
            set(candidate["requirement_ids"]).issubset(
                ledger["active_requirement_ids"]
            ),
            "CHARTER_REQUIREMENT_INACTIVE",
            "$.requirement_ids",
        )
    return candidate


def verify_waiver_event_authority(
    waiver: object, effective_policy: object, now: str
) -> dict[str, object]:
    event = validate_document("waiver-event/v1", waiver)
    policy = verify_document_digest(
        "effective-execution-policy/v1", effective_policy
    )
    now_millis = _timestamp_millis(now)
    issued = _timestamp_millis(event["issued_at"])
    expires = _timestamp_millis(event["expires_at"])
    _require(
        now_millis is not None
        and issued is not None
        and expires is not None
        and issued <= now_millis < expires,
        "WAIVER_TIME_INVALID",
        code="WAIVER_INVALID",
    )
    _require(
        event["policy_version"] == policy["policy_version"],
        "WAIVER_POLICY_VERSION_INVALID",
        code="WAIVER_INVALID",
    )
    _require(
        event["issuer"] in policy["authorized_waiver_issuers"],
        "WAIVER_ISSUER_NOT_AUTHORIZED",
        code="WAIVER_INVALID",
    )
    _fail(
        "WAIVER_SIGNATURE_AUTHORITY_UNAVAILABLE",
        code="WAIVER_INVALID",
    )


_TASK_CONTROL_ATTEMPT_TRANSITIONS = {
    "CREATED": {"LEASED", "FENCED"},
    "LEASED": {"PREPARING", "FAILED", "CANCELLED", "FENCED"},
    "PREPARING": {"RUNNING", "FAILED", "CANCELLED", "FENCED"},
    "RUNNING": {
        "VERIFYING", "SUSPENDING", "FAILED", "CANCELLED", "FENCED"
    },
    "VERIFYING": {
        "RUNNING", "SUSPENDING", "PUBLISHING", "FAILED", "CANCELLED",
        "FENCED",
    },
    "SUSPENDING": {"SUSPENDED"},
    "PUBLISHING": {"RUNNING", "SUCCEEDED", "FAILED", "CANCELLED", "FENCED"},
    "SUCCEEDED": set(),
    "SUSPENDED": set(),
    "FAILED": set(),
    "CANCELLED": set(),
    "FENCED": set(),
}


def validate_attempt_transition(
    previous_attempt: object, candidate_attempt: object
) -> dict[str, object]:
    previous = validate_document("attempt-record/v1", previous_attempt)
    candidate = validate_document("attempt-record/v1", candidate_attempt)
    immutable = (
        "attempt_id", "task_id", "native_epoch", "transport_binding",
        "predecessor_checkpoint_generation", "owner_session_id",
    )
    _require(
        all(candidate[field] == previous[field] for field in immutable),
        "ATTEMPT_IDENTITY_MUTATED",
        code="AUTHORITY_FENCED",
    )
    _require(
        candidate["state_version"] == previous["state_version"] + 1,
        "ATTEMPT_STATE_VERSION_INVALID",
        "$.state_version",
        code="STATE_TRANSITION_INVALID",
    )
    _require(
        candidate["state"] in _TASK_CONTROL_ATTEMPT_TRANSITIONS[previous["state"]],
        "ATTEMPT_TRANSITION_INVALID",
        "$.state",
        code="STATE_TRANSITION_INVALID",
    )
    return candidate


_TASK_CONTROL_OWNER_TRANSITIONS = {
    "STARTING": {"ACTIVE", "FENCED"},
    "ACTIVE": {"CLOSED", "FENCED"},
    "CLOSED": set(),
    "FENCED": set(),
}


def validate_task_owner_transition(
    previous_owner: object, candidate_owner: object
) -> dict[str, object]:
    previous = validate_document("task-owner/v1", previous_owner)
    candidate = validate_document("task-owner/v1", candidate_owner)
    immutable = (
        "task_id", "owner_id", "owner_epoch", "session_id", "attempt_id",
        "native_epoch", "started_at",
    )
    _require(
        all(candidate[field] == previous[field] for field in immutable),
        "OWNER_IDENTITY_MUTATED",
        code="AUTHORITY_FENCED",
    )
    _require(
        candidate["state_version"] == previous["state_version"] + 1,
        "OWNER_STATE_VERSION_INVALID",
        "$.state_version",
        code="STATE_TRANSITION_INVALID",
    )
    _require(
        candidate["state"] in _TASK_CONTROL_OWNER_TRANSITIONS[previous["state"]],
        "OWNER_TRANSITION_INVALID",
        "$.state",
        code="STATE_TRANSITION_INVALID",
    )
    return candidate


_TASK_CONTROL_RECORD_TRANSITIONS = {
    "QUEUED": {"ACTIVE", "FINALIZING"},
    "ACTIVE": {"ACTIVE", "WAITING_INPUT", "WAITING_APPROVAL", "FINALIZING"},
    "WAITING_INPUT": {"QUEUED", "FINALIZING"},
    "WAITING_APPROVAL": {"QUEUED", "FINALIZING"},
    "FINALIZING": {"ACTIVE", "QUEUED", "RECONCILING", "FINALIZING", "TERMINAL"},
    "RECONCILING": {"RECONCILING", "TERMINAL"},
    "TERMINAL": set(),
}


def validate_task_record_transition(
    previous_record: object, candidate_record: object
) -> dict[str, object]:
    previous = validate_document("task-record/v1", previous_record)
    candidate = validate_document("task-record/v1", candidate_record)
    _require(
        candidate["task_version"] == previous["task_version"] + 1,
        "TASK_VERSION_STALE",
        "$.task_version",
        code="TASK_VERSION_STALE",
    )
    _require(
        candidate["lifecycle"]
        in _TASK_CONTROL_RECORD_TRANSITIONS[previous["lifecycle"]],
        "TASK_RECORD_TRANSITION_INVALID",
        "$.lifecycle",
        code="STATE_TRANSITION_INVALID",
    )
    immutable = (
        "task_id", "task_type", "request_ref", "request_digest",
        "policy_ref", "policy_digest", "policy_version", "protocol_mode",
        "owner_id", "absolute_deadline_at", "terminalization_reserve_ms",
        "created_at",
    )
    _require(
        all(candidate[field] == previous[field] for field in immutable),
        "TASK_RECORD_IDENTITY_MUTATED",
        code="AUTHORITY_FENCED",
    )
    _require(
        not (
            previous["desired_state"] == "CANCEL"
            and candidate["desired_state"] != "CANCEL"
        ),
        "TASK_RECORD_CANCEL_ROLLBACK_INVALID",
        code="STATE_TRANSITION_INVALID",
    )
    _require(
        candidate["deletion_version"] >= previous["deletion_version"],
        "TASK_RECORD_DELETION_VERSION_INVALID",
        code="STATE_TRANSITION_INVALID",
    )
    _require(
        candidate["native_epoch"] >= previous["native_epoch"],
        "TASK_RECORD_NATIVE_EPOCH_INVALID",
        code="NATIVE_EPOCH_STALE",
    )
    _require(
        candidate["owner_epoch"] >= previous["owner_epoch"],
        "TASK_RECORD_OWNER_EPOCH_INVALID",
        code="OWNER_EPOCH_STALE",
    )
    _require(
        candidate["updated_at"] >= previous["updated_at"],
        "TASK_RECORD_TIME_ORDER_INVALID",
        "$.updated_at",
    )
    return candidate


def validate_claim_write_set(
    previous_record: object,
    claimed_record: object,
    attempt_record: object,
    task_owner: object,
) -> dict[str, object]:
    previous = validate_document("task-record/v1", previous_record)
    claimed = validate_task_record_transition(previous, claimed_record)
    attempt = validate_document("attempt-record/v1", attempt_record)
    owner = validate_document("task-owner/v1", task_owner)
    _require(
        previous["lifecycle"] == "QUEUED"
        and claimed["lifecycle"] == "ACTIVE"
        and claimed["desired_state"] == "RUN",
        "CLAIM_TASK_STATE_INVALID",
        code="TASK_NOT_CLAIMABLE",
    )
    _require(
        claimed["native_epoch"] == previous["native_epoch"] + 1
        == attempt["native_epoch"]
        == owner["native_epoch"],
        "CLAIM_NATIVE_EPOCH_INVALID",
        code="NATIVE_EPOCH_STALE",
    )
    _require(
        claimed["owner_epoch"] == previous["owner_epoch"] + 1
        == owner["owner_epoch"],
        "CLAIM_OWNER_EPOCH_INVALID",
        code="OWNER_EPOCH_STALE",
    )
    exact = (
        claimed["task_id"] == attempt["task_id"] == owner["task_id"]
        and claimed["current_attempt_id"]
        == attempt["attempt_id"]
        == owner["attempt_id"]
        and claimed["owner_id"] == owner["owner_id"]
        and attempt["owner_session_id"] == owner["session_id"]
        and attempt["state"] == "LEASED"
        and owner["state"] == "STARTING"
    )
    _require(exact, "CLAIM_WRITE_SET_INVALID", code="AUTHORITY_FENCED")
    binding = attempt["transport_binding"]
    _require(
        binding["protocol_mode"] == claimed["protocol_mode"]
        and all(
            binding[field] == claimed[field]
            for field in ("outer_job_id", "run_id", "lease_id", "transport_epoch")
        ),
        "CLAIM_TRANSPORT_BINDING_INVALID",
        code="AUTHORITY_FENCED",
    )
    return claimed


def _task_control_normalized_instant(value: str) -> str:
    if "." not in value:
        return value
    prefix, fraction = value[:-1].split(".", 1)
    fraction = fraction.rstrip("0")
    return prefix + (("." + fraction) if fraction else "") + "Z"


def validate_task_result_publication(
    previous_record: object,
    terminal_record: object,
    task_result: object,
) -> dict[str, object]:
    previous = validate_document("task-record/v1", previous_record)
    terminal = validate_task_record_transition(previous, terminal_record)
    _require(isinstance(task_result, dict), "TASK_RESULT_CONTEXT_INVALID")
    result = json.loads(canonical_document_bytes(task_result).decode("utf-8"))
    required = {
        "schema_id", "task_id", "task_type", "outcome",
        "published_from_version", "terminal_task_version", "request_ref",
        "policy_ref", "attempt_identity", "owner_identity", "terminal_at",
    }
    _require(
        required.issubset(result) and result.get("schema_id") == "task-result/v1",
        "TASK_RESULT_CONTEXT_INVALID",
    )
    result_bytes = canonical_document_bytes(result)
    result_digest = hashlib.sha256(result_bytes).hexdigest()
    _require(
        previous["lifecycle"] in {"FINALIZING", "RECONCILING"}
        and terminal["lifecycle"] == "TERMINAL",
        "TASK_RESULT_PUBLICATION_STATE_INVALID",
        code="STATE_TRANSITION_INVALID",
    )
    _require(
        result["published_from_version"] == previous["task_version"]
        and result["terminal_task_version"] == terminal["task_version"],
        "TASK_RESULT_PUBLICATION_VERSION_INVALID",
        code="TASK_VERSION_STALE",
    )
    _require(
        result["task_id"] == terminal["task_id"]
        and result["task_type"] == terminal["task_type"]
        and result["outcome"] == terminal["outcome"],
        "TASK_RESULT_PUBLICATION_IDENTITY_INVALID",
    )
    _require(
        terminal["terminal_kind"] == "task_result"
        and terminal["result_digest"] == result_digest
        and terminal["result_ref"]["sha256"] == result_digest
        and terminal["result_ref"]["size_bytes"] == len(result_bytes),
        "TASK_RESULT_PUBLICATION_REF_INVALID",
    )
    _require(
        _task_control_normalized_instant(terminal["terminal_at"])
        == _task_control_normalized_instant(result["terminal_at"]),
        "TASK_RESULT_PUBLICATION_TIME_INVALID",
        "$.terminal_at",
    )
    _require(
        result["request_ref"] == terminal["request_ref"]
        and result["policy_ref"] == terminal["policy_ref"],
        "TASK_RESULT_PUBLICATION_CONTROL_REF_INVALID",
    )
    attempt = result["attempt_identity"]
    owner = result["owner_identity"]
    if attempt["kind"] == "started":
        _require(
            attempt["attempt_id"] == terminal["current_attempt_id"]
            and attempt["native_epoch"] == terminal["native_epoch"]
            and owner["owner_id"] == terminal["owner_id"]
            and owner["owner_epoch"] == terminal["owner_epoch"],
            "TASK_RESULT_PUBLICATION_AUTHORITY_INVALID",
            code="AUTHORITY_FENCED",
        )
    return terminal


def _valid_tool_source_path(value: object) -> bool:
    if not isinstance(value, str) or not value or "\\" in value:
        return False
    if value.startswith("/") or len(value.encode("utf-8")) > 4096:
        return False
    return all(part not in {"", ".", ".."} for part in value.split("/"))


def _rule_agent_tool_request(value: dict[str, object]) -> None:
    _require(
        _valid_tool_source_path(value["tool_input"]["relative_path"]),
        "TOOL_SOURCE_PATH_INVALID",
        "$.tool_input.relative_path",
    )


def _rule_local_tool_receipt(value: dict[str, object]) -> None:
    _verify_embedded_digest("local-tool-receipt/v1", value)
    started = _timestamp_millis(value["started_at"])
    completed = _timestamp_millis(value["completed_at"])
    _require(
        started is not None
        and completed is not None
        and completed >= started
        and value["elapsed_ms"] == completed - started,
        "LOCAL_RECEIPT_TIMING_INVALID",
    )


def _rule_r0_read_payload(value: dict[str, object]) -> None:
    _verify_embedded_digest("r0-read-payload/v1", value)
    _require(
        _valid_tool_source_path(value["relative_path"]),
        "TOOL_SOURCE_PATH_INVALID",
        "$.relative_path",
    )


def _rule_r0_read_result(value: dict[str, object]) -> None:
    _verify_embedded_digest("r0-read-result/v1", value)
    _require(
        value["source_state_before_id"] == value["source_state_after_id"],
        "SOURCE_STATE_CHANGED",
    )


def _rule_source_content(value: dict[str, object]) -> None:
    raw = _decode_canonical_base64(value["data_base64"], "$.data_base64")
    _require(
        len(raw) == value["size_bytes"],
        "SOURCE_CONTENT_SIZE_MISMATCH",
        "$.size_bytes",
    )
    _require(
        hashlib.sha256(raw).hexdigest() == value["byte_sha256"],
        "SOURCE_CONTENT_SHA256_MISMATCH",
        "$.byte_sha256",
    )
    _verify_embedded_digest("source-content/v1", value)


def _rule_source_state(value: dict[str, object]) -> None:
    _verify_embedded_digest("source-state/v1", value)


def _rule_tool_catalog(value: dict[str, object]) -> None:
    _verify_embedded_digest("tool-catalog/v1", value)
    _require(
        _ordered_unique(value["tools"], lambda item: item["tool_key"]),
        "TOOL_CATALOG_ORDER_INVALID",
    )


def _rule_tool_dispatch_capability(value: dict[str, object]) -> None:
    _verify_embedded_digest("tool-dispatch-capability/v1", value)
    _require(
        _timestamp_millis(value["issued_at"]) is not None,
        "TOOL_CAPABILITY_TIME_INVALID",
        "$.issued_at",
    )


def _rule_tool_dispatch_intent(value: dict[str, object]) -> None:
    _verify_embedded_digest("tool-dispatch-intent/v1", value)
    _require(
        _valid_tool_source_path(value["tool_input"]["relative_path"]),
        "TOOL_SOURCE_PATH_INVALID",
        "$.tool_input.relative_path",
    )
    _require(
        _timestamp_millis(value["created_at"]) is not None,
        "TOOL_INTENT_TIME_INVALID",
        "$.created_at",
    )


def _rule_tool_invocation(value: dict[str, object]) -> None:
    _verify_embedded_digest("tool-invocation/v1", value)
    _require(
        _valid_tool_source_path(value["tool_input"]["relative_path"]),
        "TOOL_SOURCE_PATH_INVALID",
        "$.tool_input.relative_path",
    )


def _tool_exact(left: dict[str, object], right: dict[str, object], fields) -> bool:
    return all(_json_equal(left[field], right[field]) for field in fields)


def validate_tool_invocation_binding(
    request: object, invocation: object, catalog: object
) -> bool:
    checked_request = validate_document("agent-tool-request/v1", request)
    checked_invocation = verify_document_digest("tool-invocation/v1", invocation)
    checked_catalog = verify_document_digest("tool-catalog/v1", catalog)
    descriptor = next(
        (
            item
            for item in checked_catalog["tools"]
            if item["tool_key"] == checked_request["tool_key"]
        ),
        None,
    )
    if descriptor is None:
        _fail("TOOL_INVOCATION_BINDING_INVALID")
    _require(
        descriptor["request_schema_id"] == checked_request["schema_id"]
        and _tool_exact(
            checked_request,
            checked_invocation,
            ("idempotency_key", "tool_key", "tool_input"),
        ),
        "TOOL_INVOCATION_BINDING_INVALID",
    )
    return True


def validate_tool_journal_begin(
    invocation: object, intent: object, capability: object
) -> bool:
    checked_invocation = verify_document_digest("tool-invocation/v1", invocation)
    checked_intent = verify_document_digest("tool-dispatch-intent/v1", intent)
    checked_capability = verify_document_digest(
        "tool-dispatch-capability/v1", capability
    )
    exact = (
        "package", "authority_digest", "grant_digest", "invocation_digest",
        "task_id", "idempotency_key", "tool_key", "tool_input",
    )
    _require(
        _tool_exact(checked_intent, checked_invocation, exact),
        "TOOL_INTENT_BINDING_INVALID",
    )
    _require(
        _json_equal(checked_capability["package"], checked_intent["package"])
        and checked_capability["intent_digest"] == checked_intent["intent_digest"]
        and checked_capability["capability_digest"]
        == checked_intent["capability_digest"]
        and checked_capability["issued_at"] == checked_intent["created_at"],
        "TOOL_CAPABILITY_BINDING_INVALID",
    )
    return True


def validate_tool_capability_consumption(
    intent: object, capability: object, consumed_capability_digests: object
) -> bool:
    checked_intent = verify_document_digest("tool-dispatch-intent/v1", intent)
    checked_capability = verify_document_digest(
        "tool-dispatch-capability/v1", capability
    )
    _require(
        isinstance(consumed_capability_digests, list)
        and all(
            isinstance(item, str) and re.fullmatch(r"[0-9a-f]{64}", item)
            for item in consumed_capability_digests
        )
        and _sorted_unique(consumed_capability_digests),
        "TOOL_CAPABILITY_CONSUMPTION_INVALID",
    )
    _require(
        checked_capability["intent_digest"] == checked_intent["intent_digest"]
        and checked_capability["capability_digest"]
        == checked_intent["capability_digest"],
        "TOOL_CAPABILITY_BINDING_INVALID",
    )
    _require(
        checked_capability["capability_digest"]
        not in consumed_capability_digests,
        "CAPABILITY_ALREADY_CONSUMED",
    )
    return True


def _verify_tool_content_ref(
    reference: object, schema_id: str, document: dict[str, object]
) -> None:
    checked = validate_document("content-ref/v1", reference)
    encoded = canonical_document_bytes(document)
    _require(
        checked["content_schema_id"] == schema_id
        and checked["sha256"] == hashlib.sha256(encoded).hexdigest()
        and checked["size_bytes"] == len(encoded)
        and checked["media_type"] == "application/json"
        and checked["encoding"] == "utf-8",
        "TOOL_CONTENT_REF_BINDING_INVALID",
    )


def validate_tool_journal_settlement(
    invocation: object,
    intent: object,
    receipt: object,
    payload: object,
    result: object,
    source_before: object,
    source_after: object,
) -> bool:
    checked_invocation = verify_document_digest("tool-invocation/v1", invocation)
    checked_intent = verify_document_digest("tool-dispatch-intent/v1", intent)
    checked_receipt = verify_document_digest("local-tool-receipt/v1", receipt)
    checked_payload = verify_document_digest("r0-read-payload/v1", payload)
    checked_result = verify_document_digest("r0-read-result/v1", result)
    before = verify_document_digest("source-state/v1", source_before)
    after = verify_document_digest("source-state/v1", source_after)
    _require(
        checked_intent["invocation_digest"] == checked_invocation["invocation_digest"]
        and checked_intent["task_id"] == checked_invocation["task_id"]
        and checked_intent["idempotency_key"] == checked_invocation["idempotency_key"]
        and checked_intent["tool_key"] == checked_invocation["tool_key"]
        and _json_equal(checked_intent["tool_input"], checked_invocation["tool_input"]),
        "TOOL_SETTLEMENT_BINDING_INVALID",
    )
    invocation_digest = checked_invocation["invocation_digest"]
    _require(
        checked_receipt["tool_key"] == checked_invocation["tool_key"]
        and checked_receipt["invocation_digest"] == invocation_digest
        and checked_payload["invocation_digest"] == invocation_digest
        and checked_result["invocation_digest"] == invocation_digest
        and checked_payload["relative_path"]
        == checked_invocation["tool_input"]["relative_path"]
        and checked_result["local_receipt_digest"]
        == checked_receipt["receipt_digest"]
        and _json_equal(checked_receipt["payload_ref"], checked_result["payload_ref"]),
        "TOOL_SETTLEMENT_BINDING_INVALID",
    )
    _verify_tool_content_ref(
        checked_receipt["payload_ref"], "r0-read-payload/v1", checked_payload
    )
    identity = ("task_id", "attempt_id", "native_epoch")
    _require(
        all(
            before[field] == checked_invocation[field]
            and after[field] == checked_invocation[field]
            for field in identity
        ),
        "SOURCE_STATE_BINDING_INVALID",
    )
    _require(
        before["source_state_id"] == after["source_state_id"]
        and checked_result["source_state_before_id"] == before["source_state_id"]
        and checked_result["source_state_after_id"] == after["source_state_id"],
        "SOURCE_STATE_CHANGED",
    )
    return True


_ARTIFACT_CONTENT_TUPLES = (
    ("change_set", "change-set/v1", "application/json", "utf-8"),
    ("change_set_patch", "change-set-patch/v1", "application/json", "utf-8"),
    ("r0_read_result", "r0-read-result/v1", "application/json", "utf-8"),
    ("source_content", "source-content/v1", "application/json", "utf-8"),
    ("task_report", "task-report/v1", "application/json", "utf-8"),
)


def _rule_artifact_content_registry(value: dict[str, object]) -> None:
    _verify_embedded_digest("artifact-content-registry/v1", value)
    actual = tuple(
        (
            item["artifact_kind"],
            item["content_schema_id"],
            item["media_type"],
            item["encoding"],
        )
        for item in value["entries"]
    )
    _require(
        actual == _ARTIFACT_CONTENT_TUPLES,
        "ARTIFACT_CONTENT_REGISTRY_INVALID",
    )


def _rule_artifact_content_ref(value: dict[str, object]) -> None:
    expected = next(
        (
            item
            for item in _ARTIFACT_CONTENT_TUPLES
            if item[0] == value["artifact_kind"]
        ),
        None,
    )
    ref = value["ref"]
    _require(
        expected is not None
        and (
            ref["content_schema_id"], ref["media_type"], ref["encoding"]
        )
        == expected[1:],
        "ARTIFACT_CONTENT_TUPLE_INVALID",
    )


def _rule_budget_summary(value: dict[str, object]) -> None:
    _verify_embedded_digest("budget-summary/v1", value)
    if value["consumed_ms"] > value["elapsed_limit_ms"]:
        _fail(
            "BUDGET_SUMMARY_ELAPSED_INVALID",
            code="BUDGET_EXHAUSTED",
        )
    if value["calls_consumed"] > value["tool_call_limit"]:
        _fail(
            "BUDGET_SUMMARY_CALLS_INVALID",
            code="BUDGET_EXHAUSTED",
        )


def _rule_effect_ledger_snapshot(value: dict[str, object]) -> None:
    _verify_embedded_digest("effect-ledger-snapshot/v1", value)
    rows = value["rows"]
    _require(
        value["watermark"] == len(rows),
        "EFFECT_LEDGER_WATERMARK_INVALID",
        "$.watermark",
    )
    effect_ids = [item["effect_id"] for item in rows]
    _require(
        effect_ids == sorted(set(effect_ids)),
        "EFFECT_LEDGER_ROW_ORDER_INVALID",
        "$.rows",
    )
    expected = {
        state: sum(
            item["state"] == state.upper()
            for item in rows
        )
        for state in value["state_counts"]
    }
    _require(
        value["state_counts"] == expected,
        "EFFECT_LEDGER_STATE_COUNTS_INVALID",
        "$.state_counts",
    )


def _rule_task_report(value: dict[str, object]) -> None:
    _verify_embedded_digest("task-report/v1", value)
    _require(
        _ordered_unique(value["sections"], lambda item: item["section_id"]),
        "TASK_REPORT_SECTION_ORDER_INVALID",
        "$.sections",
    )
    for field, limit in (("title", 512), ("summary", 4096)):
        _require(
            len(value[field].encode("utf-8")) <= limit,
            "TASK_REPORT_UTF8_LIMIT_INVALID",
            f"$.{field}",
        )
    all_refs: list[dict[str, object]] = []
    for index, section in enumerate(value["sections"]):
        _require(
            len(section["title"].encode("utf-8")) <= 512
            and len(section["body"].encode("utf-8")) <= 65536,
            "TASK_REPORT_UTF8_LIMIT_INVALID",
            f"$.sections[{index}]",
        )
        _require(
            _ordered_unique(section["evidence_refs"], _ref_key),
            "TASK_REPORT_EVIDENCE_ORDER_INVALID",
            f"$.sections[{index}].evidence_refs",
        )
        all_refs.extend(section["evidence_refs"])
    verify_content_ref_set(all_refs)


_QUALITY_POLICY_INPUT_FIELDS = (
    "proposal_digest",
    "policy_digest",
    "task_type",
    "requirement_ledger_digest",
    "change_set_classification_digest",
    "capability_usage_digest",
)

_QUALITY_POLICY_SLOT_TABLE = {
    "Q1": (
        ("slot_11111111111111111111111111111111", "contract_and_data"),
    ),
    "Q2": (
        ("slot_11111111111111111111111111111111", "contract_and_data"),
        (
            "slot_22222222222222222222222222222222",
            "security_and_concurrency",
        ),
    ),
    "Q3": (),
}

_QUALITY_RISK_RANK = {"Q0": 0, "Q1": 1, "Q2": 2, "Q3": 3}


def _rule_quality_policy_plan(value: dict[str, object]) -> None:
    input_projection = {
        field: value[field] for field in _QUALITY_POLICY_INPUT_FIELDS
    }
    _require(
        value["input_digest"] == canonical_document_sha256(input_projection),
        "QUALITY_POLICY_INPUT_DIGEST_INVALID",
        "$.input_digest",
    )
    expected_slots = _QUALITY_POLICY_SLOT_TABLE.get(value["quality_risk"])
    _require(
        expected_slots is not None
        and tuple(
            (item["slot_id"], item["concern"]) for item in value["slots"]
        )
        == expected_slots,
        "QUALITY_POLICY_SLOT_TABLE_INVALID",
        "$.slots",
    )
    _require(
        value["self_attestation_allowed"] is False,
        "QUALITY_POLICY_SELF_ATTESTATION_INVALID",
        "$.self_attestation_allowed",
    )
    for index, slot in enumerate(value["slots"]):
        requirement_ids = slot["requirement_ids"]
        _require(
            bool(requirement_ids) and _sorted_unique(requirement_ids),
            "QUALITY_POLICY_REQUIREMENT_ORDER_INVALID",
            f"$.slots[{index}].requirement_ids",
        )
    unsigned = {
        key: item for key, item in value.items() if key != "plan_digest"
    }
    digest_input = (
        b"pullwise:quality-policy-plan:v1\0"
        + canonical_document_bytes(unsigned)
    )
    _require(
        value["plan_digest"] == hashlib.sha256(digest_input).hexdigest(),
        "CONTRACT_DIGEST_MISMATCH",
        "$.plan_digest",
    )


def _quality_context_object(value: object, path: str) -> dict[str, object]:
    _require(isinstance(value, dict), "QUALITY_POLICY_CONTEXT_INVALID", path)
    return value


def _quality_context_field(
    value: dict[str, object], field: str, path: str
) -> object:
    _require(field in value, "QUALITY_POLICY_CONTEXT_INVALID", f"{path}.{field}")
    return value[field]


def verify_quality_policy_plan_context(
    plan: object,
    proposal: object,
    policy: object,
    task_request: object,
    requirement_ledger: object,
    change_set: object,
) -> dict[str, object]:
    checked = verify_document_digest("quality-policy-plan/v1", plan)
    proposal_value = _quality_context_object(proposal, "$.proposal")
    policy_value = _quality_context_object(policy, "$.policy")
    request_value = _quality_context_object(task_request, "$.task_request")
    ledger_value = _quality_context_object(
        requirement_ledger, "$.requirement_ledger"
    )
    change_value = _quality_context_object(change_set, "$.change_set")

    bindings = (
        ("task_id", proposal_value, "task_id", "$.proposal"),
        ("proposal_id", proposal_value, "proposal_id", "$.proposal"),
        (
            "proposal_digest",
            proposal_value,
            "proposal_digest",
            "$.proposal",
        ),
        ("policy_digest", proposal_value, "policy_digest", "$.proposal"),
        (
            "requirement_ledger_digest",
            proposal_value,
            "requirement_ledger_digest",
            "$.proposal",
        ),
        ("policy_digest", policy_value, "digest", "$.policy"),
        ("task_type", policy_value, "task_type", "$.policy"),
        ("task_id", request_value, "task_id", "$.task_request"),
        ("task_type", request_value, "task_type", "$.task_request"),
        ("task_id", ledger_value, "task_id", "$.requirement_ledger"),
        (
            "requirement_ledger_digest",
            ledger_value,
            "ledger_digest",
            "$.requirement_ledger",
        ),
        (
            "change_set_classification_digest",
            change_value,
            "change_set_classification_digest",
            "$.change_set",
        ),
        (
            "capability_usage_digest",
            change_value,
            "capability_usage_digest",
            "$.change_set",
        ),
    )
    for plan_field, context, context_field, path in bindings:
        _require(
            checked[plan_field]
            == _quality_context_field(context, context_field, path),
            "QUALITY_POLICY_CONTEXT_BINDING_INVALID",
            f"{path}.{context_field}",
        )

    floor = _quality_context_field(
        policy_value, "quality_risk_floor", "$.policy"
    )
    _require(
        isinstance(floor, str)
        and floor in _QUALITY_RISK_RANK
        and _QUALITY_RISK_RANK[checked["quality_risk"]]
        >= _QUALITY_RISK_RANK[floor],
        "QUALITY_POLICY_RISK_FLOOR_INVALID",
        "$.policy.quality_risk_floor",
    )

    active = _quality_context_field(
        ledger_value, "active_requirement_ids", "$.requirement_ledger"
    )
    entries = _quality_context_field(
        ledger_value, "entries", "$.requirement_ledger"
    )
    _require(
        isinstance(active, list)
        and bool(active)
        and all(isinstance(item, str) for item in active)
        and _sorted_unique(active),
        "QUALITY_POLICY_ACTIVE_REQUIREMENTS_INVALID",
        "$.requirement_ledger.active_requirement_ids",
    )
    _require(
        isinstance(entries, list),
        "QUALITY_POLICY_LEDGER_ENTRIES_INVALID",
        "$.requirement_ledger.entries",
    )
    entries_by_id: dict[str, bool] = {}
    for index, entry in enumerate(entries):
        path = f"$.requirement_ledger.entries[{index}]"
        _require(
            isinstance(entry, dict)
            and isinstance(entry.get("requirement_id"), str)
            and isinstance(entry.get("mandatory"), bool),
            "QUALITY_POLICY_LEDGER_ENTRIES_INVALID",
            path,
        )
        requirement_id = entry["requirement_id"]
        _require(
            requirement_id not in entries_by_id,
            "QUALITY_POLICY_LEDGER_ENTRIES_INVALID",
            f"{path}.requirement_id",
        )
        entries_by_id[requirement_id] = entry["mandatory"]
    active_set = set(active)
    _require(
        active_set.issubset(entries_by_id),
        "QUALITY_POLICY_ACTIVE_REQUIREMENTS_INVALID",
        "$.requirement_ledger.active_requirement_ids",
    )
    mandatory_active = {
        requirement_id
        for requirement_id in active
        if entries_by_id[requirement_id]
    }
    for index, slot in enumerate(checked["slots"]):
        covered = set(slot["requirement_ids"])
        _require(
            covered.issubset(active_set),
            "QUALITY_POLICY_SLOT_REQUIREMENT_INACTIVE",
            f"$.slots[{index}].requirement_ids",
        )
        _require(
            mandatory_active.issubset(covered),
            "QUALITY_POLICY_MANDATORY_COVERAGE_INVALID",
            f"$.slots[{index}].requirement_ids",
        )
    return checked


def _result_task_result_core_projection(value: dict[str, object]) -> dict[str, object]:
    projected = json.loads(canonical_document_bytes(value).decode("utf-8"))
    projected["schema_id"] = "task-result-core/v1"
    projected["diagnostics"].pop("worker_debug_fragment", None)
    return projected


def _result_availability_reasons() -> list[str]:
    enums = [
        branch["properties"]["reason_code"]["enum"]
        for branch in schema("availability-ref/v1")["oneOf"]
        if "reason_code" in branch.get("properties", {})
    ]
    _seo_require(
        len(enums) == 2 and enums[0] == enums[1],
        "AVAILABILITY_REASON_REGISTRY_BIJECTION_INVALID",
        "$",
    )
    return sorted(enums[0])


def _result_outcome_reasons() -> list[str]:
    reasons: set[str] = set()
    for branch in schema("task-result/v1")["oneOf"]:
        rule = schema(branch["$ref"])["properties"]["reason_code"]
        reasons.update([rule["const"]] if "const" in rule else rule["enum"])
    return sorted(reasons)


def _result_outcome_text_valid(value: object) -> bool:
    if not isinstance(value, str) or unicodedata.normalize("NFC", value) != value:
        return False
    try:
        size = len(value.encode("utf-8", errors="strict"))
    except UnicodeEncodeError:
        return False
    return 1 <= size <= 4096


def _result_outcome_order(valid: bool, path: str) -> None:
    _seo_require(valid, "TASK_RESULT_OUTCOME_DETAILS_ORDER_INVALID", path)


def _result_nondecreasing(values: list[object], key) -> bool:
    keys = [key(item) for item in values]
    return keys == sorted(keys)


def _result_ordered_unique(values: list[object], key) -> bool:
    keys = [key(item) for item in values]
    return all(left < right for left, right in zip(keys, keys[1:]))


def _result_sorted_unique(values: list[object]) -> bool:
    return _result_ordered_unique(values, lambda item: item)


def _result_canonical_unique(values: list[object]) -> bool:
    canonical = [canonical_document_bytes(item) for item in values]
    return len(canonical) == len(set(canonical))


def _result_nondecreasing_canonical_unique(values: list[object], key) -> bool:
    return _result_nondecreasing(values, key) and _result_canonical_unique(values)


def _result_validate_delivered_scope(items: list[dict[str, object]], path: str) -> None:
    for index, item in enumerate(items):
        _seo_require(_result_outcome_text_valid(item["statement"]), "TASK_RESULT_OUTCOME_TEXT_INVALID", f"{path}[{index}].statement")
        _result_outcome_order(_result_sorted_unique(item["requirement_ids"]), f"{path}[{index}].requirement_ids")
        _result_outcome_order(_result_ordered_unique(item["artifact_refs"], _artifact_ref_key), f"{path}[{index}].artifact_refs")
    _result_outcome_order(
        _result_nondecreasing_canonical_unique(items, lambda item: item["statement"].encode("utf-8", errors="strict")),
        path,
    )


def _result_validate_outcome_details(details: dict[str, object]) -> None:
    path = "$.outcome_details"
    if "delivered_scope" in details:
        _result_validate_delivered_scope(details["delivered_scope"], f"{path}.delivered_scope")
    for field in ("satisfaction_observation_ids", "waiver_ids"):
        if field in details:
            _result_outcome_order(_result_sorted_unique(details[field]), f"{path}.{field}")
    for field in ("original_verdicts", "gaps"):
        if field in details:
            _result_outcome_order(_result_ordered_unique(details[field], lambda item: item["requirement_id"]), f"{path}.{field}")
    if "residual_risks" in details:
        risks = details["residual_risks"]
        for index, item in enumerate(risks):
            _seo_require(_result_outcome_text_valid(item["statement"]), "TASK_RESULT_OUTCOME_TEXT_INVALID", f"{path}.residual_risks[{index}].statement")
            _result_outcome_order(_result_sorted_unique(item["evidence_ids"]), f"{path}.residual_risks[{index}].evidence_ids")
        _result_outcome_order(_result_ordered_unique(risks, lambda item: item["risk_id"]), f"{path}.residual_risks")
    if "blockers" in details:
        blockers = details["blockers"]
        for index, item in enumerate(blockers):
            _seo_require(_result_outcome_text_valid(item["unblock_condition"]), "TASK_RESULT_OUTCOME_TEXT_INVALID", f"{path}.blockers[{index}].unblock_condition")
            _result_outcome_order(_result_sorted_unique(item["requirement_ids"]), f"{path}.blockers[{index}].requirement_ids")
        _result_outcome_order(
            _result_nondecreasing_canonical_unique(
                blockers,
                lambda item: (item["code"], item["requirement_ids"][0] if item["requirement_ids"] else "", item["unblock_condition"]),
            ),
            f"{path}.blockers",
        )
    if "failures" in details:
        failures = details["failures"]
        for index, item in enumerate(failures):
            _result_outcome_order(_result_ordered_unique(item["evidence_refs"], _ref_key), f"{path}.failures[{index}].evidence_refs")
        _result_outcome_order(
            _result_nondecreasing_canonical_unique(
                failures,
                lambda item: (item["code"], item["evidence_refs"][0]["artifact_id"]),
            ),
            f"{path}.failures",
        )


def _result_instant(value: object) -> tuple[int, ...] | None:
    match = None if not isinstance(value, str) else re.fullmatch(
        r"([0-9]{4})-([0-9]{2})-([0-9]{2})T([0-9]{2}):([0-9]{2}):([0-9]{2})(?:\.([0-9]{1,9}))?Z",
        value,
    )
    if match is None:
        return None
    parts = [int(match.group(index)) for index in range(1, 7)]
    try:
        datetime(*parts)
    except ValueError:
        return None
    return (*parts, int(((match.group(7) or "") + "000000000")[:9]))


def _result_time_leq(left: object, right: object) -> bool:
    earlier, later = _result_instant(left), _result_instant(right)
    return earlier is not None and later is not None and earlier <= later


def _availability_ref_key(value: dict[str, object]) -> tuple[object, ...]:
    return (value["availability"], value.get("reason_code")) if value["availability"] != "available" else ("available",) + _ref_key(value["ref"])


def _rule_availability_ref(value: dict[str, object]) -> None:
    _seo_require(set(value) == ({"availability", "ref"} if value["availability"] == "available" else {"availability", "reason_code"}), "AVAILABILITY_REF_SHAPE_INVALID")


def _rule_availability_reason_registry(value: dict[str, object]) -> None:
    _seo_verify_embedded_digest("availability-reason-registry/v1", value)
    _seo_require(value["reasons"] == _result_availability_reasons(), "AVAILABILITY_REASON_REGISTRY_BIJECTION_INVALID", "$")


def _rule_task_result_outcome_reason_registry(value: dict[str, object]) -> None:
    _seo_verify_embedded_digest("task-result-outcome-reason-registry/v1", value)
    _seo_require(value["reasons"] == _result_outcome_reasons(), "TASK_RESULT_OUTCOME_REASON_REGISTRY_BIJECTION_INVALID", "$")


def _rule_task_result_complete(value: dict[str, object]) -> None:
    _seo_require(len(value["summary"].encode("utf-8")) <= 4096, "TASK_RESULT_SUMMARY_LIMIT_INVALID")
    _result_validate_outcome_details(value["outcome_details"])
    _seo_require(value["terminal_task_version"] == value["published_from_version"] + 1, "TASK_RESULT_VERSION_SUCCESSOR_INVALID")
    started = value["attempt_identity"]["kind"] == "started"
    _seo_require(started == (value["owner_identity"]["kind"] == "started"), "TASK_RESULT_IDENTITY_MATRIX_INVALID")
    if value["outcome"] in {
        "COMPLETED", "NO_CHANGE_NEEDED", "COMPLETED_WITH_WAIVERS", "PARTIAL",
        "CANCELLED_WITH_EFFECTS", "TERMINATED_WITH_UNKNOWN_EFFECTS",
    }:
        _seo_require(started, "TASK_RESULT_IDENTITY_MATRIX_INVALID")
    effects = value["effects"]
    if value["outcome"] == "CANCELLED_WITH_EFFECTS":
        effect_valid = effects["committed"] >= 1 and effects["unknown"] == 0
    elif value["outcome"] == "TERMINATED_WITH_UNKNOWN_EFFECTS":
        effect_valid = effects["unknown"] >= 1
    elif value["outcome"] == "PARTIAL":
        effect_valid = effects["committed"] >= 1 and effects["unknown"] == 0
    elif value["outcome"] in {"BLOCKED", "FAILED", "CANCELLED", "NO_CHANGE_NEEDED"}:
        effect_valid = effects["committed"] == 0 and effects["unknown"] == 0
    else:
        effect_valid = effects["unknown"] == 0
    _seo_require(effect_valid, "TASK_RESULT_EFFECT_MATRIX_INVALID", "$.effects")
    results = value["requirement_results"]
    _seo_require(_ordered_unique(results, lambda item: item["requirement_id"]), "TASK_RESULT_REQUIREMENT_ORDER_INVALID")
    for index, item in enumerate(results):
        for field in ("evidence_refs", "attestation_refs", "waiver_refs"):
            _seo_require(_ordered_unique(item[field], _ref_key), "TASK_RESULT_REFERENCE_ORDER_INVALID", f"$.requirement_results[{index}].{field}")
    _seo_require(_ordered_unique(value["execution_states"], _availability_ref_key), "TASK_RESULT_EXECUTION_ORDER_INVALID")
    _seo_require(_ordered_unique(value["artifact_refs"], _artifact_ref_key), "TASK_RESULT_ARTIFACT_ORDER_INVALID")
    _seo_require(_sorted_unique(value["provenance"]["attempt_ids"]), "TASK_RESULT_ATTEMPT_ORDER_INVALID")
    verify_content_ref_set([item for result in results for field in ("evidence_refs", "attestation_refs", "waiver_refs") for item in result[field]])
    _seo_require(value["evidence_closure_digest"] == value["evidence_closure_ref"]["sha256"], "TASK_RESULT_EVIDENCE_CLOSURE_DIGEST_INVALID")
    if value["outcome"] == "NO_CHANGE_NEEDED":
        _seo_require(value["change_set_ref"] is None, "TASK_RESULT_NO_CHANGE_SET_INVALID")
        _seo_require(value["original_source_state"]["availability"] == "available" and value["final_source_state"]["availability"] == "available" and _json_equal(value["original_source_state"]["ref"], value["final_source_state"]["ref"]), "TASK_RESULT_NO_CHANGE_STATE_INVALID")
    _seo_require(_result_time_leq(value["created_at"], value["terminal_at"]), "TASK_RESULT_TIME_ORDER_INVALID", "$.terminal_at")


def _rule_task_result_core(value: dict[str, object]) -> None:
    _rule_task_result_complete(value)
    _seo_require(value["diagnostics"] == {}, "TASK_RESULT_CORE_DEBUG_FIELD_INVALID")


def _rule_worker_debug_file_manifest(value: dict[str, object]) -> None:
    _seo_verify_embedded_digest("worker-debug-file-manifest/v1", value)
    entries = value["entries"]
    _seo_require(_ordered_unique(entries, lambda item: item["path"]), "DEBUG_FILE_MANIFEST_ORDER_INVALID")
    _seo_require(value["entry_count"] == len(entries), "DEBUG_FILE_MANIFEST_COUNT_INVALID")
    _seo_require(value["total_size_bytes"] == sum(item["size_bytes"] for item in entries), "DEBUG_FILE_MANIFEST_SIZE_INVALID")
    for index, item in enumerate(entries):
        expected = "application/x-ndjson" if item["path"] in {"agent-events.jsonl", "codex-events.jsonl", "gateway-events.jsonl", "progress.log.jsonl", "task-events.jsonl", "worker.log.jsonl"} else "application/json"
        _seo_require(item["media_type"] == expected, "DEBUG_FILE_MEDIA_TYPE_INVALID", f"$.entries[{index}].media_type")


def _rule_worker_debug_redaction_report(value: dict[str, object]) -> None:
    _seo_verify_embedded_digest("worker-debug-redaction-report/v1", value)
    structured, rescanned, redacted = value["structured_pass_detection_count"], value["archive_rescan_detection_count"], value["redacted_value_count"]
    _seo_require(rescanned == 0, "DEBUG_REDACTION_RESCAN_FAILED")
    _seo_require(structured == redacted, "DEBUG_REDACTION_COUNT_INVALID")
    _seo_require((value["status"] == "clean" and structured == 0) or (value["status"] == "redacted" and structured >= 1), "DEBUG_REDACTION_STATUS_INVALID")


def _rule_worker_debug_descriptor(value: dict[str, object]) -> None:
    uploaded = value["state"] == "uploaded"
    _seo_require(uploaded == (value["transport_kind"] == "server_transport"), "DEBUG_DESCRIPTOR_BINDING_INVALID")
    _seo_require((value["server_fragment_ref"] is not None) == uploaded, "DEBUG_DESCRIPTOR_BINDING_INVALID")
    _seo_require((value["server_receipt_ref"] is not None) == uploaded, "DEBUG_DESCRIPTOR_BINDING_INVALID")
    _seo_require((value["reason_code"] is None) == uploaded, "DEBUG_DESCRIPTOR_BINDING_INVALID")
    if uploaded:
        _seo_require(value["server_fragment_ref"]["sha256"] == value["fragment_ref"]["sha256"] and value["server_fragment_ref"]["size_bytes"] == value["fragment_ref"]["size_bytes"], "DEBUG_DESCRIPTOR_FRAGMENT_MISMATCH")
    _seo_require(value["source_sha256"] == value["fragment_ref"]["sha256"], "DEBUG_DESCRIPTOR_SOURCE_DIGEST_INVALID")


def _rule_worker_debug_fragment(value: dict[str, object]) -> None:
    _seo_require(value["last_server_acked_event_seq"] <= value["local_event_seq"], "DEBUG_EVENT_SEQUENCE_INVALID")
    terminal = value["capture_kind"] == "terminal"
    if terminal:
        _seo_require(value["task_result_core"]["availability"] == "available", "DEBUG_TERMINAL_CORE_REQUIRED")
    else:
        _seo_require(value["task_result_core"] == {"availability": "not_applicable", "reason_code": "TASK_RESULT_CORE_NOT_APPLICABLE"}, "DEBUG_NONTERMINAL_CORE_INVALID")
    _seo_require((value["status"] == "complete" and value["reason_code"] is None) or (value["status"] == "partial" and value["reason_code"] in {"DEBUG_LIMIT_EXCEEDED", "DEBUG_UNAVAILABLE"}), "DEBUG_FRAGMENT_REASON_INVALID")


def _rule_task_result_transport_ack(value: dict[str, object]) -> None:
    _seo_verify_embedded_digest("task-result-transport-ack/v1", value)
    _seo_require(value["terminal_task_version"] == value["published_from_version"] + 1, "TRANSPORT_ACK_VERSION_INVALID")
    _seo_require((value["receipt_binding_state"] == "bound") == (value["receipt_digest"] is not None), "TRANSPORT_ACK_RECEIPT_MATRIX_INVALID")


def _rule_task_result_transport_envelope(value: dict[str, object]) -> None:
    result = validate_document("task-result/v1", value["task_result"])
    result_bytes = canonical_document_bytes(result)
    _seo_require(hashlib.sha256(result_bytes).hexdigest() == value["task_result_digest"], "TRANSPORT_ENVELOPE_DIGEST_INVALID", code="TRANSPORT_ENVELOPE_DIGEST_INVALID")
    core = validate_document(
        "task-result-core/v1", _result_task_result_core_projection(result)
    )
    core_bytes = canonical_document_bytes(core)
    _seo_require(value["task_result_core_digest"] == hashlib.sha256(core_bytes).hexdigest(), "TRANSPORT_CORE_DIGEST_INVALID")
    _seo_require(value["task_result_core_ref"]["sha256"] == value["task_result_core_digest"] and value["task_result_core_ref"]["size_bytes"] == len(core_bytes), "TRANSPORT_CORE_REF_INVALID")
    authority, fence = value["authority"], value["full_fence"]
    exact = ("task_id", "attempt_id", "session_id", "owner_id", "lease_id", "task_version", "deletion_version", "owner_epoch", "native_epoch", "transport_epoch")
    for key in exact:
        _seo_require(authority[key] == fence[key], "TRANSPORT_AUTHORITY_FENCE_INVALID", f"$.full_fence.{key}")
    _seo_require(authority["task_version"] == result["published_from_version"], "TRANSPORT_RESULT_VERSION_INVALID", "$.task_result.published_from_version")
    _seo_require(authority["task_id"] == result["task_id"], "TRANSPORT_RESULT_TASK_INVALID")
    _seo_require(_json_equal(value["package"], authority["package"]), "TRANSPORT_PACKAGE_INVALID")
    debug = result["diagnostics"]["worker_debug_fragment"]
    descriptor, receipt = value["worker_debug_descriptor"], value["transport_receipt"]
    not_applicable = {"availability": "not_applicable", "reason_code": "TRANSPORT_RECEIPT_NOT_APPLICABLE"}
    if debug["availability"] == "available":
        _seo_require(descriptor is not None, "TRANSPORT_DEBUG_DESCRIPTOR_REQUIRED")
        descriptor = validate_document(
            "worker-debug-fragment-descriptor/v1", descriptor
        )
        receipt_valid = receipt.get("availability") == "available" if descriptor["state"] == "uploaded" else receipt == not_applicable
        _seo_require(receipt_valid, "TRANSPORT_RECEIPT_MATRIX_INVALID", "$.transport_receipt")
    else:
        _seo_require(descriptor is None, "TRANSPORT_DEBUG_DESCRIPTOR_INVALID")
        _seo_require(receipt == not_applicable, "TRANSPORT_RECEIPT_MATRIX_INVALID", "$.transport_receipt")


def _result_checked_receipt(transport_receipt: object) -> dict[str, object]:
    _seo_require(isinstance(transport_receipt, dict), "TRANSPORT_RECEIPT_TYPE_INVALID", code="TRANSPORT_RECEIPT_TYPE_INVALID")
    _seo_require(transport_receipt.get("schema_id") == "server-transport-receipt/v1", "TRANSPORT_RECEIPT_TYPE_INVALID", "$.schema_id", "TRANSPORT_RECEIPT_TYPE_INVALID")
    _seo_require(transport_receipt.get("receipt_kind") == "server_transport", "TRANSPORT_RECEIPT_TYPE_INVALID", "$.receipt_kind", "TRANSPORT_RECEIPT_TYPE_INVALID")
    return verify_document_digest("server-transport-receipt/v1", transport_receipt)


def _result_require_ref(ref: dict[str, object], schema_id: str, document: dict[str, object], path: str, detail: str = "CAS_CORRUPT", code: str | None = None) -> None:
    _seo_require(_seo_ref_matches_document(ref, schema_id, document), detail, path, code)


def _result_ref_tuple(value: dict[str, object]) -> tuple[object, ...]:
    return tuple(value.get(key) for key in ("content_schema_id", "sha256", "size_bytes", "media_type", "encoding"))


def _result_fragment_identity(value: dict[str, object], manifest_digest: str) -> str:
    identity = {
        "task_id": value["task_id"], "job_id": value["job_id"], "run_id": value["run_id"], "lease_id": value["lease_id"],
        "transport_attempt_id": value["transport_attempt_id"], "transport_epoch": value["transport_epoch"],
        "native_attempt_id": value["native_attempt_id"], "native_epoch": value["native_epoch"],
        "capture_kind": value["capture_kind"], "snapshot_seq": value["snapshot_seq"], "file_manifest_digest": manifest_digest,
    }
    return "frag_" + hashlib.sha256(b"pullwise:worker-debug-fragment-id/v1\0" + canonical_document_bytes(identity)).hexdigest()


def derive_task_result_core(task_result: object) -> dict[str, object]:
    checked = validate_document("task-result/v1", task_result)
    return validate_document(
        "task-result-core/v1", _result_task_result_core_projection(checked)
    )


def verify_task_result_context(
    task_result: object,
    *,
    terminal_gate_decision: object = None,
    effect_ledger_snapshot: object = None,
    worker_debug_descriptor: object = None,
) -> dict[str, object]:
    checked = validate_document("task-result/v1", task_result)
    _seo_require(isinstance(terminal_gate_decision, dict), "TASK_RESULT_CONTEXT_INVALID", "$.gate_decision.ref")
    decision = verify_document_digest("gate-decision/v1", terminal_gate_decision)
    _result_require_ref(checked["gate_decision"]["ref"], "gate-decision/v1", decision, "$.gate_decision.ref")
    _seo_require(decision["decision_kind"] == "terminalization" and decision["selected_lifecycle"] == "TERMINAL" and decision["passed"], "TASK_RESULT_CONTEXT_INVALID", "$.gate_decision")
    _seo_require(decision["task_id"] == checked["task_id"], "TASK_RESULT_CONTEXT_INVALID", "$.task_id")
    _seo_require(decision["task_version"] == checked["published_from_version"], "TASK_RESULT_CONTEXT_INVALID", "$.published_from_version")
    _seo_require(decision["selected_outcome"] == checked["outcome"], "TASK_RESULT_CONTEXT_INVALID", "$.outcome")
    _seo_require(decision["selected_reason"] == checked["reason_code"], "TASK_RESULT_CONTEXT_INVALID", "$.reason_code")
    _seo_require(decision["selector_input_digest"] == checked["selector_input_digest"], "TASK_RESULT_CONTEXT_INVALID", "$.selector_input_digest")
    _seo_require(isinstance(effect_ledger_snapshot, dict), "TASK_RESULT_CONTEXT_INVALID", "$.effects")
    ledger = verify_document_digest("effect-ledger-snapshot/v1", effect_ledger_snapshot)
    effect_availability = decision["effect_availability"]
    _seo_require(effect_availability["availability"] == "available", "TASK_RESULT_CONTEXT_INVALID", "$.gate_decision.effect_availability")
    _result_require_ref(effect_availability["ref"], "effect-ledger-snapshot/v1", ledger, "$.gate_decision.effect_availability.ref")
    _seo_require(ledger["task_id"] == checked["task_id"], "TASK_RESULT_EFFECT_LEDGER_TASK_INVALID", "$.effects")
    counts = ledger["state_counts"]
    _seo_require(counts["prepared"] == counts["dispatched"] == 0, "TASK_RESULT_ACTIVE_EFFECTS", "$.effects")
    _seo_require(_json_equal(counts, checked["effects"]), "TASK_RESULT_EFFECT_COUNTS_INVALID", "$.effects")
    effect_state = (
        "unknown_post_deadline"
        if counts["unknown"]
        else "committed"
        if counts["committed"]
        else "none"
    )
    _seo_require(decision["effect_state"] == effect_state, "TASK_RESULT_EFFECT_STATE_INVALID", "$.gate_decision.effect_state")
    debug = checked["diagnostics"]["worker_debug_fragment"]
    if debug["availability"] == "available":
        _seo_require(isinstance(worker_debug_descriptor, dict), "TASK_RESULT_CONTEXT_INVALID", "$.diagnostics.worker_debug_fragment.ref")
        descriptor = validate_document("worker-debug-fragment-descriptor/v1", worker_debug_descriptor)
        _seo_require(_seo_ref_matches_document(debug["ref"], "worker-debug-fragment-descriptor/v1", descriptor), "TASK_RESULT_CONTEXT_INVALID", "$.diagnostics.worker_debug_fragment.ref")
    else:
        _seo_require(worker_debug_descriptor is None, "TASK_RESULT_CONTEXT_INVALID", "$.diagnostics.worker_debug_fragment")
    return checked


def verify_task_result_core(task_result: object, core: object) -> dict[str, object]:
    checked = validate_document("task-result-core/v1", core)
    _seo_require(_json_equal(checked, derive_task_result_core(task_result)), "TASK_RESULT_CORE_PROJECTION_INVALID")
    return checked


def verify_worker_debug_fragment_content(fragment: object, task_result_core: object, file_manifest: object, redaction_report: object) -> dict[str, object]:
    checked = validate_document("worker-debug-fragment/v1", fragment)
    manifest = verify_document_digest("worker-debug-file-manifest/v1", file_manifest)
    report = verify_document_digest("worker-debug-redaction-report/v1", redaction_report)
    _result_require_ref(checked["file_manifest_ref"], "worker-debug-file-manifest/v1", manifest, "$.file_manifest_ref")
    _result_require_ref(checked["redaction_report_ref"], "worker-debug-redaction-report/v1", report, "$.redaction_report_ref")
    _seo_require(checked["fragment_id"] == _result_fragment_identity(checked, manifest["manifest_digest"]), "DEBUG_FRAGMENT_ID_INVALID", "$.fragment_id")
    if checked["task_result_core"]["availability"] == "available":
        _seo_require(task_result_core is not None, "DEBUG_TERMINAL_CORE_REQUIRED", "$.task_result_core")
        core = validate_document("task-result-core/v1", task_result_core)
        _result_require_ref(checked["task_result_core"]["ref"], "task-result-core/v1", core, "$.task_result_core.ref")
        attempt = core["attempt_identity"]
        _seo_require(checked["task_id"] == core["task_id"] and attempt["kind"] == "started", "DEBUG_TERMINAL_CORE_INVALID", "$.task_result_core")
        _seo_require(checked["native_attempt_id"] == attempt["attempt_id"], "DEBUG_TERMINAL_CORE_INVALID", "$.native_attempt_id")
        _seo_require(checked["native_epoch"] == attempt["native_epoch"], "DEBUG_TERMINAL_CORE_INVALID", "$.native_epoch")
        _seo_require(checked["task_version"] == core["published_from_version"], "DEBUG_TERMINAL_CORE_INVALID", "$.task_version")
        _seo_require(checked["checkpoint_generation"] == core["provenance"]["checkpoint_generation"], "DEBUG_TERMINAL_CORE_INVALID", "$.checkpoint_generation")
        _seo_require(core["final_source_state"]["availability"] == "available" and checked["source_state_id"] == core["final_source_state"]["ref"]["sha256"], "DEBUG_TERMINAL_CORE_INVALID", "$.source_state_id")
        _seo_require(_result_time_leq(core["created_at"], checked["captured_at"]) and _result_time_leq(checked["captured_at"], core["terminal_at"]), "DEBUG_TERMINAL_CORE_INVALID", "$.captured_at")
    else:
        _seo_require(task_result_core is None, "DEBUG_NONTERMINAL_CORE_INVALID", "$.task_result_core")
    return checked


def verify_worker_debug_descriptor_content(descriptor: object, fragment: object, *, transport_receipt: object = None) -> dict[str, object]:
    checked = validate_document("worker-debug-fragment-descriptor/v1", descriptor)
    fragment_value = validate_document("worker-debug-fragment/v1", fragment)
    fragment_bytes = canonical_document_bytes(fragment_value)
    _result_require_ref(checked["fragment_ref"], "worker-debug-fragment/v1", fragment_value, "$.fragment_ref")
    _seo_require(checked["snapshot_seq"] == fragment_value["snapshot_seq"], "DEBUG_DESCRIPTOR_BINDING_INVALID", "$.snapshot_seq")
    _seo_require(checked["source_sha256"] == hashlib.sha256(fragment_bytes).hexdigest(), "DEBUG_DESCRIPTOR_SOURCE_DIGEST_INVALID", "$.source_sha256")
    if checked["server_fragment_ref"] is not None:
        _result_require_ref(checked["server_fragment_ref"], "worker-debug-fragment/v1", fragment_value, "$.server_fragment_ref")
    if checked["state"] == "uploaded":
        _seo_require(transport_receipt is not None, "TRANSPORT_RECEIPT_BINDING_CONFLICT", "$.server_receipt_ref", "TRANSPORT_RECEIPT_BINDING_CONFLICT")
        receipt = _result_checked_receipt(transport_receipt)
        _result_require_ref(checked["server_receipt_ref"], "server-transport-receipt/v1", receipt, "$.server_receipt_ref", "TRANSPORT_RECEIPT_BINDING_CONFLICT", "TRANSPORT_RECEIPT_BINDING_CONFLICT")
        _result_require_ref(receipt["content_ref"], "worker-debug-fragment/v1", fragment_value, "$.content_ref", "TRANSPORT_RECEIPT_BINDING_CONFLICT", "TRANSPORT_RECEIPT_BINDING_CONFLICT")
        _seo_require(_result_ref_tuple(receipt["content_ref"]) == _result_ref_tuple(checked["server_fragment_ref"]), "TRANSPORT_RECEIPT_BINDING_CONFLICT", "$.content_ref", "TRANSPORT_RECEIPT_BINDING_CONFLICT")
        _seo_require(_result_time_leq(fragment_value["captured_at"], receipt["accepted_at"]), "TRANSPORT_RECEIPT_BINDING_CONFLICT", "$.server_receipt_ref", "TRANSPORT_RECEIPT_BINDING_CONFLICT")
    else:
        _seo_require(transport_receipt is None, "TRANSPORT_RECEIPT_BINDING_CONFLICT", "$.server_receipt_ref", "TRANSPORT_RECEIPT_BINDING_CONFLICT")
    return checked


def verify_task_result_transport_envelope(envelope: object, core: object, *, transport_receipt: object = None, worker_debug_descriptor: object = None) -> dict[str, object]:
    checked = validate_document("task-result-transport-envelope/v1", envelope)
    core_value = verify_task_result_core(checked["task_result"], core)
    core_bytes = canonical_document_bytes(core_value)
    _result_require_ref(checked["task_result_core_ref"], "task-result-core/v1", core_value, "$.task_result_core_ref")
    _seo_require(checked["task_result_core_digest"] == hashlib.sha256(core_bytes).hexdigest(), "TRANSPORT_CORE_DIGEST_INVALID", "$.task_result_core_digest")
    authority, fence, result = checked["authority"], checked["full_fence"], checked["task_result"]
    for key in ("task_id", "attempt_id", "session_id", "owner_id", "lease_id", "deletion_version", "owner_epoch", "native_epoch", "transport_epoch"):
        _seo_require(authority[key] == fence[key], "TRANSPORT_AUTHORITY_FENCE_INVALID", f"$.full_fence.{key}")
    _seo_require(authority["task_version"] == fence["task_version"], "TRANSPORT_AUTHORITY_FENCE_INVALID", "$.full_fence.task_version")
    _seo_require(authority["task_version"] == result["published_from_version"], "TRANSPORT_RESULT_VERSION_INVALID", "$.task_result.published_from_version")
    debug = result["diagnostics"]["worker_debug_fragment"]
    descriptor = checked["worker_debug_descriptor"]
    if debug["availability"] == "available":
        _seo_require(descriptor is not None, "TRANSPORT_DEBUG_DESCRIPTOR_REQUIRED", "$.worker_debug_descriptor")
        _seo_require(isinstance(worker_debug_descriptor, dict), "TRANSPORT_DEBUG_DESCRIPTOR_REQUIRED", "$.worker_debug_descriptor")
        descriptor = validate_document("worker-debug-fragment-descriptor/v1", worker_debug_descriptor)
        _seo_require(_json_equal(descriptor, checked["worker_debug_descriptor"]), "TRANSPORT_DEBUG_DESCRIPTOR_CONFLICT", "$.worker_debug_descriptor")
        _result_require_ref(debug["ref"], "worker-debug-fragment-descriptor/v1", descriptor, "$.task_result.diagnostics.worker_debug_fragment.ref", "TASK_RESULT_CONTEXT_INVALID")
    else:
        _seo_require(descriptor is None and worker_debug_descriptor is None, "TRANSPORT_DEBUG_DESCRIPTOR_INVALID", "$.worker_debug_descriptor")
    if checked["transport_receipt"]["availability"] == "available":
        _seo_require(transport_receipt is not None, "TRANSPORT_RECEIPT_BINDING_CONFLICT", "$.transport_receipt", "TRANSPORT_RECEIPT_BINDING_CONFLICT")
        receipt = _result_checked_receipt(transport_receipt)
        _result_require_ref(checked["transport_receipt"]["ref"], "server-transport-receipt/v1", receipt, "$.transport_receipt.ref", "TRANSPORT_RECEIPT_BINDING_CONFLICT", "TRANSPORT_RECEIPT_BINDING_CONFLICT")
        _seo_require(descriptor is not None, "TRANSPORT_RECEIPT_BINDING_CONFLICT", "$.worker_debug_descriptor", "TRANSPORT_RECEIPT_BINDING_CONFLICT")
        _result_require_ref(descriptor["server_receipt_ref"], "server-transport-receipt/v1", receipt, "$.worker_debug_descriptor.server_receipt_ref", "TRANSPORT_RECEIPT_BINDING_CONFLICT", "TRANSPORT_RECEIPT_BINDING_CONFLICT")
        _seo_require(receipt["package"] == checked["package"], "TRANSPORT_RECEIPT_BINDING_CONFLICT", "$.transport_receipt", "TRANSPORT_RECEIPT_BINDING_CONFLICT")
        _seo_require(all(receipt[key] == authority[key] for key in ("task_id", "attempt_id", "session_id", "owner_id", "lease_id", "task_version", "deletion_version", "owner_epoch", "native_epoch", "transport_epoch")), "TRANSPORT_RECEIPT_BINDING_CONFLICT", "$.transport_receipt", "TRANSPORT_RECEIPT_BINDING_CONFLICT")
        _seo_require(receipt["authority_digest"] == authority["authority_digest"] and receipt["grant_digest"] == authority["grant"]["grant_digest"], "TRANSPORT_RECEIPT_BINDING_CONFLICT", "$.transport_receipt", "TRANSPORT_RECEIPT_BINDING_CONFLICT")
        _seo_require(_result_ref_tuple(receipt["content_ref"]) == _result_ref_tuple(descriptor["fragment_ref"]), "TRANSPORT_RECEIPT_BINDING_CONFLICT", "$.transport_receipt.content_ref", "TRANSPORT_RECEIPT_BINDING_CONFLICT")
    else:
        _seo_require(transport_receipt is None, "TRANSPORT_RECEIPT_BINDING_CONFLICT", "$.transport_receipt", "TRANSPORT_RECEIPT_BINDING_CONFLICT")
        _seo_require(checked["transport_receipt"] == {"availability": "not_applicable", "reason_code": "TRANSPORT_RECEIPT_NOT_APPLICABLE"}, "TRANSPORT_RECEIPT_MATRIX_INVALID", "$.transport_receipt")
    raw = canonical_document_bytes(checked)
    return {"document": checked, "canonical_bytes": raw, "transport_envelope_digest": hashlib.sha256(raw).hexdigest()}


def verify_task_result_transport_ack(ack: object, envelope: object, *, transport_receipt: object = None) -> dict[str, object]:
    checked = verify_document_digest("task-result-transport-ack/v1", ack)
    document = validate_document("task-result-transport-envelope/v1", envelope)
    result, raw = document["task_result"], canonical_document_bytes(document)
    _seo_require(_json_equal(checked["package"], document["package"]), "TRANSPORT_ACK_PACKAGE_INVALID", "$.package")
    for field in ("result_id", "task_id", "outcome", "published_from_version", "terminal_task_version"):
        _seo_require(checked[field] == result[field], "TRANSPORT_ACK_CONTEXT_INVALID", f"$.{field}")
    _seo_require(checked["transport_envelope_digest"] == hashlib.sha256(raw).hexdigest(), "TRANSPORT_ACK_DIGEST_INVALID", "$.transport_envelope_digest")
    if document["transport_receipt"]["availability"] == "available":
        _seo_require(transport_receipt is not None, "TRANSPORT_RECEIPT_BINDING_CONFLICT", "$.transport_receipt", "TRANSPORT_RECEIPT_BINDING_CONFLICT")
        receipt = _result_checked_receipt(transport_receipt)
        _result_require_ref(document["transport_receipt"]["ref"], "server-transport-receipt/v1", receipt, "$.transport_receipt.ref", "TRANSPORT_RECEIPT_BINDING_CONFLICT", "TRANSPORT_RECEIPT_BINDING_CONFLICT")
        _seo_require(checked["receipt_binding_state"] == "bound" and checked["receipt_digest"] == receipt["receipt_digest"], "TRANSPORT_ACK_RECEIPT_MATRIX_INVALID", "$.receipt_binding_state")
        _seo_require(_result_time_leq(receipt["accepted_at"], checked["accepted_at"]), "TASK_RESULT_TIME_ORDER_INVALID", "$.accepted_at")
    else:
        _seo_require(transport_receipt is None, "TRANSPORT_RECEIPT_BINDING_CONFLICT", "$.transport_receipt", "TRANSPORT_RECEIPT_BINDING_CONFLICT")
        _seo_require(checked["receipt_binding_state"] == "not_applicable" and checked["receipt_digest"] is None, "TRANSPORT_ACK_RECEIPT_MATRIX_INVALID", "$.receipt_binding_state")
    _seo_require(_result_time_leq(result["terminal_at"], checked["accepted_at"]), "TASK_RESULT_TIME_ORDER_INVALID", "$.accepted_at")
    return checked


_PRE_GATE_ROOT_FIELDS = (
    "request",
    "policy",
    "charter",
    "ledger",
    "waiver_events",
    "proposal",
    "original_source",
    "final_source",
    "execution_states",
    "change_set",
    "pre_observation_manifest",
    "final_observation_manifest",
    "verifier_inputs",
    "verifier_work",
    "attestations",
    "artifacts",
    "report",
    "effect_ledger",
    "budget_summary",
    "termination_facts",
    "publication_content_manifest",
    "debug_redaction_plan",
)
_PRE_GATE_ROOT_KEYS = {
    "schema_id",
    "task_id",
    "root_set_digest",
    *_PRE_GATE_ROOT_FIELDS,
}
_PRE_GATE_ALWAYS_AVAILABLE = (
    "request",
    "policy",
    "ledger",
    "effect_ledger",
    "budget_summary",
    "publication_content_manifest",
    "debug_redaction_plan",
)
_PRE_GATE_SUCCESS_OUTCOMES = {
    "COMPLETED",
    "COMPLETED_WITH_WAIVERS",
    "NO_CHANGE_NEEDED",
}
_PRE_GATE_SUCCESS_AVAILABLE = (
    "charter",
    "proposal",
    "original_source",
    "final_source",
    "pre_observation_manifest",
    "final_observation_manifest",
    "attestations",
    "report",
)
_PRE_GATE_FORBIDDEN_CLOSURE_TARGETS = {
    "error-response/v1",
    "evidence-closure-manifest/v1",
    "gate-decision/v1",
    "gate-input-snapshot/v1",
    "server-debug-assembly/v1",
    "server-debug-snapshot/v1",
    "task-result-core/v1",
    "task-result/v1",
    "terminalization-input-snapshot/v1",
    "worker-debug-fragment/v1",
}


def _availability(value: dict[str, object]) -> str:
    return value["availability"]


def _rule_pre_gate_root_set(value: dict[str, object]) -> None:
    _require(
        set(value) == _PRE_GATE_ROOT_KEYS,
        "PRE_GATE_ROOT_FIELDS_INVALID",
    )
    for field in _PRE_GATE_ALWAYS_AVAILABLE:
        _require(
            _availability(value[field]) == "available",
            "PRE_GATE_REQUIRED_ROOT_UNAVAILABLE",
            f"$.{field}",
        )

def _rule_pre_gate_evidence_closure_manifest(
    value: dict[str, object],
) -> None:
    entries = value["entries"]
    _require(
        value["entry_count"] == len(entries),
        "PRE_GATE_CLOSURE_ENTRY_COUNT_INVALID",
        "$.entry_count",
    )
    _require(
        _ordered_unique(entries, _ref_key),
        "PRE_GATE_CLOSURE_ENTRY_ORDER_INVALID",
        "$.entries",
    )
    verify_content_ref_set(entries)
    _require(
        value["pre_gate_root_set_ref"] in entries,
        "PRE_GATE_CLOSURE_ROOT_MISSING",
        "$.entries",
    )
    _require(
        not _PRE_GATE_FORBIDDEN_CLOSURE_TARGETS.intersection(
            item["content_schema_id"] for item in entries
        ),
        "PRE_GATE_CLOSURE_DIRECTION_INVALID",
        "$.entries",
    )
    expected_digest = hashlib.sha256(
        canonical_document_bytes(entries)
    ).hexdigest()
    _require(
        value["pre_gate_closure_digest"] == expected_digest,
        "PRE_GATE_CLOSURE_DIGEST_INVALID",
        "$.pre_gate_closure_digest",
    )


def _content_ref_matches_direct_document(
    ref: dict[str, object],
    schema_id: str,
    document: dict[str, object],
) -> bool:
    raw = canonical_document_bytes(document)
    return (
        ref["content_schema_id"] == schema_id
        and ref["sha256"] == hashlib.sha256(raw).hexdigest()
        and ref["size_bytes"] == len(raw)
        and ref["media_type"] == "application/json"
        and ref["encoding"] == "utf-8"
    )


def _pre_gate_available_root_refs(
    root_set: dict[str, object],
) -> list[dict[str, object]]:
    refs: list[dict[str, object]] = []
    for field in _PRE_GATE_ROOT_FIELDS:
        value = root_set[field]
        values = value if isinstance(value, list) else [value]
        refs.extend(
            item["ref"]
            for item in values
            if item["availability"] == "available"
        )
    return refs


def verify_pre_gate_root_set_context(
    root_set: object,
    task_id: str,
) -> dict[str, object]:
    """Verify an outcome-neutral root set against direct task context."""
    validated = verify_document_digest("pre-gate-root-set/v1", root_set)
    _require(
        isinstance(task_id, str) and validated["task_id"] == task_id,
        "PRE_GATE_TASK_BINDING_INVALID",
        "$.task_id",
    )
    return validated


def verify_pre_gate_evidence_closure_context(
    manifest: object,
    root_set: object,
) -> dict[str, object]:
    """Bind a PreGate closure to the direct root-set document."""
    validated = verify_document_digest(
        "pre-gate-evidence-closure-manifest/v1", manifest
    )
    roots = verify_document_digest("pre-gate-root-set/v1", root_set)
    _require(
        validated["task_id"] == roots["task_id"],
        "EVIDENCE_CLOSURE_INVALID",
        "$.task_id",
    )
    _require(
        _content_ref_matches_direct_document(
            validated["pre_gate_root_set_ref"],
            "pre-gate-root-set/v1",
            roots,
        ),
        "CAS_CORRUPT",
        "$.pre_gate_root_set_ref",
    )
    entry_bytes = {
        canonical_document_bytes(item) for item in validated["entries"]
    }
    _require(
        all(
            canonical_document_bytes(item) in entry_bytes
            for item in _pre_gate_available_root_refs(roots)
        ),
        "EVIDENCE_CLOSURE_INVALID",
        "$.entries",
    )
    return validated


_TASK_EVIDENCE_IDENTITY_FIELDS = (
    "content_schema_id",
    "sha256",
    "size_bytes",
    "media_type",
    "encoding",
)


def _task_evidence_content_identity(
    ref: dict[str, object],
) -> tuple[object, ...]:
    return tuple(ref[field] for field in _TASK_EVIDENCE_IDENTITY_FIELDS)


def _task_evidence_has_content_alias(
    refs: list[dict[str, object]],
) -> bool:
    artifacts_by_content: dict[tuple[object, ...], str] = {}
    for ref in refs:
        identity = _task_evidence_content_identity(ref)
        artifact_id = ref["artifact_id"]
        previous = artifacts_by_content.setdefault(identity, artifact_id)
        if previous != artifact_id:
            return True
    return False


def _task_evidence_exact_edge(
    entries: list[dict[str, object]],
    schema_ids: set[str],
    expected: dict[str, object],
) -> bool:
    matches = [
        ref for ref in entries if ref["content_schema_id"] in schema_ids
    ]
    return (
        len(matches) == 1
        and canonical_document_bytes(matches[0])
        == canonical_document_bytes(expected)
    )


def _rule_evidence_closure_manifest(value: dict[str, object]) -> None:
    entries = value["entries"]
    _require(
        value["entry_count"] == len(entries),
        "EVIDENCE_CLOSURE_COUNT_INVALID",
        "$.entry_count",
    )
    _require(
        _ordered_unique(entries, _ref_key),
        "EVIDENCE_CLOSURE_ORDER_INVALID",
        "$.entries",
    )
    verify_content_ref_set(entries)
    _require(
        not _task_evidence_has_content_alias(entries),
        "EVIDENCE_CLOSURE_CONTENT_ALIAS",
        "$.entries",
    )
    edges = (
        (
            {"pre-gate-evidence-closure-manifest/v1"},
            value["pre_gate_evidence_closure_ref"],
        ),
        (
            {
                "gate-input-snapshot/v1",
                "terminalization-input-snapshot/v1",
            },
            value["input_snapshot_ref"],
        ),
        ({"gate-decision/v1"}, value["gate_decision_ref"]),
    )
    _require(
        all(
            _task_evidence_exact_edge(entries, schema_ids, expected)
            for schema_ids, expected in edges
        ),
        "EVIDENCE_CLOSURE_REQUIRED_EDGE_INVALID",
        "$.entries",
    )
    expected_digest = hashlib.sha256(
        canonical_document_bytes(entries)
    ).hexdigest()
    _require(
        value["evidence_closure_digest"] == expected_digest,
        "EVIDENCE_CLOSURE_DIGEST_INVALID",
        "$.evidence_closure_digest",
    )


def _task_evidence_ref_matches_document(
    ref: dict[str, object],
    schema_id: str,
    document: dict[str, object],
) -> bool:
    raw = canonical_document_bytes(document)
    return (
        ref["schema_id"] == "content-ref/v1"
        and ref["content_schema_id"] == schema_id
        and ref["sha256"] == hashlib.sha256(raw).hexdigest()
        and ref["size_bytes"] == len(raw)
        and ref["media_type"] == "application/json"
        and ref["encoding"] == "utf-8"
    )


def _task_evidence_expected_entries(
    manifest: dict[str, object],
    pre_gate_manifest: dict[str, object],
) -> list[dict[str, object]]:
    candidates = [
        *pre_gate_manifest["entries"],
        manifest["pre_gate_evidence_closure_ref"],
        manifest["input_snapshot_ref"],
        manifest["gate_decision_ref"],
    ]
    unique = {
        canonical_document_bytes(ref): ref
        for ref in candidates
    }
    return sorted(unique.values(), key=_ref_key)


def verify_evidence_closure_context(
    manifest: object,
    pre_gate_manifest: object,
) -> dict[str, object]:
    """Bind final closure to the direct PreGate manifest document."""
    validated = verify_document_digest(
        "evidence-closure-manifest/v1", manifest
    )
    pre_gate = verify_document_digest(
        "pre-gate-evidence-closure-manifest/v1", pre_gate_manifest
    )
    _require(
        validated["task_id"] == pre_gate["task_id"],
        "EVIDENCE_CLOSURE_INVALID",
        "$.task_id",
    )
    _require(
        _task_evidence_ref_matches_document(
            validated["pre_gate_evidence_closure_ref"],
            "pre-gate-evidence-closure-manifest/v1",
            pre_gate,
        ),
        "CAS_CORRUPT",
        "$.pre_gate_evidence_closure_ref",
    )
    expected = _task_evidence_expected_entries(validated, pre_gate)
    _require(
        [canonical_document_bytes(ref) for ref in validated["entries"]]
        == [canonical_document_bytes(ref) for ref in expected],
        "EVIDENCE_CLOSURE_INVALID",
        "$.entries",
    )
    return validated


