def _terminal_selection(axes: dict[str, object]) -> tuple[str, str | None, str | None]:
    _require(
        all(axes.get(field) in allowed for field, allowed in _GATE_SELECTOR_AXES.items()),
        "GATE_TERMINAL_SELECTOR_COMBINATION_INVALID",
        "$.context",
    )
    if axes["profile"] == "tombstone_pre_fence":
        _fail("GATE_TERMINAL_SELECTOR_TOMBSTONE_PRE_FENCE", "$.context.profile")
    gate_mode = axes["gate_mode"]
    cancel_state = axes["cancel_state"]
    effect_state = axes["effect_state"]
    cause_family = axes["cause_family"]
    delivery_state = axes["delivery_state"]
    valid = "GATE_TERMINAL_SELECTOR_COMBINATION_INVALID"
    if effect_state in {"unknown_pre_deadline", "unknown_post_deadline"}:
        _require(gate_mode == "none" and delivery_state == "none", valid, "$.context")
        if effect_state == "unknown_pre_deadline":
            return "RECONCILING", None, None
        return "TERMINAL", "TERMINATED_WITH_UNKNOWN_EFFECTS", "DEADLINE_REACHED"
    if cancel_state != "none":
        _require(
            gate_mode == "none" and delivery_state == "none"
            and effect_state in {"none", "committed"} and cause_family == "none",
            valid,
            "$.context",
        )
        outcome = "CANCELLED_WITH_EFFECTS" if effect_state == "committed" else "CANCELLED"
        return "TERMINAL", outcome, _GATE_CANCEL_REASONS[cancel_state]
    if gate_mode != "none":
        outcome, reason, expected_delivery = _GATE_SUCCESS_SELECTIONS[gate_mode]
        _require(
            cause_family == "none" and delivery_state == expected_delivery
            and (
                effect_state == "none"
                if gate_mode == "no_change_needed"
                else effect_state in {"none", "committed"}
            ),
            valid,
            "$.context",
        )
        return "TERMINAL", outcome, reason
    if delivery_state == "safe_partial":
        _require(
            effect_state == "committed" and cause_family in _GATE_PARTIAL_REASONS,
            valid,
            "$.context",
        )
        return "TERMINAL", "PARTIAL", _GATE_PARTIAL_REASONS[cause_family]
    if cause_family in _GATE_BLOCKED_REASONS:
        _require(effect_state == "none" and delivery_state == "none", valid, "$.context")
        return "TERMINAL", "BLOCKED", _GATE_BLOCKED_REASONS[cause_family]
    if cause_family in _GATE_FAILED_REASONS:
        _require(
            effect_state == "none" and delivery_state == "none",
            valid,
            "$.context",
        )
        return "TERMINAL", "FAILED", _GATE_FAILED_REASONS[cause_family]
    _fail(valid, "$.context")


def _terminal_selector_projection(value: dict[str, object]) -> dict[str, object]:
    fields = (
        "input_digest", "predicate_registry_digest", "task_id", "task_version",
        "deletion_version", "profile", "gate_mode", "cancel_state", "effect_state",
        "cause_family", "delivery_state", "authoritative_fact_refs",
        "source_availability", "evidence_availability", "effect_availability",
        "predicate_results", "selected_lifecycle", "selected_outcome", "selected_reason",
    )
    return {field: value[field] for field in fields}


def _terminal_selector_digest(value: dict[str, object]) -> str:
    return hashlib.sha256(
        b"pullwise:terminal-selector-input:v1\0"
        + canonical_document_bytes(_terminal_selector_projection(value))
    ).hexdigest()


def _gate_verify_digest(
    schema_id: str, value: dict[str, object], field: str
) -> None:
    presented = value[field]
    spec = schema(schema_id)["x-pullwise-digest"]
    unsigned = {key: item for key, item in value.items() if key != field}
    expected = hashlib.sha256(
        spec["domain"].encode("utf-8")
        + b"\0"
        + canonical_document_bytes(unsigned)
    ).hexdigest()
    _require(presented == expected, "CONTRACT_DIGEST_MISMATCH", f"$.{field}")


def _rule_gate_predicate_registry(value: dict[str, object]) -> None:
    _require(
        value["predicates"] == _GATE_PREDICATE_ENTRIES,
        "GATE_PREDICATE_REGISTRY_INVALID",
        "$.predicates",
    )
    _gate_verify_digest(
        "gate-predicate-registry/v1", value, "registry_digest"
    )


def _gate_registry_digest() -> str:
    return fixture("gate_golden_independent_registry")["document"][
        "registry_digest"
    ]


def _gate_expected_entries(decision_kind: str) -> list[dict[str, object]]:
    return [
        item
        for item in _GATE_PREDICATE_ENTRIES
        if item["decision_kind"] == decision_kind
    ]


def _gate_validate_ref_order(
    refs: list[dict[str, object]], path: str
) -> None:
    verify_content_ref_set(refs)
    keys = [_ref_key(item) for item in refs]
    _require(
        keys == sorted(set(keys)),
        "GATE_PREDICATE_EVIDENCE_INVALID",
        path,
    )


def _rule_gate_decision(value: dict[str, object]) -> None:
    _require(
        value["predicate_registry_digest"] == _gate_registry_digest(),
        "GATE_PREDICATE_REGISTRY_DIGEST_INVALID",
        "$.predicate_registry_digest",
    )
    expected = _gate_expected_entries(value["decision_kind"])
    results = value["predicate_results"]
    _require(
        [item["predicate_id"] for item in results]
        == [item["predicate_id"] for item in expected],
        "GATE_PREDICATE_ORDER_INVALID",
        "$.predicate_results",
    )
    for index, (result, predicate) in enumerate(zip(results, expected)):
        path = f"$.predicate_results[{index}]"
        _require(
            result["passed"] == (result["failure_code"] is None),
            "GATE_PREDICATE_RESULT_INVALID",
            f"{path}.failure_code",
        )
        _require(
            result["failure_code"] is None
            or result["failure_code"] in predicate["failure_codes"],
            "GATE_PREDICATE_FAILURE_CODE_INVALID",
            f"{path}.failure_code",
        )
        refs = result["evidence_refs"]
        _gate_validate_ref_order(refs, f"{path}.evidence_refs")
        _require(
            all(
                item["content_schema_id"] in predicate["input_schema_ids"]
                for item in refs
            ),
            "GATE_PREDICATE_EVIDENCE_INVALID",
            f"{path}.evidence_refs",
        )
    _require(
        value["passed"] == all(item["passed"] for item in results),
        "GATE_DECISION_PASS_INVALID",
        "$.passed",
    )
    if value["decision_kind"] == "terminalization":
        selected = _terminal_selection(
            {field: value[field] for field in _GATE_SELECTOR_AXES}
        )
        _require(
            selected == (
                value["selected_lifecycle"], value["selected_outcome"],
                value["selected_reason"],
            ),
            "GATE_TERMINAL_OUTCOME_INVALID",
            "$.selected_reason",
        )
        refs = value["authoritative_fact_refs"]
        verify_content_ref_set(refs)
        keys = [_ref_key(item) for item in refs]
        _require(
            keys == sorted(set(keys)),
            "GATE_TERMINAL_FACT_ORDER_INVALID",
            "$.authoritative_fact_refs",
        )
        _require(
            value["selector_input_digest"] == _terminal_selector_digest(value),
            "GATE_TERMINAL_SELECTOR_DIGEST_INVALID",
            "$.selector_input_digest",
        )
    _gate_verify_digest("gate-decision/v1", value, "decision_digest")


def _gate_context(
    context: object, expected_keys: set[str]
) -> dict[str, object]:
    if not isinstance(context, dict) or set(context) != expected_keys:
        _fail("GATE_EVALUATION_CONTEXT_INVALID", "$.context")
    return json.loads(canonical_document_bytes(context).decode("utf-8"))


def _gate_passed(predicate_results: object) -> bool:
    if (
        not isinstance(predicate_results, list)
        or not all(
            isinstance(item, dict) and isinstance(item.get("passed"), bool)
            for item in predicate_results
        )
    ):
        _fail(
            "GATE_EVALUATION_CONTEXT_INVALID",
            "$.context.predicate_results",
        )
    return all(item["passed"] for item in predicate_results)


def _gate_snapshot_and_ref(
    schema_id: str, snapshot_value: object, reference_value: object
) -> tuple[dict[str, object], dict[str, object]]:
    snapshot = verify_document_digest(schema_id, snapshot_value)
    reference = validate_document("content-ref/v1", reference_value)
    raw = canonical_document_bytes(snapshot)
    if (
        reference["content_schema_id"] != schema_id
        or reference["sha256"] != hashlib.sha256(raw).hexdigest()
        or reference["size_bytes"] != len(raw)
        or reference["media_type"] != "application/json"
        or reference["encoding"] != "utf-8"
    ):
        _fail(
            "GATE_INPUT_SNAPSHOT_REF_MISMATCH",
            "$.context.input_snapshot_ref",
        )
    _require(
        snapshot["predicate_registry_digest"] == _gate_registry_digest(),
        "GATE_PREDICATE_REGISTRY_DIGEST_INVALID",
        "$.predicate_registry_digest",
    )
    return snapshot, reference


def _gate_effect_state(
    snapshot: dict[str, object],
    effect_ledger: object,
) -> str:
    ledger = verify_document_digest("effect-ledger-snapshot/v1", effect_ledger)
    raw = canonical_document_bytes(ledger)
    ref = snapshot["effect_ledger_ref"]
    _require(
        ref["content_schema_id"] == "effect-ledger-snapshot/v1"
        and ref["sha256"] == hashlib.sha256(raw).hexdigest()
        and ref["size_bytes"] == len(raw)
        and ref["media_type"] == "application/json"
        and ref["encoding"] == "utf-8",
        "CAS_CORRUPT",
        "$.context.effect_ledger",
    )
    _require(
        ledger["task_id"] == snapshot["task_id"],
        "GATE_TERMINAL_EFFECT_LEDGER_TASK_INVALID",
        "$.context.effect_ledger.task_id",
    )
    counts = ledger["state_counts"]
    _require(
        counts["prepared"] == counts["dispatched"] == 0,
        "GATE_TERMINAL_ACTIVE_EFFECTS",
        "$.context.effect_ledger.state_counts",
    )
    if counts["unknown"]:
        before_deadline = (
            _timestamp_millis(snapshot["trusted_wall_time_at"])
            < _timestamp_millis(snapshot["absolute_deadline_at"])
        )
        return "unknown_pre_deadline" if before_deadline else "unknown_post_deadline"
    return "committed" if counts["committed"] else "none"


def evaluate_success_gate(
    input_snapshot: object, context: object
) -> dict[str, object]:
    evaluation = _gate_context(
        context, {"input_snapshot_ref", "predicate_results"}
    )
    snapshot, reference = _gate_snapshot_and_ref(
        "gate-input-snapshot/v1",
        input_snapshot,
        evaluation["input_snapshot_ref"],
    )
    results = evaluation["predicate_results"]
    passed = _gate_passed(results)
    return seal_document(
        "gate-decision/v1",
        {
            "schema_id": "gate-decision/v1",
            "decision_kind": "success",
            "input_snapshot_ref": reference,
            "input_digest": snapshot["input_digest"],
            "predicate_registry_digest": snapshot["predicate_registry_digest"],
            "requested_outcome": snapshot["requested_outcome"],
            "passed": passed,
            "predicate_results": results,
        },
    )


def evaluate_terminalization_gate(
    input_snapshot: object, context: object
) -> dict[str, object]:
    evaluation = _gate_context(
        context,
        {
            "input_snapshot_ref", "profile", "gate_mode", "cancel_state",
            "effect_state", "cause_family", "delivery_state",
            "source_availability", "evidence_availability",
            "effect_availability", "effect_ledger", "predicate_results",
        },
    )
    snapshot, reference = _gate_snapshot_and_ref(
        "terminalization-input-snapshot/v1",
        input_snapshot,
        evaluation["input_snapshot_ref"],
    )
    _require(
        evaluation["source_availability"] == snapshot["final_source"],
        "GATE_TERMINAL_AVAILABILITY_MISMATCH",
        "$.context.source_availability",
    )
    expected_effect = {
        "availability": "available",
        "ref": snapshot["effect_ledger_ref"],
    }
    _require(
        evaluation["effect_availability"] == expected_effect,
        "GATE_TERMINAL_AVAILABILITY_MISMATCH",
        "$.context.effect_availability",
    )
    _require(
        evaluation["effect_state"]
        == _gate_effect_state(snapshot, evaluation["effect_ledger"]),
        "GATE_TERMINAL_EFFECT_STATE_INVALID",
        "$.context.effect_state",
    )
    results = evaluation["predicate_results"]
    passed = _gate_passed(results)
    axes = {field: evaluation[field] for field in _GATE_SELECTOR_AXES}
    lifecycle, outcome, reason = _terminal_selection(axes)
    decision = {
        "schema_id": "gate-decision/v1",
        "decision_kind": "terminalization",
        "input_snapshot_ref": reference,
        "input_digest": snapshot["input_digest"],
        "predicate_registry_digest": snapshot["predicate_registry_digest"],
        "task_id": snapshot["task_id"],
        "task_version": snapshot["task_version"],
        "deletion_version": snapshot["deletion_version"],
        **axes,
        "selected_lifecycle": lifecycle,
        "selected_outcome": outcome,
        "selected_reason": reason,
        "authoritative_fact_refs": snapshot["terminalization_fact_refs"],
        "source_availability": evaluation["source_availability"],
        "evidence_availability": evaluation["evidence_availability"],
        "effect_availability": evaluation["effect_availability"],
        "passed": passed,
        "predicate_results": results,
    }
    decision["selector_input_digest"] = _terminal_selector_digest(decision)
    return seal_document("gate-decision/v1", decision)


_TERMINALIZATION_REASON_CODES = {
    "BUDGET_EXHAUSTED",
    "CAPABILITY_UNAVAILABLE",
    "DEADLINE_REACHED",
    "INTERACTION_UNAVAILABLE",
    "POLICY_INVARIANT_BROKEN",
    "PROTOCOL_FAILURE",
    "RUNTIME_FAILURE",
    "STORAGE_FAILURE",
}
_TERMINALIZATION_CONTROL_ACTOR_KINDS = {
    "server_control",
    "system_reconciler",
    "worker_control",
}
_TERMINALIZATION_REQUEST_LIFECYCLES = {
    "QUEUED",
    "ACTIVE",
    "WAITING_INPUT",
    "WAITING_APPROVAL",
    "FINALIZING",
}


def _rule_debug_redaction_plan(value: dict[str, object]) -> None:
    _require(
        _sorted_unique(value["allowed_json_pointers"]),
        "DEBUG_REDACTION_POINTER_ORDER_INVALID",
        "$.allowed_json_pointers",
    )
    _require(
        _sorted_unique(value["rule_ids"]),
        "DEBUG_REDACTION_RULE_ORDER_INVALID",
        "$.rule_ids",
    )
    _require(
        _ordered_unique(value["debug_input_refs"], _ref_key),
        "DEBUG_REDACTION_INPUT_ORDER_INVALID",
        "$.debug_input_refs",
    )
    verify_content_ref_set(value["debug_input_refs"])


def _rule_publication_content_manifest(value: dict[str, object]) -> None:
    entries = value["entries"]
    _require(
        value["entry_count"] == len(entries),
        "PUBLICATION_ENTRY_COUNT_INVALID",
        "$.entry_count",
    )
    _require(
        _ordered_unique(entries, lambda item: item["json_pointer"]),
        "PUBLICATION_ENTRY_ORDER_INVALID",
        "$.entries",
    )
    for index, entry in enumerate(entries):
        receipt = entry["redaction_receipt"]
        receipt_path = f"$.entries[{index}].redaction_receipt"
        _require(
            receipt["policy_digest"] == value["redaction_policy_digest"],
            "PUBLICATION_REDACTION_POLICY_INVALID",
            f"{receipt_path}.policy_digest",
        )
        original_sha256 = (
            entry["source_ref"]["sha256"]
            if entry["content_kind"] == "artifact_bytes"
            else entry["inline_digest"]
        )
        _require(
            receipt["original_sha256"] == original_sha256,
            "PUBLICATION_REDACTION_SOURCE_INVALID",
            f"{receipt_path}.original_sha256",
        )


def _rule_terminalization_fact(value: dict[str, object]) -> None:
    reason_code = value["reason_code"]
    _require(
        reason_code in _TERMINALIZATION_REASON_CODES,
        "TERMINALIZATION_REASON_INVALID",
        "$.reason_code",
    )
    expected_key = (
        f"terminalize:{reason_code.lower()}:{value['observed_task_version']}"
    )
    _require(
        value["idempotency_key"] == expected_key,
        "TERMINALIZATION_IDEMPOTENCY_KEY_INVALID",
        "$.idempotency_key",
    )
    _require(
        value["source"]["kind"] in _TERMINALIZATION_CONTROL_ACTOR_KINDS,
        "TERMINALIZATION_ACTOR_INVALID",
        "$.source.kind",
    )
    evidence_refs = value["evidence_refs"]
    _require(
        _ordered_unique(evidence_refs, _ref_key),
        "TERMINALIZATION_EVIDENCE_ORDER_INVALID",
        "$.evidence_refs",
    )
    verify_content_ref_set(evidence_refs)
    if reason_code == "BUDGET_EXHAUSTED":
        _require(
            any(
                item["content_schema_id"] == "budget-summary/v1"
                for item in evidence_refs
            ),
            "TERMINALIZATION_BUDGET_EVIDENCE_REQUIRED",
            "$.evidence_refs",
        )


def verify_terminalization_fact_context(
    fact: object,
    task_id: str,
    current_task_version: int,
    lifecycle_state: str,
    existing_fact: object | None = None,
) -> dict[str, object]:
    """Bind a fact to task state and enforce exact idempotency retry bytes.

    The stable public signature is ``(fact, task_id, current_task_version,
    lifecycle_state, existing_fact=None)``. ``existing_fact`` is the fact
    previously accepted for the candidate idempotency key, when one exists.
    """
    validated = verify_document_digest("terminalization-fact/v1", fact)
    _require(
        isinstance(task_id, str) and validated["task_id"] == task_id,
        "TASK_ID_COLLISION",
        "$.task_id",
    )
    _require(
        isinstance(current_task_version, int)
        and not isinstance(current_task_version, bool)
        and 1 <= current_task_version <= SAFE_INTEGER
        and validated["observed_task_version"] == current_task_version,
        "TASK_VERSION_STALE",
        "$.observed_task_version",
    )
    _require(
        lifecycle_state in _TERMINALIZATION_REQUEST_LIFECYCLES,
        "STATE_TRANSITION_INVALID",
        "$.lifecycle_state",
    )
    if existing_fact is not None:
        existing = verify_document_digest(
            "terminalization-fact/v1", existing_fact
        )
        if existing["idempotency_key"] == validated["idempotency_key"]:
            _require(
                canonical_document_bytes(existing)
                == canonical_document_bytes(validated),
                "IDEMPOTENCY_CONFLICT",
                "$.idempotency_key",
            )
    return validated


_VERIFICATION_CONTEXT_INVALID = "VERIFICATION_CONTEXT_INVALID"
_VERIFICATION_CONTEXT_CAS_CORRUPT = "VERIFICATION_CONTEXT_CAS_CORRUPT"
_VERIFICATION_CONTEXT_DIGEST_INVALID = "VERIFICATION_CONTEXT_DIGEST_INVALID"
_VERIFICATION_CONTEXT_TIME_INVALID = "VERIFICATION_CONTEXT_TIME_INVALID"


def _verification_require(
    condition: bool,
    detail: str,
    path: str = "$",
) -> None:
    if not condition:
        _fail(detail, path)


def _verification_verify_embedded_digest(
    schema_id: str,
    value: dict[str, object],
) -> None:
    spec = schema(schema_id).get("x-pullwise-digest")
    _verification_require(
        isinstance(spec, dict),
        "CONTRACT_DIGEST_UNDECLARED",
        "$",
    )
    field = spec["field"]
    domain = spec["domain"]
    unsigned = {key: item for key, item in value.items() if key != field}
    raw = domain.encode("utf-8") + b"\0" + canonical_document_bytes(unsigned)
    _verification_require(
        value[field] == hashlib.sha256(raw).hexdigest(),
        "CONTRACT_DIGEST_MISMATCH",
        f"$.{field}",
    )


def _verification_digest_field(schema_id: str) -> str | None:
    spec = schema(schema_id).get("x-pullwise-digest")
    return spec["field"] if isinstance(spec, dict) else None


def _verification_check_document(
    schema_id: str,
    value: object,
) -> dict[str, object]:
    return (
        verify_document_digest(schema_id, value)
        if _verification_digest_field(schema_id) is not None
        else validate_document(schema_id, value)
    )


def _verification_check_documents(
    schema_id: str,
    values: object,
    path: str,
) -> list[dict[str, object]]:
    _verification_require(isinstance(values, list), _VERIFICATION_CONTEXT_INVALID, path)
    return [_verification_check_document(schema_id, item) for item in values]


def _verification_request_digest(document: dict[str, object]) -> str:
    return hashlib.sha256(canonical_document_bytes(document)).hexdigest()


def _verification_companion_digest(
    schema_id: str,
    document: dict[str, object],
) -> str:
    field = _verification_digest_field(schema_id)
    _verification_require(field is not None, _VERIFICATION_CONTEXT_DIGEST_INVALID, "$")
    return document[field]


def _verification_require_ref(
    ref: dict[str, object],
    schema_id: str,
    document: dict[str, object],
    path: str,
) -> None:
    _verification_require(
        _seo_ref_matches_document(ref, schema_id, document),
        _VERIFICATION_CONTEXT_CAS_CORRUPT,
        path,
    )


def _verification_require_companion_digest(
    actual: object,
    schema_id: str,
    document: dict[str, object],
    path: str,
) -> None:
    _verification_require(
        actual == _verification_companion_digest(schema_id, document),
        _VERIFICATION_CONTEXT_DIGEST_INVALID,
        path,
    )


def _verification_require_time_order(
    values: list[object],
    path: str,
) -> None:
    _verification_require(bool(values), _VERIFICATION_CONTEXT_TIME_INVALID, path)
    final_epoch = _timestamp_millis(values[-1])
    _verification_require(final_epoch is not None, _VERIFICATION_CONTEXT_TIME_INVALID, path)
    for predecessor in values[:-1]:
        if predecessor is None:
            continue
        predecessor_epoch = _timestamp_millis(predecessor)
        _verification_require(
            predecessor_epoch is not None and predecessor_epoch <= final_epoch,
            _VERIFICATION_CONTEXT_TIME_INVALID,
            path,
        )


def _verification_change_binding(
    availability: object,
    change_set: dict[str, object] | None,
    path: str,
) -> dict[str, object]:
    if not isinstance(availability, dict):
        _verification_require(
            False,
            _VERIFICATION_CONTEXT_INVALID,
            path,
        )
        return {}
    checked = availability
    if change_set is None:
        _verification_require(
            checked["availability"] == "not_applicable",
            _VERIFICATION_CONTEXT_INVALID,
            path,
        )
        return checked
    _verification_require(
        checked["availability"] == "available",
        _VERIFICATION_CONTEXT_INVALID,
        path,
    )
    _verification_require_ref(
        checked["ref"],
        "change-set/v1",
        change_set,
        f"{path}.ref",
    )
    return checked


def _verification_find_plan_slot(
    plan: dict[str, object],
    slot_id: str,
) -> dict[str, object] | None:
    return next((item for item in plan["slots"] if item["slot_id"] == slot_id), None)


def _verification_manifest_entries(
    manifest: dict[str, object],
) -> dict[str, dict[str, object]]:
    return {item["observation_id"]: item for item in manifest["entries"]}


def _verification_requirement_ids(
    values: list[dict[str, object]],
) -> list[str]:
    return [item["requirement_id"] for item in values]


def _verification_valid_assessments(
    values: list[dict[str, object]],
) -> bool:
    return _ordered_unique(values, lambda item: item["requirement_id"]) and all(
        _sorted_unique(item["evidence_ids"])
        and _sorted_unique(item["limitations"])
        and (item["verdict"] != "PASS" or not item["limitations"])
        for item in values
    )


def _verification_run_status(
    values: list[dict[str, object]],
) -> str:
    verdicts = {item["verdict"] for item in values}
    for verdict in ("POLICY_VIOLATION", "NEEDS_WORK", "UNVERIFIABLE"):
        if verdict in verdicts:
            return verdict
    return "PASS"


def _verification_aggregate_result(
    requirement_id: str,
    required_slot_ids: list[str],
    attestation_by_slot: dict[str, dict[str, object]],
) -> tuple[list[str], str]:
    attestation_ids: list[str] = []
    verdicts: list[str] = []
    missing_verdict = False
    for slot_id in required_slot_ids:
        document = attestation_by_slot.get(slot_id)
        if document is None:
            missing_verdict = True
            continue
        verdict = next(
            (
                item["verdict"]
                for item in document["requirement_verdicts"]
                if item["requirement_id"] == requirement_id
            ),
            None,
        )
        if verdict is None:
            missing_verdict = True
            continue
        attestation_ids.append(document["attestation_id"])
        verdicts.append(verdict)
    attestation_ids.sort()
    if missing_verdict or "UNVERIFIABLE" in verdicts:
        return attestation_ids, "UNVERIFIABLE"
    if any(item in {"POLICY_VIOLATION", "NEEDS_WORK"} for item in verdicts):
        return attestation_ids, "FAIL"
    return attestation_ids, "PASS"


def _rule_completion_proposal(value: dict[str, object]) -> None:
    _verification_verify_embedded_digest("completion-proposal/v1", value)
    _verification_require(
        _sorted_unique(value["execution_state_ids"]),
        "PROPOSAL_EXECUTION_STATE_ORDER_INVALID",
    )
    _verification_require(
        _ordered_unique(value["artifact_refs"], _artifact_ref_key),
        "PROPOSAL_ARTIFACT_ORDER_INVALID",
    )
    _verification_require(
        _ordered_unique(value["requirement_claims"], lambda item: item["requirement_id"]),
        "PROPOSAL_CLAIM_ORDER_INVALID",
    )
    for item in value["requirement_claims"]:
        _verification_require(
            _sorted_unique(item["evidence_ids"]),
            "PROPOSAL_EVIDENCE_ORDER_INVALID",
        )
    _verification_require(_sorted_unique(value["known_gaps"]), "PROPOSAL_GAP_ORDER_INVALID")
    _verification_require(
        _sorted_unique(value["residual_risks"]),
        "PROPOSAL_RISK_ORDER_INVALID",
    )
    if value["outcome_requested"] == "NO_CHANGE_NEEDED":
        _verification_require(value["change_set_ref"] is None, "PROPOSAL_NO_CHANGE_SET_INVALID")
        _verification_require(
            value["original_source_state_id"] == value["final_source_state_id"],
            "PROPOSAL_NO_CHANGE_STATE_INVALID",
        )


def _rule_verifier_input(value: dict[str, object]) -> None:
    _verification_verify_embedded_digest("verifier-input-manifest/v1", value)
    _verification_require(value["owner_conclusion_excluded"] is True, "VERIFIER_OWNER_CONCLUSION_INCLUDED")
    _verification_require(
        _ordered_unique(value["artifact_refs"], _artifact_ref_key),
        "VERIFIER_ARTIFACT_ORDER_INVALID",
    )
    _verification_require(
        _ordered_unique(value["engineering_rule_refs"], _ref_key),
        "VERIFIER_RULE_ORDER_INVALID",
    )
    _verification_require(_sorted_unique(value["requirement_ids"]), "VERIFIER_REQUIREMENT_ORDER_INVALID")


def _rule_verifier_work(value: dict[str, object]) -> None:
    _verification_verify_embedded_digest("verifier-work-report/v1", value)
    _verification_require(value["sandbox_mode"] == "read_only_or_cow", "VERIFIER_SANDBOX_INVALID")
    for field in ("counterexamples_searched", "own_observation_ids", "limitations"):
        _verification_require(_sorted_unique(value[field]), "VERIFIER_WORK_ORDER_INVALID", f"$.{field}")
    _verification_require(bool(value["own_observation_ids"]), "VERIFIER_OBSERVATION_REQUIRED")
    _verification_require(
        _verification_valid_assessments(value["provisional_requirement_assessments"]),
        "VERIFIER_ASSESSMENT_INVALID",
    )


def _rule_attestation(value: dict[str, object]) -> None:
    _verification_verify_embedded_digest("verification-attestation/v1", value)
    _verification_require(
        _sorted_unique(value["execution_state_ids"]),
        "ATTESTATION_EXECUTION_ORDER_INVALID",
    )
    _verification_require(
        _sorted_unique(value["own_observation_ids"]) and bool(value["own_observation_ids"]),
        "ATTESTATION_OBSERVATION_INVALID",
    )
    _verification_require(
        _verification_valid_assessments(value["requirement_verdicts"]),
        "ATTESTATION_VERDICT_INVALID",
    )
    _verification_require(
        value["run_status"] == _verification_run_status(value["requirement_verdicts"]),
        "ATTESTATION_RUN_STATUS_INVALID",
    )


def _rule_attestation_manifest(value: dict[str, object]) -> None:
    _verification_verify_embedded_digest("verification-attestation-manifest/v1", value)
    _verification_require(
        value["attestation_count"] == len(value["attestations"]),
        "ATTESTATION_MANIFEST_COUNT_INVALID",
    )
    _verification_require(
        _ordered_unique(
            value["attestations"],
            lambda item: (item["slot_id"], item["attestation_id"]),
        ),
        "ATTESTATION_MANIFEST_ORDER_INVALID",
    )
    slot_ids = {item["slot_id"] for item in value["attestations"]}
    attestation_ids = {item["attestation_id"] for item in value["attestations"]}
    _verification_require(
        _ordered_unique(value["requirement_aggregates"], lambda item: item["requirement_id"]),
        "ATTESTATION_AGGREGATE_ORDER_INVALID",
    )
    for item in value["requirement_aggregates"]:
        _verification_require(
            _sorted_unique(item["required_slot_ids"]),
            "ATTESTATION_REQUIRED_SLOT_ORDER_INVALID",
        )
        _verification_require(
            _sorted_unique(item["attestation_ids"]),
            "ATTESTATION_ID_ORDER_INVALID",
        )
        _verification_require(
            set(item["attestation_ids"]).issubset(attestation_ids),
            "ATTESTATION_ID_UNKNOWN",
        )
        if set(item["required_slot_ids"]).difference(slot_ids):
            _verification_require(
                item["verdict"] == "UNVERIFIABLE",
                "ATTESTATION_MISSING_SLOT_INVALID",
            )


def verify_completion_proposal_context(
    proposal: object,
    task_snapshot: object,
    attempt: object,
    owner: object,
    task_request: object,
    effective_policy: object,
    requirement_ledger: object,
    execution_charter: object,
    original_source: object,
    final_source: object,
    execution_states: object,
    change_set: object,
    pre_observation_manifest: object,
) -> dict[str, object]:
    checked = verify_document_digest("completion-proposal/v1", proposal)
    snapshot = validate_document("task-record/v1", task_snapshot)
    attempt_value = validate_document("attempt-record/v1", attempt)
    owner_value = validate_document("task-owner/v1", owner)
    request_value = validate_document("task-request/v1", task_request)
    policy_value = verify_document_digest("effective-execution-policy/v1", effective_policy)
    ledger_value = verify_document_digest("requirement-ledger/v1", requirement_ledger)
    charter_value = verify_document_digest("task-charter/v1", execution_charter)
    original_value = verify_document_digest("source-tree-manifest/v1", original_source)
    final_value = verify_document_digest("source-tree-manifest/v1", final_source)
    pre_value = verify_document_digest("pre-verifier-observation-manifest/v1", pre_observation_manifest)
    state_values = _verification_check_documents("execution-state-manifest/v1", execution_states, "$.execution_state_ids")
    change_value = None if change_set is None else verify_document_digest("change-set/v1", change_set)

    _verification_require(checked["task_id"] == snapshot["task_id"], _VERIFICATION_CONTEXT_INVALID, "$.task_id")
    _verification_require(checked["task_id"] == attempt_value["task_id"], _VERIFICATION_CONTEXT_INVALID, "$.task_id")
    _verification_require(checked["task_id"] == owner_value["task_id"], _VERIFICATION_CONTEXT_INVALID, "$.task_id")
    _verification_require(checked["task_id"] == request_value["task_id"], _VERIFICATION_CONTEXT_INVALID, "$.task_id")
    _verification_require(checked["task_id"] == ledger_value["task_id"], _VERIFICATION_CONTEXT_INVALID, "$.task_id")
    _verification_require(checked["task_id"] == charter_value["task_id"], _VERIFICATION_CONTEXT_INVALID, "$.task_id")
    _verification_require(checked["attempt_id"] == snapshot["current_attempt_id"], _VERIFICATION_CONTEXT_INVALID, "$.attempt_id")
    _verification_require(checked["attempt_id"] == attempt_value["attempt_id"], _VERIFICATION_CONTEXT_INVALID, "$.attempt_id")
    _verification_require(checked["attempt_id"] == owner_value["attempt_id"], _VERIFICATION_CONTEXT_INVALID, "$.attempt_id")
    _verification_require(checked["native_epoch"] == snapshot["native_epoch"], _VERIFICATION_CONTEXT_INVALID, "$.native_epoch")
    _verification_require(checked["native_epoch"] == attempt_value["native_epoch"], _VERIFICATION_CONTEXT_INVALID, "$.native_epoch")
    _verification_require(checked["native_epoch"] == owner_value["native_epoch"], _VERIFICATION_CONTEXT_INVALID, "$.native_epoch")
    _verification_require(checked["owner_id"] == snapshot["owner_id"], _VERIFICATION_CONTEXT_INVALID, "$.owner_id")
    _verification_require(checked["owner_id"] == owner_value["owner_id"], _VERIFICATION_CONTEXT_INVALID, "$.owner_id")
    _verification_require(checked["owner_epoch"] == snapshot["owner_epoch"], _VERIFICATION_CONTEXT_INVALID, "$.owner_epoch")
    _verification_require(checked["owner_epoch"] == owner_value["owner_epoch"], _VERIFICATION_CONTEXT_INVALID, "$.owner_epoch")
    _verification_require(snapshot["task_type"] == request_value["task_type"], _VERIFICATION_CONTEXT_INVALID, "$.task_type")
    _verification_require(snapshot["task_type"] == policy_value["task_type"], _VERIFICATION_CONTEXT_INVALID, "$.task_type")
    _verification_require(snapshot["task_version"] == checked["proposed_from_task_version"], _VERIFICATION_CONTEXT_INVALID, "$.proposed_from_task_version")
    _verification_require(owner_value["session_id"] == attempt_value["owner_session_id"], _VERIFICATION_CONTEXT_INVALID, "$.session_id")
    _verification_require(pre_value["task_id"] == checked["task_id"], _VERIFICATION_CONTEXT_INVALID, "$.pre_observation_manifest.task_id")
    _verification_require(pre_value["proposal_id"] == checked["proposal_id"], _VERIFICATION_CONTEXT_INVALID, "$.pre_observation_manifest.proposal_id")
    _verification_require(pre_value["attempt_id"] == checked["attempt_id"], _VERIFICATION_CONTEXT_INVALID, "$.pre_observation_manifest.attempt_id")
    _verification_require(pre_value["native_epoch"] == checked["native_epoch"], _VERIFICATION_CONTEXT_INVALID, "$.pre_observation_manifest.native_epoch")
    _verification_require(snapshot["charter_ref"] is not None, _VERIFICATION_CONTEXT_INVALID, "$.charter_ref")
    _verification_require_ref(snapshot["request_ref"], "task-request/v1", request_value, "$.request_ref")
    _verification_require_ref(snapshot["policy_ref"], "effective-execution-policy/v1", policy_value, "$.policy_ref")
    _verification_require_ref(snapshot["charter_ref"], "task-charter/v1", charter_value, "$.charter_ref")
    if snapshot["completion_proposal_ref"] is not None:
        _verification_require_ref(snapshot["completion_proposal_ref"], "completion-proposal/v1", checked, "$.completion_proposal_ref")
    _verification_require(
        checked["request_digest"] == snapshot["request_digest"] == _verification_request_digest(request_value),
        _VERIFICATION_CONTEXT_DIGEST_INVALID,
        "$.request_digest",
    )
    _verification_require(
        checked["policy_digest"] == snapshot["policy_digest"] == policy_value["digest"],
        _VERIFICATION_CONTEXT_DIGEST_INVALID,
        "$.policy_digest",
    )
    _verification_require(
        checked["requirement_ledger_digest"] == snapshot["ledger_head_digest"] == ledger_value["ledger_digest"],
        _VERIFICATION_CONTEXT_DIGEST_INVALID,
        "$.requirement_ledger_digest",
    )
    _verification_require(
        checked["charter_digest"] == _verification_companion_digest("task-charter/v1", charter_value),
        _VERIFICATION_CONTEXT_DIGEST_INVALID,
        "$.charter_digest",
    )
    _verification_require(checked["original_source_state_id"] == original_value["source_state_id"], _VERIFICATION_CONTEXT_INVALID, "$.original_source_state_id")
    _verification_require(checked["final_source_state_id"] == final_value["source_state_id"], _VERIFICATION_CONTEXT_INVALID, "$.final_source_state_id")
    _verification_require(
        checked["execution_state_ids"] == [item["execution_state_id"] for item in state_values],
        _VERIFICATION_CONTEXT_INVALID,
        "$.execution_state_ids",
    )
    for index, state_value in enumerate(state_values):
        _verification_require(
            state_value["source_state_id"] == final_value["source_state_id"],
            _VERIFICATION_CONTEXT_INVALID,
            f"$.execution_state_ids[{index}]",
        )
    if change_value is None:
        _verification_require(checked["change_set_ref"] is None, _VERIFICATION_CONTEXT_INVALID, "$.change_set_ref")
    else:
        _verification_require_ref(checked["change_set_ref"], "change-set/v1", change_value, "$.change_set_ref")
        _verification_require(change_value["original_source_state_id"] == original_value["source_state_id"], _VERIFICATION_CONTEXT_INVALID, "$.change_set_ref")
        _verification_require(change_value["final_source_state_id"] == final_value["source_state_id"], _VERIFICATION_CONTEXT_INVALID, "$.change_set_ref")
    _verification_require(
        _verification_requirement_ids(checked["requirement_claims"]) == ledger_value["active_requirement_ids"],
        _VERIFICATION_CONTEXT_INVALID,
        "$.requirement_claims",
    )
    known_observations = set(_verification_manifest_entries(pre_value))
    for index, item in enumerate(checked["requirement_claims"]):
        _verification_require(
            set(item["evidence_ids"]).issubset(known_observations),
            _VERIFICATION_CONTEXT_INVALID,
            f"$.requirement_claims[{index}].evidence_ids",
        )
    _verification_require_time_order(
        [
            request_value["submitted_at"],
            policy_value["issued_at"],
            charter_value["created_at"],
            snapshot["created_at"],
            snapshot["updated_at"],
            attempt_value["lease_acquired_at"],
            attempt_value["started_at"],
            attempt_value["ended_at"],
            owner_value["started_at"],
            owner_value["ended_at"],
            checked["created_at"],
        ],
        "$.created_at",
    )
    return checked


def verify_verifier_input_context(
    manifest: object,
    proposal: object,
    quality_policy_plan: object,
    task_request: object,
    effective_policy: object,
    requirement_ledger: object,
    execution_charter: object,
    original_source: object,
    final_source: object,
    change_set: object,
    pre_observation_manifest: object,
    engineering_rules: object,
) -> dict[str, object]:
    checked = verify_document_digest("verifier-input-manifest/v1", manifest)
    proposal_value = verify_document_digest("completion-proposal/v1", proposal)
    plan_value = verify_document_digest("quality-policy-plan/v1", quality_policy_plan)
    request_value = validate_document("task-request/v1", task_request)
    policy_value = verify_document_digest("effective-execution-policy/v1", effective_policy)
    ledger_value = verify_document_digest("requirement-ledger/v1", requirement_ledger)
    charter_value = verify_document_digest("task-charter/v1", execution_charter)
    original_value = verify_document_digest("source-tree-manifest/v1", original_source)
    final_value = verify_document_digest("source-tree-manifest/v1", final_source)
    pre_value = verify_document_digest("pre-verifier-observation-manifest/v1", pre_observation_manifest)
    rule_values = _verification_check_documents("source-content/v1", engineering_rules, "$.engineering_rule_refs")
    change_value = None if change_set is None else verify_document_digest("change-set/v1", change_set)
    slot = _verification_find_plan_slot(plan_value, checked["slot_id"])

    _verification_require(slot is not None, _VERIFICATION_CONTEXT_INVALID, "$.slot_id")
    _verification_require(checked["task_id"] == proposal_value["task_id"] == plan_value["task_id"], _VERIFICATION_CONTEXT_INVALID, "$.task_id")
    _verification_require(checked["task_id"] == request_value["task_id"] == ledger_value["task_id"] == charter_value["task_id"], _VERIFICATION_CONTEXT_INVALID, "$.task_id")
    _verification_require(checked["proposal_id"] == proposal_value["proposal_id"] == plan_value["proposal_id"], _VERIFICATION_CONTEXT_INVALID, "$.proposal_id")
    _verification_require(checked["artifact_refs"] == proposal_value["artifact_refs"], _VERIFICATION_CONTEXT_INVALID, "$.artifact_refs")
    _verification_require_ref(checked["task_request_ref"], "task-request/v1", request_value, "$.task_request_ref")
    _verification_require_ref(checked["effective_policy_ref"], "effective-execution-policy/v1", policy_value, "$.effective_policy_ref")
    _verification_require_ref(checked["requirement_ledger_ref"], "requirement-ledger/v1", ledger_value, "$.requirement_ledger_ref")
    _verification_require_ref(checked["charter_ref"], "task-charter/v1", charter_value, "$.charter_ref")
    _verification_require_ref(checked["completion_proposal_ref"], "completion-proposal/v1", proposal_value, "$.completion_proposal_ref")
    _verification_require_ref(checked["quality_policy_plan_ref"], "quality-policy-plan/v1", plan_value, "$.quality_policy_plan_ref")
    _verification_require_ref(checked["original_source_ref"], "source-tree-manifest/v1", original_value, "$.original_source_ref")
    _verification_require_ref(checked["final_source_ref"], "source-tree-manifest/v1", final_value, "$.final_source_ref")
    _verification_require_ref(checked["pre_verifier_observation_manifest_ref"], "pre-verifier-observation-manifest/v1", pre_value, "$.pre_verifier_observation_manifest_ref")
    _verification_require_companion_digest(checked["quality_policy_plan_digest"], "quality-policy-plan/v1", plan_value, "$.quality_policy_plan_digest")
    _verification_require(plan_value["proposal_digest"] == proposal_value["proposal_digest"], _VERIFICATION_CONTEXT_DIGEST_INVALID, "$.proposal_digest")
    _verification_require(plan_value["policy_digest"] == proposal_value["policy_digest"] == policy_value["digest"], _VERIFICATION_CONTEXT_DIGEST_INVALID, "$.policy_digest")
    _verification_require(plan_value["requirement_ledger_digest"] == ledger_value["ledger_digest"], _VERIFICATION_CONTEXT_DIGEST_INVALID, "$.requirement_ledger_digest")
    _verification_require(checked["slot_concern"] == slot["concern"], _VERIFICATION_CONTEXT_INVALID, "$.slot_concern")
    _verification_require(checked["requirement_ids"] == slot["requirement_ids"], _VERIFICATION_CONTEXT_INVALID, "$.requirement_ids")
    _verification_require(proposal_value["request_digest"] == _verification_request_digest(request_value), _VERIFICATION_CONTEXT_DIGEST_INVALID, "$.request_digest")
    _verification_require(request_value["task_type"] == policy_value["task_type"], _VERIFICATION_CONTEXT_INVALID, "$.task_type")
    _verification_require(proposal_value["charter_digest"] == _verification_companion_digest("task-charter/v1", charter_value), _VERIFICATION_CONTEXT_DIGEST_INVALID, "$.charter_digest")
    _verification_require(proposal_value["original_source_state_id"] == original_value["source_state_id"], _VERIFICATION_CONTEXT_INVALID, "$.original_source_ref")
    _verification_require(proposal_value["final_source_state_id"] == final_value["source_state_id"], _VERIFICATION_CONTEXT_INVALID, "$.final_source_ref")
    _verification_require(pre_value["task_id"] == proposal_value["task_id"], _VERIFICATION_CONTEXT_INVALID, "$.pre_verifier_observation_manifest_ref.task_id")
    _verification_require(pre_value["proposal_id"] == proposal_value["proposal_id"], _VERIFICATION_CONTEXT_INVALID, "$.pre_verifier_observation_manifest_ref.proposal_id")
    _verification_require(pre_value["attempt_id"] == proposal_value["attempt_id"], _VERIFICATION_CONTEXT_INVALID, "$.pre_verifier_observation_manifest_ref.attempt_id")
    _verification_require(pre_value["native_epoch"] == proposal_value["native_epoch"], _VERIFICATION_CONTEXT_INVALID, "$.pre_verifier_observation_manifest_ref.native_epoch")
    _verification_change_binding(checked["change_set"], change_value, "$.change_set")
    if change_value is None:
        _verification_require(proposal_value["change_set_ref"] is None, _VERIFICATION_CONTEXT_INVALID, "$.change_set")
    else:
        _verification_require_ref(proposal_value["change_set_ref"], "change-set/v1", change_value, "$.completion_proposal_ref.change_set_ref")
        _verification_require(change_value["original_source_state_id"] == original_value["source_state_id"], _VERIFICATION_CONTEXT_INVALID, "$.change_set.original_source_state_id")
        _verification_require(change_value["final_source_state_id"] == final_value["source_state_id"], _VERIFICATION_CONTEXT_INVALID, "$.change_set.final_source_state_id")
    _verification_require(len(rule_values) == len(checked["engineering_rule_refs"]), _VERIFICATION_CONTEXT_INVALID, "$.engineering_rule_refs")
    for index, (ref, document) in enumerate(zip(checked["engineering_rule_refs"], rule_values)):
        _verification_require_ref(ref, "source-content/v1", document, f"$.engineering_rule_refs[{index}]")
    _verification_require_time_order([proposal_value["created_at"], checked["created_at"]], "$.created_at")
    return checked


def verify_verifier_work_context(
    report: object,
    verifier_input: object,
    proposal: object,
    final_observation_manifest: object,
) -> dict[str, object]:
    checked = verify_document_digest("verifier-work-report/v1", report)
    input_value = verify_document_digest("verifier-input-manifest/v1", verifier_input)
    proposal_value = verify_document_digest("completion-proposal/v1", proposal)
    final_value = verify_document_digest("observation-manifest/v1", final_observation_manifest)
    entries = _verification_manifest_entries(final_value)

    _verification_require_ref(checked["verifier_input_manifest_ref"], "verifier-input-manifest/v1", input_value, "$.verifier_input_manifest_ref")
    _verification_require_companion_digest(checked["verifier_input_manifest_digest"], "verifier-input-manifest/v1", input_value, "$.verifier_input_manifest_digest")
    _verification_require(checked["task_id"] == input_value["task_id"] == proposal_value["task_id"] == final_value["task_id"], _VERIFICATION_CONTEXT_INVALID, "$.task_id")
    _verification_require(checked["proposal_id"] == input_value["proposal_id"] == proposal_value["proposal_id"] == final_value["proposal_id"], _VERIFICATION_CONTEXT_INVALID, "$.proposal_id")
    _verification_require(checked["slot_id"] == input_value["slot_id"], _VERIFICATION_CONTEXT_INVALID, "$.slot_id")
    _verification_require_ref(input_value["completion_proposal_ref"], "completion-proposal/v1", proposal_value, "$.completion_proposal_ref")
    _verification_require(final_value["attempt_id"] == proposal_value["attempt_id"], _VERIFICATION_CONTEXT_INVALID, "$.final_observation_manifest.attempt_id")
    _verification_require(final_value["native_epoch"] == proposal_value["native_epoch"], _VERIFICATION_CONTEXT_INVALID, "$.final_observation_manifest.native_epoch")
    _verification_require(
        _verification_requirement_ids(checked["provisional_requirement_assessments"]) == input_value["requirement_ids"],
        _VERIFICATION_CONTEXT_INVALID,
        "$.provisional_requirement_assessments",
    )
    own_ids = set(checked["own_observation_ids"])
    final_ids = set(entries)
    _verification_require(own_ids.issubset(final_ids), _VERIFICATION_CONTEXT_INVALID, "$.own_observation_ids")
    for index, observation_id in enumerate(checked["own_observation_ids"]):
        actor = entries[observation_id]["actor"]
        _verification_require(actor["kind"] == "quality_verifier", _VERIFICATION_CONTEXT_INVALID, f"$.own_observation_ids[{index}]")
        _verification_require(actor["session_id"] == checked["verifier_session_id"], _VERIFICATION_CONTEXT_INVALID, f"$.own_observation_ids[{index}]")
    for index, item in enumerate(checked["provisional_requirement_assessments"]):
        evidence_ids = set(item["evidence_ids"])
        _verification_require(evidence_ids.issubset(own_ids), _VERIFICATION_CONTEXT_INVALID, f"$.provisional_requirement_assessments[{index}].evidence_ids")
        _verification_require(evidence_ids.issubset(final_ids), _VERIFICATION_CONTEXT_INVALID, f"$.provisional_requirement_assessments[{index}].evidence_ids")
    _verification_require_time_order([proposal_value["created_at"], input_value["created_at"], checked["created_at"]], "$.created_at")
    return checked


def verify_attestation_context(
    attestation: object,
    verifier_input: object,
    verifier_work: object,
    proposal: object,
    quality_policy_plan: object,
    final_source: object,
    execution_states: object,
    final_observation_manifest: object,
) -> dict[str, object]:
    checked = verify_document_digest("verification-attestation/v1", attestation)
    input_value = verify_document_digest("verifier-input-manifest/v1", verifier_input)
    work_value = verify_document_digest("verifier-work-report/v1", verifier_work)
    proposal_value = verify_document_digest("completion-proposal/v1", proposal)
    plan_value = verify_document_digest("quality-policy-plan/v1", quality_policy_plan)
    final_source_value = verify_document_digest("source-tree-manifest/v1", final_source)
    state_values = _verification_check_documents("execution-state-manifest/v1", execution_states, "$.execution_state_ids")
    final_manifest_value = verify_document_digest("observation-manifest/v1", final_observation_manifest)
    entries = _verification_manifest_entries(final_manifest_value)
    slot = _verification_find_plan_slot(plan_value, checked["slot_id"])

    _verification_require(slot is not None, _VERIFICATION_CONTEXT_INVALID, "$.slot_id")
    _verification_require_ref(checked["verifier_input_manifest_ref"], "verifier-input-manifest/v1", input_value, "$.verifier_input_manifest_ref")
    _verification_require_ref(checked["verifier_work_report_ref"], "verifier-work-report/v1", work_value, "$.verifier_work_report_ref")
    _verification_require_ref(input_value["completion_proposal_ref"], "completion-proposal/v1", proposal_value, "$.completion_proposal_ref")
    _verification_require_ref(work_value["verifier_input_manifest_ref"], "verifier-input-manifest/v1", input_value, "$.verifier_input_manifest_ref")
    _verification_require_companion_digest(work_value["verifier_input_manifest_digest"], "verifier-input-manifest/v1", input_value, "$.verifier_input_manifest_digest")
    _verification_require_ref(checked["quality_policy_plan_ref"], "quality-policy-plan/v1", plan_value, "$.quality_policy_plan_ref")
    _verification_require_ref(checked["final_observation_manifest_ref"], "observation-manifest/v1", final_manifest_value, "$.final_observation_manifest_ref")
    _verification_require_companion_digest(checked["verifier_input_manifest_digest"], "verifier-input-manifest/v1", input_value, "$.verifier_input_manifest_digest")
    _verification_require_companion_digest(checked["verifier_work_report_digest"], "verifier-work-report/v1", work_value, "$.verifier_work_report_digest")
    _verification_require_companion_digest(checked["quality_policy_plan_digest"], "quality-policy-plan/v1", plan_value, "$.quality_policy_plan_digest")
    _verification_require_companion_digest(checked["final_observation_manifest_digest"], "observation-manifest/v1", final_manifest_value, "$.final_observation_manifest_digest")
    _verification_require(checked["task_id"] == input_value["task_id"] == work_value["task_id"] == proposal_value["task_id"], _VERIFICATION_CONTEXT_INVALID, "$.task_id")
    _verification_require(checked["task_id"] == plan_value["task_id"] == final_manifest_value["task_id"], _VERIFICATION_CONTEXT_INVALID, "$.task_id")
    _verification_require(checked["proposal_id"] == input_value["proposal_id"] == work_value["proposal_id"] == proposal_value["proposal_id"], _VERIFICATION_CONTEXT_INVALID, "$.proposal_id")
    _verification_require(checked["proposal_id"] == plan_value["proposal_id"] == final_manifest_value["proposal_id"], _VERIFICATION_CONTEXT_INVALID, "$.proposal_id")
    _verification_require(checked["slot_id"] == input_value["slot_id"] == work_value["slot_id"], _VERIFICATION_CONTEXT_INVALID, "$.slot_id")
    _verification_require(checked["verifier_session_id"] == work_value["verifier_session_id"], _VERIFICATION_CONTEXT_INVALID, "$.verifier_session_id")
    _verification_require(checked["model_identity"] == work_value["model_identity"], _VERIFICATION_CONTEXT_INVALID, "$.model_identity")
    _verification_require(final_manifest_value["attempt_id"] == proposal_value["attempt_id"], _VERIFICATION_CONTEXT_INVALID, "$.final_observation_manifest.attempt_id")
    _verification_require(final_manifest_value["native_epoch"] == proposal_value["native_epoch"], _VERIFICATION_CONTEXT_INVALID, "$.final_observation_manifest.native_epoch")
    _verification_require(checked["source_state_id"] == proposal_value["final_source_state_id"] == final_source_value["source_state_id"], _VERIFICATION_CONTEXT_INVALID, "$.source_state_id")
    _verification_require_ref(input_value["quality_policy_plan_ref"], "quality-policy-plan/v1", plan_value, "$.completion_proposal_ref.quality_policy_plan_ref")
    _verification_require_companion_digest(input_value["quality_policy_plan_digest"], "quality-policy-plan/v1", plan_value, "$.completion_proposal_ref.quality_policy_plan_digest")
    _verification_require(plan_value["proposal_digest"] == proposal_value["proposal_digest"], _VERIFICATION_CONTEXT_DIGEST_INVALID, "$.proposal_digest")
    _verification_require(
        checked["execution_state_ids"] == [item["execution_state_id"] for item in state_values],
        _VERIFICATION_CONTEXT_INVALID,
        "$.execution_state_ids",
    )
    for index, state_value in enumerate(state_values):
        _verification_require(state_value["source_state_id"] == final_source_value["source_state_id"], _VERIFICATION_CONTEXT_INVALID, f"$.execution_state_ids[{index}]")
    _verification_require(checked["own_observation_ids"] == work_value["own_observation_ids"], _VERIFICATION_CONTEXT_INVALID, "$.own_observation_ids")
    _verification_require(
        _verification_requirement_ids(checked["requirement_verdicts"]) == slot["requirement_ids"],
        _VERIFICATION_CONTEXT_INVALID,
        "$.requirement_verdicts",
    )
    _verification_require(
        _verification_requirement_ids(checked["requirement_verdicts"]) == input_value["requirement_ids"],
        _VERIFICATION_CONTEXT_INVALID,
        "$.requirement_verdicts",
    )
    own_ids = set(checked["own_observation_ids"])
    final_ids = set(entries)
    for index, observation_id in enumerate(checked["own_observation_ids"]):
        actor = entries.get(observation_id, {}).get("actor")
        _verification_require(actor is not None, _VERIFICATION_CONTEXT_INVALID, f"$.own_observation_ids[{index}]")
        _verification_require(actor["kind"] == "quality_verifier", _VERIFICATION_CONTEXT_INVALID, f"$.own_observation_ids[{index}]")
        _verification_require(actor["session_id"] == checked["verifier_session_id"], _VERIFICATION_CONTEXT_INVALID, f"$.own_observation_ids[{index}]")
    for index, entry in enumerate(final_manifest_value["entries"]):
        actor = entry["actor"]
        _verification_require(
            actor["session_id"] != checked["verifier_session_id"] or actor["kind"] == "quality_verifier",
            _VERIFICATION_CONTEXT_INVALID,
            f"$.final_observation_manifest.entries[{index}].actor",
        )
    for index, item in enumerate(checked["requirement_verdicts"]):
        evidence_ids = set(item["evidence_ids"])
        _verification_require(evidence_ids.issubset(own_ids), _VERIFICATION_CONTEXT_INVALID, f"$.requirement_verdicts[{index}].evidence_ids")
        _verification_require(evidence_ids.issubset(final_ids), _VERIFICATION_CONTEXT_INVALID, f"$.requirement_verdicts[{index}].evidence_ids")
    _verification_require_time_order([proposal_value["created_at"], input_value["created_at"], work_value["created_at"], checked["created_at"]], "$.created_at")
    return checked


def verify_attestation_manifest_context(
    manifest: object,
    quality_policy_plan: object,
    final_observation_manifest: object,
    attestations: object,
) -> dict[str, object]:
    checked = verify_document_digest("verification-attestation-manifest/v1", manifest)
    plan_value = verify_document_digest("quality-policy-plan/v1", quality_policy_plan)
    final_value = verify_document_digest("observation-manifest/v1", final_observation_manifest)
    attestation_values = _verification_check_documents("verification-attestation/v1", attestations, "$.attestations")

    _verification_require_ref(checked["quality_policy_plan_ref"], "quality-policy-plan/v1", plan_value, "$.quality_policy_plan_ref")
    _verification_require_ref(checked["final_observation_manifest_ref"], "observation-manifest/v1", final_value, "$.final_observation_manifest_ref")
    _verification_require_companion_digest(checked["quality_policy_plan_digest"], "quality-policy-plan/v1", plan_value, "$.quality_policy_plan_digest")
    _verification_require_companion_digest(checked["final_observation_manifest_digest"], "observation-manifest/v1", final_value, "$.final_observation_manifest_digest")
    _verification_require(checked["task_id"] == plan_value["task_id"] == final_value["task_id"], _VERIFICATION_CONTEXT_INVALID, "$.task_id")
    _verification_require(checked["proposal_id"] == plan_value["proposal_id"] == final_value["proposal_id"], _VERIFICATION_CONTEXT_INVALID, "$.proposal_id")
    _verification_require(checked["attestation_count"] == len(attestation_values), _VERIFICATION_CONTEXT_INVALID, "$.attestation_count")

    attestation_by_id: dict[str, dict[str, object]] = {}
    attestation_by_slot: dict[str, dict[str, object]] = {}
    plan_slots = {item["slot_id"]: item for item in plan_value["slots"]}
    for index, document in enumerate(attestation_values):
        _verification_require(document["task_id"] == checked["task_id"], _VERIFICATION_CONTEXT_INVALID, f"$.attestations[{index}].task_id")
        _verification_require(document["proposal_id"] == checked["proposal_id"], _VERIFICATION_CONTEXT_INVALID, f"$.attestations[{index}].proposal_id")
        _verification_require_ref(document["quality_policy_plan_ref"], "quality-policy-plan/v1", plan_value, f"$.attestations[{index}].quality_policy_plan_ref")
        _verification_require_ref(document["final_observation_manifest_ref"], "observation-manifest/v1", final_value, f"$.attestations[{index}].final_observation_manifest_ref")
        _verification_require_companion_digest(document["quality_policy_plan_digest"], "quality-policy-plan/v1", plan_value, f"$.attestations[{index}].quality_policy_plan_digest")
        _verification_require_companion_digest(document["final_observation_manifest_digest"], "observation-manifest/v1", final_value, f"$.attestations[{index}].final_observation_manifest_digest")
        _verification_require(document["attestation_id"] not in attestation_by_id, _VERIFICATION_CONTEXT_INVALID, f"$.attestations[{index}].attestation_id")
        _verification_require(document["slot_id"] in plan_slots, _VERIFICATION_CONTEXT_INVALID, f"$.attestations[{index}].slot_id")
        _verification_require(document["slot_id"] not in attestation_by_slot, _VERIFICATION_CONTEXT_INVALID, f"$.attestations[{index}].slot_id")
        _verification_require(
            _verification_requirement_ids(document["requirement_verdicts"]) == plan_slots[document["slot_id"]]["requirement_ids"],
            _VERIFICATION_CONTEXT_INVALID,
            f"$.attestations[{index}].requirement_verdicts",
        )
        attestation_by_id[document["attestation_id"]] = document
        attestation_by_slot[document["slot_id"]] = document

    sessions = [item["verifier_session_id"] for item in attestation_values]
    _verification_require(len(sessions) == len(set(sessions)), _VERIFICATION_CONTEXT_INVALID, "$.attestations")
    seen_manifest_slots: set[str] = set()
    for index, item in enumerate(checked["attestations"]):
        document = attestation_by_id.get(item["attestation_id"])
        _verification_require(document is not None, _VERIFICATION_CONTEXT_INVALID, f"$.attestations[{index}].attestation_id")
        _verification_require(item["slot_id"] == document["slot_id"], _VERIFICATION_CONTEXT_INVALID, f"$.attestations[{index}].slot_id")
        _verification_require(item["slot_id"] in plan_slots, _VERIFICATION_CONTEXT_INVALID, f"$.attestations[{index}].slot_id")
        _verification_require(item["slot_id"] not in seen_manifest_slots, _VERIFICATION_CONTEXT_INVALID, f"$.attestations[{index}].slot_id")
        _verification_require(item["run_status"] == document["run_status"], _VERIFICATION_CONTEXT_INVALID, f"$.attestations[{index}].run_status")
        _verification_require_ref(item["attestation_ref"], "verification-attestation/v1", document, f"$.attestations[{index}].attestation_ref")
        seen_manifest_slots.add(item["slot_id"])

    expected_requirement_ids = sorted(
        {
            requirement_id
            for slot in plan_value["slots"]
            for requirement_id in slot["requirement_ids"]
        }
    )
    _verification_require(
        [item["requirement_id"] for item in checked["requirement_aggregates"]] == expected_requirement_ids,
        _VERIFICATION_CONTEXT_INVALID,
        "$.requirement_aggregates",
    )
    for index, aggregate in enumerate(checked["requirement_aggregates"]):
        required_slot_ids = sorted(
            slot["slot_id"]
            for slot in plan_value["slots"]
            if aggregate["requirement_id"] in slot["requirement_ids"]
        )
        expected_attestation_ids, expected_verdict = _verification_aggregate_result(
            aggregate["requirement_id"],
            required_slot_ids,
            attestation_by_slot,
        )
        _verification_require(aggregate["required_slot_ids"] == required_slot_ids, _VERIFICATION_CONTEXT_INVALID, f"$.requirement_aggregates[{index}].required_slot_ids")
        _verification_require(aggregate["attestation_ids"] == expected_attestation_ids, _VERIFICATION_CONTEXT_INVALID, f"$.requirement_aggregates[{index}].attestation_ids")
        _verification_require(aggregate["verdict"] == expected_verdict, _VERIFICATION_CONTEXT_INVALID, f"$.requirement_aggregates[{index}].verdict")

    _verification_require_time_order([*(item["created_at"] for item in attestation_values), checked["created_at"]], "$.created_at")
    return checked


_RELEASE_INVALID_CODE = "CONTRACT_DOCUMENT_INVALID"
_RELEASE_CANARY_STAGE_IDS = ("CAPACITY_5", "CAPACITY_25", "FULL_CAPACITY")
_RELEASE_ATTESTATION_MAX_WINDOW_MS = 7 * 24 * 60 * 60 * 1000

_RELEASE_POLICY_BENCHMARK_FIELDS = (
    "benchmark_version", "task_inventory_digest", "oracle_rubric_digest",
    "environment_image_digest", "control_plane_digest",
    "evaluation_runtime_digest", "statistical_implementation_version",
)

_RELEASE_REPORT_POLICY_FIELDS = (
    "package", "candidate_build_id", "candidate_digest", "release_mode",
    "stable_package", "stable_candidate_digest", "stable_control_plane_digest",
    "benchmark_digest", "benchmark_version", "task_inventory_digest",
    "oracle_rubric_digest", "environment_image_digest", "control_plane_digest",
    "evaluation_runtime_digest", "statistical_implementation_version",
    "threshold_table_digest", "profile_budget_digest", "canary_plan_digest",
)
_RELEASE_REPORT_BINDING_FIELDS = (
    *_RELEASE_REPORT_POLICY_FIELDS[:7], "benchmark_ref",
    *_RELEASE_REPORT_POLICY_FIELDS[7:],
)

_RELEASE_ATTESTATION_IDENTITY_FIELDS = (
    "package", "candidate_build_id", "candidate_digest", "release_mode",
    "stable_package", "stable_candidate_digest", "stable_control_plane_digest",
)


def _release_require(
    condition: bool, detail: str, path: str = "$"
) -> None:
    _require(condition, detail, path, _RELEASE_INVALID_CODE)


def _release_digest(domain: str, value: object) -> str:
    return hashlib.sha256(
        domain.encode("utf-8") + b"\0" + canonical_document_bytes(value)
    ).hexdigest()


def _release_require_ref(
    ref: dict[str, object],
    schema_id: str,
    document: dict[str, object],
    detail: str,
    path: str,
) -> None:
    _release_require(
        _seo_ref_matches_document(ref, schema_id, document),
        detail,
        path,
    )


def _release_require_equal(
    actual: object, expected: object, detail: str, path: str
) -> None:
    _release_require(_json_equal(actual, expected), detail, path)


def _rule_benchmark_bundle(value: dict[str, object]) -> None:
    _release_require(
        _sorted_unique(value["seeds"]),
        "RELEASE_BENCHMARK_ORDER_INVALID",
        "$.seeds",
    )
    _release_require(
        _ordered_unique(value["unknown_families"], lambda item: item["family_id"]),
        "RELEASE_BENCHMARK_ORDER_INVALID",
        "$.unknown_families",
    )
    _release_require(
        _sorted_unique(value["core_cluster_ids"]),
        "RELEASE_BENCHMARK_ORDER_INVALID",
        "$.core_cluster_ids",
    )
    _release_require(
        _ordered_unique(value["cluster_coverage"], lambda item: item["cluster_id"]),
        "RELEASE_BENCHMARK_ORDER_INVALID",
        "$.cluster_coverage",
    )
    _release_require(
        [item["cluster_id"] for item in value["cluster_coverage"]]
        == value["core_cluster_ids"],
        "RELEASE_BENCHMARK_COVERAGE_INVALID",
        "$.cluster_coverage",
    )
    issued_at = _timestamp_millis(value["issued_at"])
    expires_at = _timestamp_millis(value["expires_at"])
    _release_require(
        issued_at is not None,
        "RELEASE_BENCHMARK_TIME_INVALID",
        "$.issued_at",
    )
    _release_require(
        expires_at is not None and expires_at > issued_at,
        "RELEASE_BENCHMARK_TIME_INVALID",
        "$.expires_at",
    )


def _rule_release_gate_policy(value: dict[str, object]) -> None:
    for field, identity in (
        ("absolute_gates", "gate_id"),
        ("relative_gates", "gate_id"),
        ("profile_budgets", "profile_id"),
    ):
        _release_require(
            _ordered_unique(value[field], lambda item, key=identity: item[key]),
            "RELEASE_POLICY_ORDER_INVALID",
            f"$.{field}",
        )
    _release_require(
        _sorted_unique(value["infrastructure_reason_codes"]),
        "RELEASE_POLICY_ORDER_INVALID",
        "$.infrastructure_reason_codes",
    )
    _release_require(
        tuple(item["stage_id"] for item in value["canary_stages"])
        == _RELEASE_CANARY_STAGE_IDS,
        "RELEASE_POLICY_CANARY_INVALID",
        "$.canary_stages",
    )
    stable_fields = (
        value["stable_package"],
        value["stable_candidate_digest"],
        value["stable_control_plane_digest"],
    )
    expected_applicability = (
        "NOT_APPLICABLE" if value["release_mode"] == "BOOTSTRAP" else "REQUIRED"
    )
    stable_shape_valid = (
        all(item is None for item in stable_fields)
        if value["release_mode"] == "BOOTSTRAP"
        else all(item is not None for item in stable_fields)
    )
    _release_require(
        stable_shape_valid,
        "RELEASE_POLICY_MODE_INVALID",
        "$.stable_package",
    )
    _release_require(
        all(
            item["applicability"] == expected_applicability
            for item in value["relative_gates"]
        ),
        "RELEASE_POLICY_MODE_INVALID",
        "$.relative_gates",
    )
    issued_at = _timestamp_millis(value["issued_at"])
    expires_at = _timestamp_millis(value["expires_at"])
    _release_require(
        issued_at is not None,
        "RELEASE_POLICY_TIME_INVALID",
        "$.issued_at",
    )
    _release_require(
        expires_at is not None and expires_at > issued_at,
        "RELEASE_POLICY_TIME_INVALID",
        "$.expires_at",
    )
    threshold_projection = {
        "absolute_gates": value["absolute_gates"],
        "relative_gates": value["relative_gates"],
        "infrastructure_reason_codes": value["infrastructure_reason_codes"],
    }
    _release_require(
        value["threshold_table_digest"]
        == _release_digest(
            "pullwise:release-threshold-table:v1",
            threshold_projection,
        ),
        "RELEASE_POLICY_THRESHOLD_DIGEST_INVALID",
        "$.threshold_table_digest",
    )
    _release_require(
        value["profile_budget_digest"]
        == _release_digest(
            "pullwise:release-profile-budgets:v1",
            value["profile_budgets"],
        ),
        "RELEASE_POLICY_PROFILE_DIGEST_INVALID",
        "$.profile_budget_digest",
    )
    canary_projection = {
        field: value[field]
        for field in (
            "canary_stages",
            "canary_platform_failure_rate_max_bps",
            "canary_relative_platform_failure_increase_max_bps",
            "canary_p95_wall_time_increase_max_bps",
            "canary_p95_cost_increase_max_bps",
        )
    }
    _release_require(
        value["canary_plan_digest"]
        == _release_digest(
            "pullwise:release-canary-plan:v1",
            canary_projection,
        ),
        "RELEASE_POLICY_CANARY_DIGEST_INVALID",
        "$.canary_plan_digest",
    )
    candidate_projection = {
        field: value[field]
        for field in (
            "package",
            "candidate_build_id",
            "control_plane_digest",
            "evaluation_runtime_digest",
            "benchmark_ref",
            "benchmark_digest",
            "threshold_table_digest",
            "profile_budget_digest",
            "canary_plan_digest",
        )
    }
    _release_require(
        value["candidate_digest"]
        == _release_digest(
            "pullwise:candidate-digest:v1",
            candidate_projection,
        ),
        "RELEASE_POLICY_CANDIDATE_DIGEST_INVALID",
        "$.candidate_digest",
    )


def _rule_release_gate_report(value: dict[str, object]) -> None:
    _release_validate_indeterminate_shape(value)
    _release_validate_absolute_results(value)
    _release_validate_relative_results(value)
    _release_require(
        value["raw_sample_count"]
        == value["valid_sample_count"] + value["excluded_sample_count"],
        "RELEASE_REPORT_SAMPLE_INVALID",
        "$.raw_sample_count",
    )
    _release_require(
        value["excluded_sample_count"]
        == sum(item["count"] for item in value["excluded_reason_counts"]),
        "RELEASE_REPORT_SAMPLE_INVALID",
        "$.excluded_sample_count",
    )
    _release_require(
        _ordered_unique(
            value["excluded_reason_counts"],
            lambda item: item["reason_code"],
        ),
        "RELEASE_REPORT_ORDER_INVALID",
        "$.excluded_reason_counts",
    )
    for field, identity in (
        ("absolute_results", "gate_id"),
        ("relative_results", "gate_id"),
        ("profile_results", "profile_id"),
    ):
        _release_require(
            _ordered_unique(value[field], lambda item, key=identity: item[key]),
            "RELEASE_REPORT_ORDER_INVALID",
            f"$.{field}",
        )
    if value["release_mode"] == "BOOTSTRAP":
        relative_shape_valid = all(
            item["applicability"] == "NOT_APPLICABLE"
            and item["observed_regression_bps"] is None
            and item["status"] == "NOT_APPLICABLE"
            for item in value["relative_results"]
        )
    else:
        relative_shape_valid = all(
            item["applicability"] == "REQUIRED"
            and item["status"] != "NOT_APPLICABLE"
            and (
                item["status"] == "INDETERMINATE"
                or item["observed_regression_bps"] is not None
            )
            for item in value["relative_results"]
        )
    _release_require(
        relative_shape_valid,
        "RELEASE_REPORT_MODE_INVALID",
        "$.relative_results",
    )
    statuses = [
        *(item["status"] for item in value["absolute_results"]),
        *(
            item["status"]
            for item in value["relative_results"]
            if item["status"] != "NOT_APPLICABLE"
        ),
        *(item["status"] for item in value["profile_results"]),
    ]
    expected_verdict = (
        "FAIL"
        if "FAIL" in statuses
        else "INDETERMINATE"
        if "INDETERMINATE" in statuses
        else "PASS"
    )
    _release_require(
        value["verdict"] == expected_verdict,
        "RELEASE_REPORT_VERDICT_INVALID",
        "$.verdict",
    )
    _release_require(
        value["exit_code"] == {"PASS": 0, "FAIL": 1, "INDETERMINATE": 2}[
            value["verdict"]
        ],
        "RELEASE_REPORT_VERDICT_INVALID",
        "$.exit_code",
    )


def _rule_release_gate_attestation(value: dict[str, object]) -> None:
    _release_require(
        value["attested_verdict"] == "PASS",
        "RELEASE_ATTESTATION_VERDICT_INVALID",
        "$.attested_verdict",
    )
    _release_require(
        value["attested_exit_code"] == 0,
        "RELEASE_ATTESTATION_VERDICT_INVALID",
        "$.attested_exit_code",
    )
    issued_at = _timestamp_millis(value["issued_at"])
    expires_at = _timestamp_millis(value["expires_at"])
    _release_require(
        issued_at is not None,
        "RELEASE_ATTESTATION_WINDOW_INVALID",
        "$.issued_at",
    )
    _release_require(
        expires_at is not None
        and 0 < expires_at - issued_at <= _RELEASE_ATTESTATION_MAX_WINDOW_MS,
        "RELEASE_ATTESTATION_WINDOW_INVALID",
        "$.expires_at",
    )


def _verify_release_gate_policy_binding(
    policy: dict[str, object],
    benchmark_bundle: dict[str, object],
) -> None:
    _release_require_ref(
        policy["benchmark_ref"],
        "benchmark-bundle/v1",
        benchmark_bundle,
        "RELEASE_POLICY_BENCHMARK_REF_INVALID",
        "$.benchmark_ref",
    )
    _release_require_equal(
        policy["package"],
        benchmark_bundle["package"],
        "RELEASE_POLICY_BENCHMARK_BINDING_INVALID",
        "$.package",
    )
    _release_require(
        policy["benchmark_digest"] == benchmark_bundle["bundle_digest"],
        "RELEASE_POLICY_BENCHMARK_BINDING_INVALID",
        "$.benchmark_digest",
    )
    for field in _RELEASE_POLICY_BENCHMARK_FIELDS:
        _release_require_equal(
            policy[field],
            benchmark_bundle[field],
            "RELEASE_POLICY_BENCHMARK_BINDING_INVALID",
            f"$.{field}",
        )


def verify_release_gate_policy_context(
    policy: object,
    benchmark_bundle: object,
) -> dict[str, object]:
    checked_policy = verify_document_digest("release-gate-policy/v1", policy)
    checked_benchmark = verify_document_digest(
        "benchmark-bundle/v1",
        benchmark_bundle,
    )
    _verify_release_gate_policy_binding(checked_policy, checked_benchmark)
    return checked_policy


def _release_require_bindings(
    left: dict[str, object],
    right: dict[str, object],
    fields: tuple[str, ...],
    detail: str,
    prefix: str = "$",
) -> None:
    for field in fields:
        _release_require_equal(
            left[field], right[field], detail, f"{prefix}.{field}"
        )


def verify_release_gate_report_context(
    report: object,
    benchmark_bundle: object,
    policy: object,
) -> dict[str, object]:
    checked_report = verify_document_digest("release-gate-report/v1", report)
    checked_benchmark = verify_document_digest(
        "benchmark-bundle/v1",
        benchmark_bundle,
    )
    checked_policy = verify_document_digest("release-gate-policy/v1", policy)
    _release_require_ref(
        checked_report["benchmark_ref"],
        "benchmark-bundle/v1",
        checked_benchmark,
        "RELEASE_REPORT_REF_INVALID",
        "$.benchmark_ref",
    )
    _release_require_ref(
        checked_report["policy_ref"],
        "release-gate-policy/v1",
        checked_policy,
        "RELEASE_REPORT_REF_INVALID",
        "$.policy_ref",
    )
    _release_require_bindings(
        checked_report,
        checked_policy,
        _RELEASE_REPORT_BINDING_FIELDS,
        "RELEASE_REPORT_BINDING_INVALID",
    )
    _release_require_bindings(
        checked_report,
        checked_benchmark,
        ("package",) + _RELEASE_POLICY_BENCHMARK_FIELDS,
        "RELEASE_REPORT_BINDING_INVALID",
    )
    _release_require(
        checked_report["benchmark_digest"] == checked_benchmark["bundle_digest"],
        "RELEASE_REPORT_BINDING_INVALID",
        "$.benchmark_digest",
    )
    _release_require(
        checked_report["policy_digest"] == checked_policy["policy_digest"],
        "RELEASE_REPORT_BINDING_INVALID",
        "$.policy_digest",
    )
    actual_absolute = [
        {field: item[field] for field in ("gate_id", "comparator", "threshold")}
        for item in checked_report["absolute_results"]
    ]
    expected_absolute = [
        {field: item[field] for field in ("gate_id", "comparator", "threshold")}
        for item in checked_policy["absolute_gates"]
    ]
    _release_require_equal(
        actual_absolute,
        expected_absolute,
        "RELEASE_REPORT_POLICY_TABLE_INVALID",
        "$.absolute_results",
    )
    actual_relative = [
        {
            field: item[field]
            for field in ("gate_id", "applicability", "max_regression_bps")
        }
        for item in checked_report["relative_results"]
    ]
    expected_relative = [
        {
            field: item[field]
            for field in ("gate_id", "applicability", "max_regression_bps")
        }
        for item in checked_policy["relative_gates"]
    ]
    _release_require_equal(
        actual_relative,
        expected_relative,
        "RELEASE_REPORT_POLICY_TABLE_INVALID",
        "$.relative_results",
    )
    _release_require_equal(
        [item["profile_id"] for item in checked_report["profile_results"]],
        [item["profile_id"] for item in checked_policy["profile_budgets"]],
        "RELEASE_REPORT_POLICY_TABLE_INVALID",
        "$.profile_results",
    )
    _release_validate_profile_results(checked_report, checked_policy)
    _release_validate_sample_inventory(checked_report, checked_benchmark)
    allowed_reason_codes = set(checked_policy["infrastructure_reason_codes"])
    _release_require(
        all(
            item["reason_code"] in allowed_reason_codes
            for item in checked_report["excluded_reason_counts"]
        ),
        "RELEASE_REPORT_POLICY_TABLE_INVALID",
        "$.excluded_reason_counts",
    )
    return checked_report


def verify_release_gate_attestation_context(
    attestation: object,
    policy: object,
    report: object,
) -> dict[str, object]:
    checked_attestation = verify_document_digest(
        "release-gate-attestation/v1",
        attestation,
    )
    checked_policy = verify_document_digest("release-gate-policy/v1", policy)
    checked_report = verify_document_digest("release-gate-report/v1", report)
    _release_require_ref(
        checked_attestation["policy_ref"],
        "release-gate-policy/v1",
        checked_policy,
        "RELEASE_ATTESTATION_REF_INVALID",
        "$.policy_ref",
    )
    _release_require_ref(
        checked_attestation["report_ref"],
        "release-gate-report/v1",
        checked_report,
        "RELEASE_ATTESTATION_REF_INVALID",
        "$.report_ref",
    )
    _release_require_ref(
        checked_report["policy_ref"],
        "release-gate-policy/v1",
        checked_policy,
        "RELEASE_ATTESTATION_REF_INVALID",
        "$.report.policy_ref",
    )
    _release_require(
        checked_report["policy_digest"] == checked_policy["policy_digest"],
        "RELEASE_ATTESTATION_BINDING_INVALID",
        "$.report.policy_digest",
    )
    _release_require_bindings(
        checked_report,
        checked_policy,
        _RELEASE_REPORT_POLICY_FIELDS,
        "RELEASE_ATTESTATION_BINDING_INVALID",
        "$.report",
    )
    _release_require_bindings(
        checked_attestation,
        checked_policy,
        _RELEASE_ATTESTATION_IDENTITY_FIELDS + ("policy_id", "policy_digest"),
        "RELEASE_ATTESTATION_BINDING_INVALID",
    )
    _release_require_bindings(
        checked_attestation,
        checked_report,
        _RELEASE_ATTESTATION_IDENTITY_FIELDS
        + ("policy_digest", "report_id", "report_digest"),
        "RELEASE_ATTESTATION_BINDING_INVALID",
    )
    _release_require(
        checked_report["verdict"] == "PASS"
        and checked_report["exit_code"] == 0,
        "RELEASE_ATTESTATION_REPORT_NOT_PASS",
        "$.report.verdict",
    )
    _release_require(
        checked_attestation["attested_verdict"] == checked_report["verdict"]
        and checked_attestation["attested_exit_code"] == checked_report["exit_code"],
        "RELEASE_ATTESTATION_BINDING_INVALID",
        "$.attested_verdict",
    )
    return checked_attestation


def _release_compare(comparator: str, observed: int, threshold: int) -> bool:
    return {
        "EQ": observed == threshold,
        "GTE": observed >= threshold,
        "LT": observed < threshold,
        "LTE": observed <= threshold,
    }[comparator]


def _release_validate_indeterminate_shape(value: dict[str, object]) -> None:
    reasons = value["indeterminate_reason_codes"]
    _release_require(
        _sorted_unique(reasons),
        "RELEASE_EVALUATOR_INDETERMINATE_INVALID",
        "$.indeterminate_reason_codes",
    )
    results = [
        *value["absolute_results"],
        *value["relative_results"],
        *value["profile_results"],
    ]
    _release_require(
        bool(reasons) == any(item["status"] == "INDETERMINATE" for item in results),
        "RELEASE_EVALUATOR_INDETERMINATE_INVALID",
        "$.indeterminate_reason_codes",
    )
    for index, item in enumerate(value["absolute_results"]):
        _release_require(
            (item["observed_value"] is None)
            == (item["status"] == "INDETERMINATE"),
            "RELEASE_EVALUATOR_INDETERMINATE_INVALID",
            f"$.absolute_results[{index}]",
        )
    for index, item in enumerate(value["relative_results"]):
        missing = item["observed_regression_bps"] is None
        expected_missing = item["status"] in {
            "INDETERMINATE", "NOT_APPLICABLE"
        }
        _release_require(
            missing == expected_missing,
            "RELEASE_EVALUATOR_INDETERMINATE_INVALID",
            f"$.relative_results[{index}]",
        )
    for index, item in enumerate(value["profile_results"]):
        measurements = [
            item["wall_ms"], item["token_count"], item["cost_microusd"]
        ]
        expected_missing = item["status"] == "INDETERMINATE"
        _release_require(
            (all(value is None for value in measurements) if expected_missing
             else all(value is not None for value in measurements)),
            "RELEASE_EVALUATOR_INDETERMINATE_INVALID",
            f"$.profile_results[{index}]",
        )


def _release_validate_absolute_results(value: dict[str, object]) -> None:
    for index, item in enumerate(value["absolute_results"]):
        if item["status"] == "INDETERMINATE":
            continue
        expected = (
            "PASS"
            if _release_compare(
                item["comparator"], item["observed_value"], item["threshold"]
            )
            else "FAIL"
        )
        _release_require(
            item["status"] == expected,
            "RELEASE_EVALUATOR_STATUS_INVALID",
            f"$.absolute_results[{index}].status",
        )


def _release_validate_relative_results(value: dict[str, object]) -> None:
    for index, item in enumerate(value["relative_results"]):
        if item["status"] in {"INDETERMINATE", "NOT_APPLICABLE"}:
            continue
        expected = (
            "PASS"
            if item["observed_regression_bps"] <= item["max_regression_bps"]
            else "FAIL"
        )
        _release_require(
            item["status"] == expected,
            "RELEASE_EVALUATOR_STATUS_INVALID",
            f"$.relative_results[{index}].status",
        )


def _release_validate_profile_results(
    report: dict[str, object], policy: dict[str, object]
) -> None:
    for index, (result, budget) in enumerate(
        zip(report["profile_results"], policy["profile_budgets"])
    ):
        if result["status"] == "INDETERMINATE":
            continue
        passed = (
            result["wall_ms"] <= budget["wall_ms"]
            and result["token_count"] <= budget["token_limit"]
            and result["cost_microusd"] <= budget["cost_microusd"]
        )
        _release_require(
            result["status"] == ("PASS" if passed else "FAIL"),
            "RELEASE_EVALUATOR_STATUS_INVALID",
            f"$.profile_results[{index}].status",
        )


def _release_validate_sample_inventory(
    report: dict[str, object], benchmark: dict[str, object]
) -> None:
    expected = (
        benchmark["known_gold_task_count"]
        + sum(item["task_count"] for item in benchmark["unknown_families"])
    ) * benchmark["repeats_per_task"]
    reasons = set(report["indeterminate_reason_codes"])
    valid = (
        ("SAMPLE_INSUFFICIENT" in reasons)
        == (report["raw_sample_count"] != expected)
        and ("ZERO_DENOMINATOR" in reasons)
        == (report["valid_sample_count"] == 0)
    )
    _release_require(
        valid,
        "RELEASE_EVALUATOR_SAMPLE_INVALID",
        "$.indeterminate_reason_codes",
    )


def evaluate_release_gate(
    benchmark_bundle: object,
    policy: object,
    report: object,
) -> dict[str, object]:
    checked = verify_release_gate_report_context(
        report, benchmark_bundle, policy
    )
    return {
        "verdict": checked["verdict"],
        "exit_code": checked["exit_code"],
    }


